const MODULE_TOGGLE_SETTING_FIELD_MAP = Object.freeze({
  verification: ['moduleVerificationEnabled'],
  governance: ['moduleGovernanceEnabled'],
  wallettracker: ['moduleWalletTrackerEnabled', 'moduleTreasuryEnabled'],
  nfttracker: ['moduleNftTrackerEnabled'],
  tokentracker: ['moduleTokenTrackerEnabled'],
  invites: ['moduleInviteTrackerEnabled'],
  aiassistant: ['moduleAiAssistantEnabled'],
  ticketing: ['moduleTicketingEnabled'],
  engagement: ['moduleEngagementEnabled'],
  guildguard: ['moduleGuildGuardEnabled'],
  minigames: ['moduleMinigamesEnabled', 'moduleBattleEnabled'],
  heist: ['moduleMissionsEnabled'],
  vault: ['moduleVaultEnabled'],
  telegrambridge: ['moduleTelegramBridgeEnabled'],
  automessages: ['moduleAutoMessagesEnabled'],
  welcome: ['moduleWelcomeEnabled'],
  selfserveroles: ['moduleRoleClaimEnabled'],
});

function canToggleModuleFromHub(moduleKey) {
  return Array.isArray(MODULE_TOGGLE_SETTING_FIELD_MAP[moduleKey]);
}

async function toggleModuleFromHub(moduleKey, enabled, inputEl) {
  const fields = MODULE_TOGGLE_SETTING_FIELD_MAP[moduleKey];
  if (!fields || !activeGuildId || !inputEl) return;
  if (!(isAdmin || isSuperadmin)) return;

  const readOnlyManaged = !!portalSettingsData?.readOnlyManaged && !isSuperadmin;
  const previousChecked = !enabled;
  if (readOnlyManaged) {
    inputEl.checked = previousChecked;
    showInfo('Module toggles are managed by superadmin for this tenant.');
    return;
  }

  const payload = {};
  fields.forEach(field => {
    payload[field] = !!enabled;
  });

  inputEl.disabled = true;
  try {
    const response = await fetch('/api/admin/settings', {
      method: 'PUT',
      credentials: 'include',
      headers: { 'Content-Type': 'application/json', ...buildTenantRequestHeaders() },
      body: JSON.stringify(payload)
    });
    const data = await response.json();
    if (!response.ok || data?.success === false) {
      throw new Error(data?.message || `Failed to update ${moduleKey}`);
    }

    if (!window._tenantModuleState) window._tenantModuleState = {};
    window._tenantModuleState[moduleKey] = !!enabled;
    if (moduleKey === 'minigames') window._tenantModuleState.battle = !!enabled;

    await syncTenantModuleNavVisibility();
    renderModuleHub();
    showSuccess(`${moduleKey} ${enabled ? 'enabled' : 'disabled'}`);
  } catch (error) {
    inputEl.checked = previousChecked;
    showError(error.message || 'Failed to update module state');
  } finally {
    inputEl.disabled = false;
  }
}

function openModuleExternal(pathname) {
  const target = new URL(pathname, window.location.origin);
  if (activeGuildId) target.searchParams.set('guildId', activeGuildId);
  window.location.assign(target.toString());
}

function updateBreadcrumbs(items = []) {
  const wrap = document.getElementById('breadcrumb-wrap');
  if (!wrap) return;
  
  if (!items || items.length === 0) {
    wrap.style.display = 'none';
    return;
  }
  
  wrap.style.display = 'flex';
  wrap.innerHTML = items.map((item, idx) => {
    const isLast = idx === items.length - 1;
    return `
      <div class="breadcrumb-item ${isLast ? 'active' : ''}" 
           ${item.action && !isLast ? `onclick="${item.action}"` : ''}>
        ${escapeHtml(item.label)}
      </div>
    `;
  }).join('');
}

function renderModuleHub() {
  const grid = document.getElementById('module-hub-grid');
  if (!grid) return;
  
  const state = window._tenantModuleState || {};
  const record = getServerRecord(activeGuildId);
  const name = record?.name || activeGuildId || 'Selected Server';
  const iconUrl = record ? getGuildIconUrl(record) : '';
  const isServerAdmin = isAdmin || isSuperadmin;
  const canManageModules = isServerAdmin && !!activeGuildId;
  const readOnlyManaged = !!portalSettingsData?.readOnlyManaged && !isSuperadmin;
  const infoEl = document.getElementById('moduleHubServerInfo');
  if (infoEl && activeGuildId) {
    infoEl.innerHTML = `
      <div class="module-hub-server">
        ${iconUrl
          ? `<img src="${iconUrl}" alt="${escapeHtml(name)} icon" class="module-hub-server__icon">`
          : `<div class="module-hub-server__icon module-hub-server__icon--fallback">${escapeHtml(name.slice(0, 2).toUpperCase())}</div>`}
        <div class="module-hub-server__meta">
          <div class="module-hub-server__name">${escapeHtml(name)}</div>
          <div class="module-hub-server__id">
            <span>ID: ${escapeHtml(activeGuildId)}</span>
            <button class="module-hub-server__copy" onclick="navigator.clipboard.writeText('${escapeJsString(activeGuildId)}');showSuccess('Server ID copied!')">Copy</button>
          </div>
        </div>
      </div>
    `;
  } else if (infoEl) {
    infoEl.innerHTML = '';
  }
  
  // Breadcrumbs: Servers > [Server Name]
  updateBreadcrumbs([
    { label: 'Servers', action: "switchSection('servers')" },
    { label: name }
  ]);
  
  let html = '';

  if (false && isServerAdmin) { // legacy settings tile intentionally hidden
    html += `
      <div class="module-tile module-tile--admin" onclick="switchSection('settings')">
        <div class="module-tile__header">
          <div class="module-tile__icon">\u2699\uFE0F</div>
          <div class="module-tile__status status-active">Admin</div>
        </div>
        <div class="module-tile__body">
          <h3 class="module-tile__title">Server Settings</h3>
          <p class="module-tile__desc">Configure module behavior, channels, automation, and tenant-level controls.</p>
        </div>
        <div class="module-tile__footer">
          <span style="font-size:0.8rem; color:var(--gold);">Open Control Panel &rarr;</span>
        </div>
      </div>
    `;
  }
  
  // Add Infrastructure Tile for Superadmins
  if (isSuperadmin) {
    html += `
      <div class="module-tile" onclick="switchSection('admin'); showAdminView('superadmin'); setTimeout(() => setSuperadminWorkspaceTab('overview'), 120);">
        <div class="module-tile__header">
          <div class="module-tile__icon">\u{1F5A5}\uFE0F</div>
          <div class="module-tile__status status-active">System</div>
        </div>
        <div class="module-tile__body">
          <h3 class="module-tile__title">Infrastructure</h3>
          <p class="module-tile__desc">Monitor CPU, Memory, and live process status of the platform.</p>
        </div>
        <div class="module-tile__footer">
          <span style="font-size:0.8rem; color:var(--gold);">Live Diagnostics &rarr;</span>
        </div>
      </div>
    `;
  }
  
  MODULE_REGISTRY.forEach(mod => {
    const isEnabled = state[mod.key] !== false;
    const isDisabledStyle = !isEnabled ? 'module-tile--disabled' : '';
    const lockedToAdmin = !!mod.adminOnly && !isServerAdmin;
    if (lockedToAdmin) return;
    const statusLabel = isEnabled ? 'Active' : 'Disabled';
    const statusClass = isEnabled ? 'status-active' : 'status-disabled';
    
    const onClick = !isEnabled
      ? ''
      : mod.externalPath
        ? `openModuleExternal('${escapeJsString(mod.externalPath)}')`
        : `switchSection('${mod.section}')`;
    const toggleHtml = (canManageModules && canToggleModuleFromHub(mod.key))
      ? `
        <div style="display:flex;align-items:center;gap:8px; margin-left:auto;" onclick="event.stopPropagation()">
          <span style="font-size:0.74rem; color:var(--text-muted); text-transform:uppercase; letter-spacing:0.04em;">
            ${readOnlyManaged ? 'Locked' : 'Enabled'}
          </span>
          <label class="toggle-switch" title="${readOnlyManaged ? 'Managed by superadmin' : 'Toggle module'}">
            <input type="checkbox"
                   ${isEnabled ? 'checked' : ''}
                   ${readOnlyManaged ? 'disabled' : ''}
                   onchange="toggleModuleFromHub('${escapeJsString(mod.key)}', this.checked, this)">
            <span class="toggle-slider"></span>
          </label>
        </div>
      `
      : '';
    
    html += `
      <div class="module-tile ${isDisabledStyle}" ${onClick ? `onclick="${onClick}"` : ''}>
        <div class="module-tile__header">
          <div class="module-tile__icon">${mod.icon}</div>
          <div class="module-tile__status ${statusClass}">${statusLabel}</div>
        </div>
        <div class="module-tile__body">
          <h3 class="module-tile__title">${escapeHtml(mod.label)}</h3>
          <p class="module-tile__desc">${escapeHtml(mod.desc)}</p>
        </div>
        <div class="module-tile__footer">
          ${isServerAdmin ? '<span class="nav-icon" style="font-size:1.1rem; opacity:0.6;">\u2699\uFE0F</span>' : ''}
          <span style="font-size:0.8rem; color:var(--text-muted); margin-left:8px;">${isEnabled ? 'Enter Module &rarr;' : 'Module Disabled'}</span>
          ${toggleHtml}
        </div>
      </div>
    `;
  });
  
  grid.innerHTML = html;
}

const GUILD_GUARD_DETECTOR_LABELS = Object.freeze({
  spam_flood: 'Spam flood', duplicate_message: 'Duplicate message', mass_mention: 'Mass mention',
  suspicious_account: 'Suspicious account', staff_impersonation: 'Staff impersonation',
  link_protection: 'Unsafe link', lookalike_domain: 'Lookalike domain', raid_burst: 'Raid burst'
});

function switchGuildGuardTab(tab) {
  const selected = ['incidents', 'configuration', 'domains', 'staff'].includes(tab) ? tab : 'incidents';
  document.querySelectorAll('#guildGuardTabs .settings-tab').forEach(button => button.classList.toggle('active', button.dataset.tab === selected));
  document.querySelectorAll('#section-guildguard .settings-tab-pane').forEach(pane => { pane.style.display = pane.id === `guildGuardTab-${selected}` ? '' : 'none'; });
}

function guildGuardSignals(incident) {
  try {
    const signals = JSON.parse(incident?.signals_json || '[]');
    return [...new Set(signals.map(signal => GUILD_GUARD_DETECTOR_LABELS[signal.detector] || signal.detector).filter(Boolean))];
  } catch (_) { return []; }
}

function renderGuildGuardConfig(config) {
  document.getElementById('guildGuardEnabled').checked = config.enabled === true;
  document.getElementById('guildGuardMode').value = config.mode === 'enforce' ? 'enforce' : 'monitor';
  document.getElementById('guildGuardRetention').value = Number(config.retentionDays || 30);
  loadGuildGuardAlertChannels(config.alertChannelId || '');
  document.querySelectorAll('[data-guildguard-detector]').forEach(input => { input.checked = config.detectors?.[input.dataset.guildguardDetector]?.enabled === true; });
  document.getElementById('guildGuardActionsEnabled').checked = config.actions?.enabled === true;
  document.querySelectorAll('[data-guildguard-action]').forEach(input => { input.checked = config.actions?.[input.dataset.guildguardAction] === true; });
  document.getElementById('guildGuardStaffRuleEnabled').checked = config.rules?.staffImpersonation?.enabled === true;
  document.getElementById('guildGuardStaffRuleThreshold').value = Number(config.rules?.staffImpersonation?.threshold || 50);
  document.getElementById('guildGuardStaffRuleTimeoutSeconds').value = Number(config.rules?.staffImpersonation?.timeoutSeconds || 3600);
  document.getElementById('guildGuardStaffRuleDelete').checked = config.rules?.staffImpersonation?.deleteMessages !== false;
  document.getElementById('guildGuardStaffRulePing').checked = config.rules?.staffImpersonation?.pingStaff !== false;
  document.getElementById('guildGuardRiskWarning').value = Number(config.risk?.warning || 35);
  document.getElementById('guildGuardRiskTimeout').value = Number(config.risk?.timeout || 60);
  document.getElementById('guildGuardRiskQuarantine').value = Number(config.risk?.quarantine || 80);
  document.getElementById('guildGuardRiskAlert').value = Number(config.risk?.alert || 25);
  document.getElementById('guildGuardRiskDecayEnabled').checked = config.risk?.decayEnabled !== false;
  document.getElementById('guildGuardRiskDecayHalfLife').value = Number(config.risk?.decayHalfLifeHours || 24);
}

async function loadGuildGuardAlertChannels(selectedId = '') {
  const select = document.getElementById('guildGuardAlertChannel');
  if (!select) return;
  const selected = String(selectedId || '').trim();
  select.innerHTML = '<option value="">Loading channels...</option>';
  try {
    const response = await fetch('/api/admin/discord/channels', { credentials: 'include', headers: buildTenantRequestHeaders() });
    const payload = await response.json();
    if (!response.ok || payload.success === false) throw new Error(payload.message || 'Unable to load channels');
    const channels = (payload.channels || payload.data?.channels || [])
      .filter(channel => channel && channel.kind !== 'category');
    populateChannelSelects(['guildGuardAlertChannel'], channels, { selectedValue: selected }, ['selectedValue']);
    if (selected && !channels.some(channel => String(channel.id) === selected)) {
      select.insertAdjacentHTML('beforeend', `<option value="${escapeHtml(selected)}" selected>Unknown channel (${escapeHtml(selected)})</option>`);
    }
  } catch (error) {
    select.innerHTML = '<option value="">Unable to load channels</option>';
    if (selected) select.insertAdjacentHTML('beforeend', `<option value="${escapeHtml(selected)}" selected>Configured channel (${escapeHtml(selected)})</option>`);
  }
}

function renderGuildGuardIncidents(incidents) {
  const target = document.getElementById('guildGuardIncidents');
  if (!incidents.length) { target.innerHTML = '<tr><td colspan="5">No incidents in the selected server.</td></tr>'; return; }
  target.innerHTML = incidents.map(incident => {
    const labels = guildGuardSignals(incident);
    const typeLabel = `${incident.event_type || 'event'}${labels.length ? ` -> ${labels.join(', ')}` : ''}`;
    return `<tr><td>${escapeHtml(incident.created_at)}</td><td><code>${escapeHtml(typeLabel)}</code></td><td>${escapeHtml(incident.risk_score)}</td><td>${escapeHtml(incident.status)}</td><td><button class="btn-secondary" data-guildguard-detail-id="${escapeHtml(incident.incident_id)}">Details</button><button class="btn-secondary" data-guildguard-review="reviewed" data-incident-id="${escapeHtml(incident.incident_id)}">Review</button><button class="btn-secondary" data-guildguard-review="confirmed" data-incident-id="${escapeHtml(incident.incident_id)}">Confirm</button><button class="btn-danger" data-guildguard-review="false_positive" data-incident-id="${escapeHtml(incident.incident_id)}">False positive</button></td></tr>`;
  }).join('');
  target.querySelectorAll('[data-guildguard-review]').forEach(button => button.addEventListener('click', () => reviewGuildGuardIncident(button.dataset.incidentId, button.dataset.guildguardReview)));
  target.querySelectorAll('[data-guildguard-detail-id]').forEach(button => button.addEventListener('click', () => loadGuildGuardIncidentDetail(button.dataset.guildguardDetailId)));
}

async function loadGuildGuardIncidentDetail(incidentId) {
  const target = document.getElementById('guildGuardIncidentDetail');
  try {
    const incidentResponse = await fetch(`/api/admin/guildguard/incidents/${encodeURIComponent(incidentId)}`, { credentials: 'include' });
    const incidentPayload = await incidentResponse.json();
    if (!incidentResponse.ok) throw new Error(incidentPayload.message || 'Unable to load incident details');
    const incident = incidentPayload.data?.incident || incidentPayload.incident;
    const riskResponse = incident.user_id ? await fetch(`/api/admin/guildguard/users/${encodeURIComponent(incident.user_id)}/risk`, { credentials: 'include' }) : null;
    const riskPayload = riskResponse ? await riskResponse.json() : {};
    const risk = riskPayload.data || riskPayload;
    const signals = JSON.parse(incident.signals_json || '[]');
    const evidence = JSON.parse(incident.evidence_json || '{}');
    target.style.display = '';
    target.innerHTML = `<div class="card-header-row"><h3>Incident details</h3><button type="button" class="btn-secondary" onclick="document.getElementById('guildGuardIncidentDetail').style.display='none'">Close</button></div><p><strong>Incident:</strong> <code>${escapeHtml(incident.incident_id)}</code> &nbsp; <strong>User:</strong> <code>${escapeHtml(incident.user_id || 'unknown')}</code></p><p><strong>Signals:</strong> ${escapeHtml(signals.map(signal => `${GUILD_GUARD_DETECTOR_LABELS[signal.detector] || signal.detector} (${signal.score})`).join(', ') || 'none')}</p><details open><summary>Evidence</summary><pre>${escapeHtml(JSON.stringify(evidence, null, 2))}</pre></details><h4>User risk history</h4><p>Current score: <strong>${escapeHtml(risk.profile?.risk_score ?? 0)}</strong> (${escapeHtml(risk.profile?.risk_level || 'low')}); violations: ${escapeHtml(risk.profile?.violation_count ?? 0)}</p><div class="data-table-wrap"><table class="data-table"><thead><tr><th>Time</th><th>Event</th><th>Score</th><th>Status</th></tr></thead><tbody>${(risk.incidents || []).slice(0, 20).map(item => `<tr><td>${escapeHtml(item.created_at)}</td><td>${escapeHtml(item.event_type)}</td><td>${escapeHtml(item.risk_score)}</td><td>${escapeHtml(item.status)}</td></tr>`).join('') || '<tr><td colspan="4">No related incidents.</td></tr>'}</tbody></table></div>`;
  } catch (error) {
    target.style.display = '';
    target.textContent = error.message || 'Unable to load incident details';
  }
}

function renderGuildGuardSummary(summary) {
  const counts = summary?.statuses || {};
  const metrics = [
    ['Total (7d)', summary?.total ?? 0], ['Open', counts.open || 0], ['Confirmed', counts.confirmed || 0],
    ['False positives', counts.false_positive || 0], ['Avg. risk', summary?.averageRiskScore ?? 0]
  ];
  document.getElementById('guildGuardMetrics').className = 'overview-metrics-grid';
  document.getElementById('guildGuardMetrics').innerHTML = metrics.map(([label, value]) => `<div class="overview-metric"><div class="overview-metric-val">${escapeHtml(value)}</div><div class="overview-metric-label">${escapeHtml(label)}</div></div>`).join('');
}

function renderGuildGuardIdentities(identities) {
  const target = document.getElementById('guildGuardIdentities');
  if (!identities.length) { target.innerHTML = '<tr><td colspan="5">No privileged staff identities found.</td></tr>'; return; }
  target.innerHTML = identities.map(identity => `<tr><td><code>${escapeHtml(identity.user_id)}</code></td><td>${escapeHtml(identity.username || '')}</td><td>${escapeHtml(identity.display_name || '')}</td><td>${Number(identity.managed_by_roles) === 1 ? 'Role permissions' : 'Manual override'}</td><td>${Number(identity.enabled) === 1 ? 'Active' : 'Disabled'}</td></tr>`).join('');
}

async function loadGuildGuardIdentities() {
  const response = await fetch('/api/admin/guildguard/staff-identities', { credentials: 'include' });
  const payload = await response.json();
  if (!response.ok) throw new Error(payload.message || 'Unable to load Guild Guard identities');
  renderGuildGuardIdentities(payload.data?.identities || payload.identities || []);
}

async function reviewGuildGuardIncident(incidentId, status) {
  const reason = status === 'false_positive' ? window.prompt('Why is this a false positive?') : '';
  if (status === 'false_positive' && !reason) return;
  const endpoint = status === 'false_positive'
    ? `/api/admin/guildguard/incidents/${encodeURIComponent(incidentId)}/false-positive`
    : `/api/admin/guildguard/incidents/${encodeURIComponent(incidentId)}/review`;
  const response = await fetch(endpoint, { method: 'POST', credentials: 'include', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(status === 'false_positive' ? { reason } : { status }) });
  if (!response.ok) throw new Error('Unable to update Guild Guard incident');
  await loadGuildGuardView();
}

async function saveGuildGuardConfig(event) {
  event.preventDefault();
  const detectors = {};
  document.querySelectorAll('[data-guildguard-detector]').forEach(input => { detectors[input.dataset.guildguardDetector] = { enabled: input.checked }; });
  const actions = { enabled: document.getElementById('guildGuardActionsEnabled').checked };
  document.querySelectorAll('[data-guildguard-action]').forEach(input => { actions[input.dataset.guildguardAction] = input.checked; });
  const rules = {
    staffImpersonation: {
      enabled: document.getElementById('guildGuardStaffRuleEnabled').checked,
      threshold: Number(document.getElementById('guildGuardStaffRuleThreshold').value || 50),
      timeoutUsers: true,
      timeoutSeconds: Number(document.getElementById('guildGuardStaffRuleTimeoutSeconds').value || 3600),
      deleteMessages: document.getElementById('guildGuardStaffRuleDelete').checked,
      pingStaff: document.getElementById('guildGuardStaffRulePing').checked
    }
  };
  const risk = {
    warning: Number(document.getElementById('guildGuardRiskWarning').value || 35),
    timeout: Number(document.getElementById('guildGuardRiskTimeout').value || 60),
    quarantine: Number(document.getElementById('guildGuardRiskQuarantine').value || 80),
    alert: Number(document.getElementById('guildGuardRiskAlert').value || 25),
    decayEnabled: document.getElementById('guildGuardRiskDecayEnabled').checked,
    decayHalfLifeHours: Number(document.getElementById('guildGuardRiskDecayHalfLife').value || 24)
  };
  const response = await fetch('/api/admin/guildguard/config', { method: 'PUT', credentials: 'include', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ enabled: document.getElementById('guildGuardEnabled').checked, mode: document.getElementById('guildGuardMode').value, retentionDays: Number(document.getElementById('guildGuardRetention').value || 30), alertChannelId: document.getElementById('guildGuardAlertChannel').value || null, detectors, actions, rules, risk }) });
  const payload = await response.json();
  if (!response.ok || payload.success === false) throw new Error(payload.message || 'Unable to save Guild Guard configuration');
  renderGuildGuardConfig(payload.data?.config || payload.config || {});
  document.getElementById('guildGuardConfigStatus').textContent = 'Saved';
  setTimeout(() => { document.getElementById('guildGuardConfigStatus').textContent = ''; }, 3000);
}

function renderGuildGuardDomains(domains) {
  const target = document.getElementById('guildGuardDomains');
  const sections = [['allow', 'Allowed domains', domains?.allow || []], ['block', 'Blocked domains', domains?.block || []]];
  target.innerHTML = sections.map(([type, label, values]) => `<h4>${label}</h4>${values.length ? `<div style="display:flex;gap:8px;flex-wrap:wrap;">${values.map(domain => `<span class="status-badge status-live" style="display:inline-flex;align-items:center;gap:6px;">${escapeHtml(domain)} <button type="button" class="btn-danger btn-sm" data-guildguard-domain-type="${type}" data-guildguard-domain="${escapeHtml(domain)}">Remove</button></span>`).join('')}</div>` : '<p class="section-subtitle">None configured.</p>'}`).join('');
  target.querySelectorAll('[data-guildguard-domain]').forEach(button => button.addEventListener('click', () => removeGuildGuardDomain(button.dataset.guildguardDomainType, button.dataset.guildguardDomain)));
}

async function loadGuildGuardDomains() {
  const response = await fetch('/api/admin/guildguard/domains', { credentials: 'include' });
  const payload = await response.json();
  if (!response.ok) throw new Error(payload.message || 'Unable to load Guild Guard domains');
  renderGuildGuardDomains(payload.data?.domains || payload.domains || {});
}

async function saveGuildGuardDomain(event) {
  event.preventDefault();
  const response = await fetch('/api/admin/guildguard/domains', { method: 'POST', credentials: 'include', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ type: document.getElementById('guildGuardDomainType').value, domain: document.getElementById('guildGuardDomain').value.trim(), reason: document.getElementById('guildGuardDomainReason').value.trim() }) });
  const payload = await response.json();
  if (!response.ok || payload.success === false) throw new Error(payload.message || 'Unable to save domain');
  document.getElementById('guildGuardDomainForm').reset();
  document.getElementById('guildGuardDomainStatus').textContent = 'Saved';
  await loadGuildGuardDomains();
}

async function removeGuildGuardDomain(type, domain) {
  const response = await fetch(`/api/admin/guildguard/domains?type=${encodeURIComponent(type)}&domain=${encodeURIComponent(domain)}`, { method: 'DELETE', credentials: 'include' });
  if (!response.ok) throw new Error('Unable to remove domain');
  await loadGuildGuardDomains();
}

async function runGuildGuardRetention() {
  const response = await fetch('/api/admin/guildguard/retention/run', { method: 'POST', credentials: 'include', headers: { 'Content-Type': 'application/json' }, body: '{}' });
  if (!response.ok) throw new Error('Unable to run Guild Guard retention cleanup');
  await loadGuildGuardView();
}

async function loadGuildGuardView() {
  if (!activeGuildId || !(isAdmin || isSuperadmin)) return;
  const status = document.getElementById('guildGuardStatus');
  try {
    const [incidentsResponse, configResponse, summaryResponse] = await Promise.all([
      fetch('/api/admin/guildguard/incidents?limit=100', { credentials: 'include' }),
      fetch('/api/admin/guildguard/config', { credentials: 'include' }),
      fetch('/api/admin/guildguard/summary?days=7', { credentials: 'include' })
    ]);
    const incidentsPayload = await incidentsResponse.json();
    const configPayload = await configResponse.json();
    const summaryPayload = await summaryResponse.json();
    if (!configResponse.ok) throw new Error(configPayload.message || 'Unable to load Guild Guard configuration');
    renderGuildGuardIncidents(incidentsPayload.data?.incidents || incidentsPayload.incidents || []);
    renderGuildGuardConfig(configPayload.data?.config || configPayload.config || {});
    renderGuildGuardSummary(summaryPayload.data?.summary || summaryPayload.summary || {});
    await loadGuildGuardIdentities();
    await loadGuildGuardDomains();
    status.textContent = '';
  } catch (error) {
    status.textContent = error.message || 'Unable to load Guild Guard';
  }
}

document.addEventListener('DOMContentLoaded', () => {
  document.getElementById('guildGuardConfigForm')?.addEventListener('submit', event => saveGuildGuardConfig(event).catch(error => { document.getElementById('guildGuardConfigStatus').textContent = error.message; }));
  document.getElementById('guildGuardDomainForm')?.addEventListener('submit', event => saveGuildGuardDomain(event).catch(error => { document.getElementById('guildGuardDomainStatus').textContent = error.message; }));
});

// ==================== GENERAL HUB & SETTINGS ====================


