// ==================== NAVIGATION ====================
function openAdminSettingsEntry() {
  if (!userData) {
    showInfo('Please log in to access modules.');
    switchSection('landing');
    return;
  }
  if (!(isAdmin || isSuperadmin)) {
    showInfo('Admin access required for module workspace.');
    switchSection('landing');
    return;
  }
  if (!activeGuildId) {
    showInfo('Select a server first to open modules.');
    switchSection('servers');
    return;
  }
  moduleAdminWorkspaceMode = true;
  switchSection('module-hub');
}

function goHomePage() {
  switchSection('landing', { updateUrl: false });
}

function openSidebarSection(sectionName) {
  switchSection(sectionName, { force: true, fromModules: true });
}

function switchSection(sectionName, options = {}) {
  sectionName = normalizePortalSectionName(sectionName);

  // Prevent redundant reloads if clicking the already active section (unless forced)
  const storedSection = getStoredPortalSection();
  const activeSection = document.querySelector('.content-section.active');
  const activeSectionName = activeSection?.id?.startsWith('section-')
    ? normalizePortalSectionName(activeSection.id.slice('section-'.length))
    : '';
  if (sectionName === storedSection && sectionName === activeSectionName && !options.force) {
    return;
  }

  const adminManagedModuleSections = new Set([
    'governance',
    'wallets',
    'invites',
    'aiassistant',
    'telegram-bridge',
    'treasury',
    'nft-activity',
    'token-activity',
    'heist',
    'battle',
    'engagement',
    'welcome',
    'self-serve-roles',
    'ticketing',
    'guildguard'
  ]);
  const workspaceSections = new Set(['module-hub', 'settings', 'vault']);
  if (workspaceSections.has(sectionName)) {
    moduleAdminWorkspaceMode = true;
  } else if (adminManagedModuleSections.has(sectionName)) {
    const fromWorkspace = options.fromModules === true || workspaceSections.has(storedSection) || workspaceSections.has(activeSectionName);
    if (!fromWorkspace) {
      moduleAdminWorkspaceMode = false;
    }
  } else {
    moduleAdminWorkspaceMode = false;
  }

  if (!isPublicPortalSection(sectionName) && !userData) {
    if (!options.silentGate) showInfo('Please log in to access this area.');
    sectionName = 'landing';
  }

  if (sectionName === 'admin' && !isSuperadmin) {
    if (!options.silentGate) showInfo('Superadmin access required.');
    sectionName = (isAdmin || isSuperadmin) ? (activeGuildId ? 'module-hub' : 'servers') : 'landing';
  }

  if (['settings', 'invites', 'aiassistant', 'guildguard'].includes(sectionName) && !(isAdmin || isSuperadmin)) {
    if (!options.silentGate) showInfo('Admin access required for this area.');
    sectionName = userData ? (activeGuildId ? 'module-hub' : 'profile') : 'landing';
  }
  if (sectionName === 'vault' && !(isAdmin || isSuperadmin)) {
    if (!options.silentGate) showInfo('Admin access required for this area.');
    sectionName = userData ? (activeGuildId ? 'module-hub' : 'profile') : 'landing';
  }

  const serverContextSections = new Set([
    'dashboard',
    'module-hub',
    'settings',
    'vault',
    'telegram-bridge',
    'auto-messages',
    'governance',
    'invites',
    'aiassistant',
    'treasury',
    'nft-activity',
    'token-activity',
    'heist',
    'battle',
    'engagement',
    'welcome',
    'self-serve-roles',
    'ticketing',
    'guildguard'
  ]);
  if (serverContextSections.has(sectionName) && !activeGuildId) {
    if (userData && hasServerChoices()) {
      if (!options.silentGate) showInfo('Select a server first to continue.');
      sectionName = 'servers';
    } else {
      sectionName = userData ? (isSuperadmin ? 'admin' : 'profile') : 'landing';
    }
  }

  const moduleState = window._tenantModuleState || null;
  const sectionRequiresModule = {
    governance: 'governance',
    wallets: 'verification',
    invites: 'invites',
    aiassistant: 'aiassistant',
    'telegram-bridge': 'telegrambridge',
    'auto-messages': 'automessages',
    treasury: 'wallettracker',
    'nft-activity': 'nfttracker',
    'token-activity': 'tokentracker',
    heist: 'heist',
    battle: 'minigames',
    welcome: 'welcome',
    vault: 'vault',
    'self-serve-roles': 'selfserveroles',
    ticketing: 'ticketing',
    engagement: 'engagement',
    guildguard: 'guildguard'
  };
  const required = sectionRequiresModule[sectionName];
  if (required && moduleState && moduleState[required] === false) {
    if (!options.silentGate) showInfo('This module is disabled for the selected server.');
    sectionName = activeGuildId ? 'module-hub' : 'servers';
  }

  setStoredPortalSection(sectionName);
  if (sectionName !== 'admin') {
    setStoredAdminView('');
  }

  const resolvedSectionName = sectionName;
  if (resolvedSectionName !== 'admin') {
    resetAdminFocusMode();
  }
  if (resolvedSectionName !== 'settings') {
    resetSettingsFocusMode();
  }

  // Update nav items (both sidebar and mobile)
  document.querySelectorAll('.nav-item').forEach(item => {
    item.classList.remove('active');
  });
  document.querySelectorAll(`.nav-item[data-section="${sectionName}"]`).forEach(item => {
    item.classList.add('active');
  });

  // Update content sections (hard-hide non-active sections to prevent bleed-through)
  const targetSectionId = `section-${resolvedSectionName}`;
  document.querySelectorAll('.content-section').forEach(section => {
    section.classList.remove('active');
    if (section.id !== targetSectionId) {
      section.style.display = 'none';
    }
  });
  const targetSection = document.getElementById(`section-${resolvedSectionName}`);
  if (targetSection) {
    targetSection.classList.add('active');
    targetSection.style.display = '';
    window.scrollTo({ top: 0, behavior: 'smooth' });
  }

  // Ensure engagement overlays never leak into other sections.
  if (resolvedSectionName !== 'engagement') {
    const monitoredOverlay = document.getElementById('engMonitoredEditorPanel');
    const hashtagOverlay = document.getElementById('engHashtagEditorPanel');
    if (monitoredOverlay) monitoredOverlay.style.display = 'none';
    if (hashtagOverlay) hashtagOverlay.style.display = 'none';
    document.body.style.overflow = '';
  }

  // Breadcrumb Logic
  const record = getServerRecord(activeGuildId);
  const serverName = record?.name || activeGuildId;
  const moduleInfo = MODULE_REGISTRY.find(m => m.section === sectionName);

  if (sectionName === 'landing' && !activeGuildId) {
    updateBreadcrumbs([]);
  } else if (sectionName === 'profile') {
    updateBreadcrumbs([{ label: 'My Profile' }]);
  } else if (sectionName === 'servers') {
    updateBreadcrumbs([{ label: 'Servers' }]);
  } else if (moduleInfo && activeGuildId) {
    updateBreadcrumbs([
      { label: 'Servers', action: "switchSection('servers')" },
      { label: serverName, action: "switchSection('module-hub')" },
      { label: moduleInfo.label }
    ]);
  } else if (sectionName === 'settings' && activeGuildId) {
    updateBreadcrumbs([
      { label: 'Servers', action: "switchSection('servers')" },
      { label: serverName, action: "switchSection('module-hub')" },
      { label: 'Settings' }
    ]);
  } else if (sectionName === 'admin') {
    updateBreadcrumbs([{ label: 'Platform Admin' }]);
  } else if (sectionName !== 'landing') {
    updateBreadcrumbs([]);
  }

  // Load section-specific data
  if (sectionName === 'landing') {
    renderGeneralSection();
  } else if (sectionName === 'dashboard') {
    loadDashboardData();
  } else if (sectionName === 'module-hub') {
    renderModuleHub();
  } else if (sectionName === 'governance' && userData) {
    loadActiveVotes();
    syncGovernanceModuleSettingsCard();
  } else if (sectionName === 'servers') {
    loadServerAccess();
  } else if (sectionName === 'wallets' && userData) {
    renderWallets();
    const verificationSettingsCard = document.getElementById('verificationModuleSettingsCard');
    if (verificationSettingsCard) {
      const canManageVerification = !!(activeGuildId && (isAdmin || isSuperadmin) && moduleAdminWorkspaceMode);
      verificationSettingsCard.style.display = canManageVerification ? '' : 'none';
      if (canManageVerification && typeof loadAdminRoles === 'function') {
        loadAdminRoles('verificationModuleSettingsContent');
      }
    }
  } else if (sectionName === 'profile' && userData) {
    renderProfileSection();
  } else if (sectionName === 'invites') {
    loadInviteTrackerSettingsView('inviteTrackerModuleSettingsPanel');
  } else if (sectionName === 'aiassistant') {
    loadAiAssistantSettingsView('aiAssistantModuleSettingsPanel');
  } else if (sectionName === 'telegram-bridge') {
    loadTelegramBridgeView('telegramBridgeModuleSettingsPanel');
  } else if (sectionName === 'auto-messages') {
    loadAutoMessagesView('autoMessagesModuleSettingsPanel');
  } else if (sectionName === 'treasury') {
    loadTreasuryWalletTable();
  } else if (sectionName === 'nft-activity') {
    loadNFTActivityView();
    if (isAdmin && moduleAdminWorkspaceMode) loadNFTActivityAdminView();
  } else if (sectionName === 'token-activity') {
    loadTokenActivityView();
  } else if (sectionName === 'battle') {
    const battleModuleSettingsCard = document.getElementById('battleModuleSettingsCard');
    const canManageBattle = !!((isAdmin || isSuperadmin) && moduleAdminWorkspaceMode);
    if (battleModuleSettingsCard) {
      battleModuleSettingsCard.style.display = canManageBattle ? '' : 'none';
    }
    if (canManageBattle && typeof loadBattleModuleSettings === 'function') {
      loadBattleModuleSettings();
    }
  } else if (sectionName === 'settings') {
    applySettingsTabVisibility(portalSettingsData || {});
    initializeSettingsClarityControls();
    switchSettingsTab('general');
  } else if (sectionName === 'vault') {
    if (typeof loadVaultSettingsTab === 'function') {
      loadVaultSettingsTab();
    }
  } else if (sectionName === 'admin') {
    loadEnvStatusBar();
  } else if (sectionName === 'heist' && userData) {
    loadHeistSection();
  } else if (sectionName === 'self-serve-roles') {
    loadSelfServeRolesPublic();
    const canManageSelfServe = !!(activeGuildId && (isAdmin || isSuperadmin) && moduleAdminWorkspaceMode);
    const adminCard = document.getElementById('selfServeRolesModuleSettingsCard');
    if (adminCard) adminCard.style.display = canManageSelfServe ? '' : 'none';
    if (canManageSelfServe) {
      loadSelfServeRolesView('selfServeRolesModuleSettingsPanel');
    }
  } else if (sectionName === 'ticketing') {
    const canManageTicketing = !!(activeGuildId && (isAdmin || isSuperadmin) && moduleAdminWorkspaceMode);
    const userCard = document.getElementById('ticketingUserOverviewCard');
    const adminCard = document.getElementById('ticketingModuleSettingsCard');
    if (userCard) userCard.style.display = canManageTicketing ? 'none' : '';
    if (adminCard) adminCard.style.display = canManageTicketing ? '' : 'none';
    if (canManageTicketing) {
      loadTicketingView('ticketingModuleSettingsPanel');
    } else {
      loadUserTicketOverview();
    }
  } else if (sectionName === 'welcome') {
    loadWelcomeSettingsSection();
  } else if (sectionName === 'engagement') {
    loadEngagementSection();
  } else if (sectionName === 'guildguard') {
    loadGuildGuardView();
  } else if (sectionName === 'plans') {
    updatePlanPrices();
    if (isAdmin) loadCurrentPlan();
  } else if (sectionName === 'help') {
    updateHelpCenterRoleVisibility();
  }

  // Keep desktop sidebar visible for command-center app shell.
  const portalLayout = document.querySelector('.portal-layout');
  if (portalLayout) {
    portalLayout.classList.remove('sidebar-hidden');
  }

  // Update URL without reload
  const url = new URL(window.location);
  if (options.updateUrl === false) {
    url.searchParams.delete('section');
    url.searchParams.delete('adminView');
  } else {
    url.searchParams.set('section', sectionName);
    if (sectionName !== 'admin') {
      url.searchParams.delete('adminView');
    }
  }
  window.history.pushState({}, '', url);
}

function toggleHelp(categoryId) {
  const content = document.getElementById(`help-${categoryId}`);
  const requiredRole = content?.getAttribute('data-help-role');
  if (!canViewHelpRole(requiredRole)) {
    showError('You do not have permission to view that help section.');
    return;
  }
  const wasVisible = !!content && content.style.display === 'block';

  // Hide all help content
  document.querySelectorAll('.help-content').forEach(content => {
    content.style.display = 'none';
  });

  // Show selected help content
  if (content && !wasVisible) {
    content.style.display = 'block';
    
    if (content.style.display === 'block') {
      // Smooth scroll to content
      setTimeout(() => {
        content.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
      }, 100);
    }
  }

  updateHelpCenterRoleVisibility();
}

async function loadTreasuryPublicView() {
  const content = document.getElementById('publicTreasuryView');
  if (!content) return;
  
  content.innerHTML = `<div style="text-align:center; padding: var(--space-5);"><div class="spinner"></div><p>Loading...</p></div>`;
  
  try {
    let data = null;
    let source = 'wallet-tracker';

    const trackerResponse = await fetch('/api/admin/wallet-tracker/balances', {
      credentials: 'include',
      headers: buildTenantRequestHeaders(),
    });

    if (trackerResponse.ok) {
      data = await trackerResponse.json();
    } else {
      source = 'treasury';
      const response = await fetch('/api/public/v1/treasury', {
        credentials: 'include',
        headers: buildTenantRequestHeaders(),
      });
      data = await response.json();
    }

    if (data && data.success) {
      const payload = data.data || {};
      const t = source === 'wallet-tracker'
        ? {
            sol: Number(payload?.totals?.sol || 0).toLocaleString(undefined, { minimumFractionDigits: 4, maximumFractionDigits: 4 }),
            usdc: Number(payload?.totals?.usdc || 0).toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 }),
            lastUpdated: payload?.lastUpdated || null,
            walletCount: Number(payload?.walletCount || 0),
          }
        : (payload || data.treasury || {});

      content.innerHTML = `
        <div style="display:grid; gap:12px; grid-template-columns:repeat(auto-fit,minmax(200px,1fr));">
          <div style="padding:16px; background:rgba(99,102,241,0.12); border:1px solid rgba(99,102,241,0.22); border-radius:10px;">
            <div style="color:var(--text-secondary); font-size:0.85em; margin-bottom:8px;">SOL Balance</div>
            <div style="font-size:2em; font-weight:700; color:#93c5fd;">${t.sol ?? t.sol_balance ?? ''}</div>
          </div>
          <div style="padding:16px; background:rgba(99,102,241,0.12); border:1px solid rgba(99,102,241,0.22); border-radius:10px;">
            <div style="color:var(--text-secondary); font-size:0.85em; margin-bottom:8px;">USDC Balance</div>
            <div style="font-size:2em; font-weight:700; color:#86efac;">${t.usdc ?? t.usdc_balance ?? ''}</div>
          </div>
          <div style="padding:16px; background:rgba(99,102,241,0.12); border:1px solid rgba(99,102,241,0.22); border-radius:10px;">
            <div style="color:var(--text-secondary); font-size:0.85em; margin-bottom:8px;">Last Updated</div>
            <div style="font-size:1.1em; font-weight:600; color:#e0e7ff;">${t.lastUpdated || t.last_updated ? new Date(t.lastUpdated || t.last_updated).toLocaleString() : ''}</div>
          </div>
        </div>
        ${source === 'wallet-tracker'
          ? `<div style="margin-top:10px; color:var(--text-secondary); font-size:0.85em;">Across ${Number(t.walletCount || 0)} tracked wallet${Number(t.walletCount || 0) === 1 ? '' : 's'}.</div>`
          : ''}
      `;
    } else {
      content.innerHTML = `<div style="color:var(--text-secondary); text-align:center; padding:20px;">Treasury data unavailable</div>`;
    }
  } catch (e) {
    content.innerHTML = `<div style="color:#ef4444; text-align:center; padding:20px;">Error loading treasury: ${escapeHtml(e.message)}</div>`;
  }
}

async function loadTreasuryTransactions() {
  const content = document.getElementById('publicTreasuryTransactions');
  if (!content) return;
  
  try {
    const response = await fetch('/api/public/v1/treasury/transactions?limit=10', {
      credentials: 'include',
      headers: buildTenantRequestHeaders(),
    });
    const data = await response.json();
    const transactions = data.data?.transactions || data.transactions || [];
    
    if (data.success && transactions.length > 0) {
      const rows = transactions.map(tx => {
        const direction = tx.direction || (tx.type === 'in' ? 'in' : 'out');
        const label = direction === 'in' || direction === 'incoming' ? ' Incoming' : ' Outgoing';
        const amount = tx.deltaSol ?? tx.amount ?? '';
        const hash = tx.signature || tx.tx_hash || '';
        const timestamp = tx.blockTime
          ? new Date(tx.blockTime * 1000)
          : (tx.timestamp ? new Date(tx.timestamp) : null);

        return `
        <div style="padding:12px; border-bottom:1px solid rgba(99,102,241,0.15); display:flex; justify-content:space-between; align-items:center;">
          <div style="flex:1;">
            <div style="color:#e0e7ff; font-weight:600;">${label}</div>
            <div style="color:var(--text-secondary); font-size:0.85em; font-family:monospace;">${hash ? `${hash.slice(0, 16)}...` : ''}</div>
          </div>
          <div style="text-align:right;">
            <div style="color:#e0e7ff; font-weight:600;">${amount} SOL</div>
            <div style="color:var(--text-secondary); font-size:0.85em;">${timestamp ? timestamp.toLocaleDateString() : ''}</div>
          </div>
        </div>
      `}).join('');
      
      content.innerHTML = `<div style="border:1px solid rgba(99,102,241,0.22); border-radius:10px; overflow:hidden;">${rows}</div>`;
    } else {
      content.innerHTML = `<div style="color:var(--text-secondary); text-align:center; padding:20px;">No transactions yet</div>`;
    }
  } catch (e) {
    content.innerHTML = `<div style="color:#ef4444; text-align:center; padding:20px;">Error loading transactions</div>`;
  }
}

