// ==================== AUTH ====================
function login() {
  if (loginRedirectInFlight) return;
  loginRedirectInFlight = true;

  const navAuthBtn = document.getElementById('navAuthBtn');
  if (navAuthBtn) {
    navAuthBtn.disabled = true;
    navAuthBtn.textContent = 'Redirecting...';
  }

  // Preserve guild + current section so user lands back in the right place
  const qs = new URLSearchParams();
  const currentSection = (document.querySelector('.nav-item.active') || {}).dataset?.section || '';
  if (activeGuildId) qs.set('guild', activeGuildId);
  if (currentSection && currentSection !== 'landing') qs.set('section', currentSection);
  const returnTo = '/app' + (qs.toString() ? '?' + qs.toString() : '');
  window.location.href = '/auth/discord/login?returnTo=' + encodeURIComponent(returnTo);

  // If navigation is blocked for any reason, allow retry.
  setTimeout(() => {
    loginRedirectInFlight = false;
    if (navAuthBtn) {
      navAuthBtn.disabled = false;
      navAuthBtn.textContent = 'Login';
    }
  }, 10000);
}

function logout() {
  closeUserMenu();
  showConfirmModal(
    'Confirm Logout',
    'Are you sure you want to log out?',
    () => {
      setActiveGuild('', { persist: true, announce: false });
      window.location.href = '/auth/discord/logout';
    }
  );
}

function handleAuth() {
  if (userData) {
    logout();
  } else {
    login();
  }
}

// ==================== UTILITY FUNCTIONS ====================
function escapeHtml(text) {
  if (!text) return '';
  const div = document.createElement('div');
  div.textContent = text;
  return div.innerHTML;
}

function escapeJsString(value) {
  return String(value ?? '')
    .replace(/\\/g, '\\\\')
    .replace(/'/g, "\\'")
    .replace(/"/g, '\\"')
    .replace(/\r/g, '\\r')
    .replace(/\n/g, '\\n')
    .replace(/</g, '\\x3C')
    .replace(/>/g, '\\x3E');
}

function formatDate(date) {
  if (!date || !(date instanceof Date) || isNaN(date)) {
    return 'Unknown date';
  }
  
  const now = new Date();
  const diff = now - date;
  const seconds = Math.floor(diff / 1000);
  const minutes = Math.floor(seconds / 60);
  const hours = Math.floor(minutes / 60);
  const days = Math.floor(hours / 24);
  
  if (seconds < 60) return 'Just now';
  if (minutes < 60) return `${minutes} minute${minutes !== 1 ? 's' : ''} ago`;
  if (hours < 24) return `${hours} hour${hours !== 1 ? 's' : ''} ago`;
  if (days < 7) return `${days} day${days !== 1 ? 's' : ''} ago`;
  
  return date.toLocaleDateString('en-US', { 
    year: 'numeric', 
    month: 'short', 
    day: 'numeric' 
  });
}


