function renderTenantTemplatePreview(previewPayload) {
  if (!previewPayload?.diff) {
    return `<div style="color:var(--text-secondary);">Select a template and click Preview to see the plan/module/limit diff before applying.</div>`;
  }

  const diff = previewPayload.diff;
  const moduleChanges = Array.isArray(diff.modules) ? diff.modules : [];
  const effectiveChanges = Array.isArray(diff.effective) ? diff.effective : [];
  const planText = diff.planChanged
    ? `${escapeHtml(getTenantPlanLabel(diff.plan?.before))}  ${escapeHtml(getTenantPlanLabel(diff.plan?.after))}`
    : escapeHtml(getTenantPlanLabel(diff.plan?.after));

  const moduleRows = moduleChanges.length
    ? moduleChanges.slice(0, 8).map(change => {
        const state = change.after ? 'enabled' : 'disabled';
        return `<div><code>${escapeHtml(change.moduleKey)}</code>  <strong>${state}</strong></div>`;
      }).join('')
    : '<div style="color:var(--text-secondary);">No module toggle changes.</div>';

  const limitRows = effectiveChanges.length
    ? effectiveChanges.slice(0, 8).map(change => {
        const beforeText = change.before === null || change.before === undefined ? 'Unlimited' : String(change.before);
        const afterText = change.after === null || change.after === undefined ? 'Unlimited' : String(change.after);
        return `<div><code>${escapeHtml(change.moduleKey)}.${escapeHtml(change.limitKey)}</code>: ${escapeHtml(beforeText)}  <strong>${escapeHtml(afterText)}</strong></div>`;
      }).join('')
    : '<div style="color:var(--text-secondary);">No effective limit changes.</div>';

  const hiddenModuleCount = Math.max(0, moduleChanges.length - 8);
  const hiddenLimitCount = Math.max(0, effectiveChanges.length - 8);

  return `
    <div style="display:grid; gap:10px;">
      <div><strong>Plan:</strong> ${planText}</div>
      <div><strong>Module Changes (${moduleChanges.length}):</strong><div style="margin-top:6px; display:grid; gap:4px;">${moduleRows}</div>${hiddenModuleCount ? `<div style="margin-top:6px; color:var(--text-secondary);">+${hiddenModuleCount} more module changes</div>` : ''}</div>
      <div><strong>Effective Limit Changes (${effectiveChanges.length}):</strong><div style="margin-top:6px; display:grid; gap:4px;">${limitRows}</div>${hiddenLimitCount ? `<div style="margin-top:6px; color:var(--text-secondary);">+${hiddenLimitCount} more limit changes</div>` : ''}</div>
    </div>
  `;
}

function renderTenantDetailPanel(tenant, tenantLimits = null, workspaceTenantTab = '') {
  if (!tenant) {
    return `<div style="padding:18px; text-align:center; color:var(--text-secondary);">Select a tenant to manage plan, modules, branding, and status.</div>`;
  }
  const workspaceTab = String(workspaceTenantTab || '').toLowerCase();
  const forcePlanControls = workspaceTab === 'plan';
  const forceModulesControls = workspaceTab === 'modules';
  const forceBranding = workspaceTab === 'branding';
  const showOverviewSection = !forcePlanControls && !forceModulesControls && !forceBranding;
  const showControlsSection = forcePlanControls;
  const showModulesSection = forceModulesControls;
  const showBrandingSection = forceBranding;
  const allowTenantMockData = isMockModeEnabled();

  const billing = tenant.billing || null;
  const billingStatus = String(billing?.subscriptionStatus || 'unknown').toLowerCase();
  const billingInterval = billing?.billingInterval === 'yearly' ? 'Yearly' : (billing?.billingInterval === 'monthly' ? 'Monthly' : 'Unknown');
  const billingProvider = billing?.provider ? String(billing.provider).toUpperCase() : 'N/A';
  const billingEnd = billing?.currentPeriodEnd ? new Date(billing.currentPeriodEnd).toLocaleString() : 'Not set';

  const resolvedPlans = (Array.isArray(superadminWorkspacePlansCache) && superadminWorkspacePlansCache.length)
    ? superadminWorkspacePlansCache.map(plan => ({
        key: String(plan?.key || '').toLowerCase(),
        label: String(plan?.label || plan?.key || '').trim(),
      })).filter(plan => plan.key && plan.label)
    : Object.entries(TENANT_PLAN_LABELS).map(([key, label]) => ({ key, label }));
  const planOptions = resolvedPlans.map(({ key, label }) => `
    <option value="${escapeHtml(key)}"${tenant.planKey === key ? ' selected' : ''}>${escapeHtml(label)}</option>
  `).join('');

  const templateOptions = (Array.isArray(superadminTemplateCatalog) ? superadminTemplateCatalog : []).map(template => `
    <option value="${escapeHtml(template.key)}">${escapeHtml(template.label || template.key)}${template.planKey ? ` (${escapeHtml(getTenantPlanLabel(template.planKey))})` : ''}</option>
  `).join('');

  const moduleToggles = Object.entries(TENANT_MODULE_LABELS).map(([moduleKey, label]) => {
    const isOn = !!tenant.modules?.[moduleKey];
    return `
      <div style="display:flex; justify-content:space-between; align-items:center; gap:12px; padding:10px 12px; border:1px solid rgba(99,102,241,0.14); border-radius:10px; background:rgba(14,23,44,0.45);">
        <span style="color:#e0e7ff; font-weight:600;">${escapeHtml(label)}</span>
        <label style="position:relative;display:inline-block;width:44px;height:24px;flex-shrink:0;">
          <input type="checkbox" ${isOn ? 'checked' : ''} onchange="toggleTenantModule('${escapeHtml(moduleKey)}', this); this.parentElement.querySelector('.tenant-toggle-track').style.background=this.checked?'var(--gold)':'#555'; this.parentElement.querySelector('.tenant-toggle-knob').style.left=this.checked?'22px':'3px';" style="opacity:0;width:0;height:0;">
          <span class="tenant-toggle-track" style="position:absolute;cursor:pointer;top:0;left:0;right:0;bottom:0;background:${isOn ? 'var(--gold)' : '#555'};border-radius:24px;transition:.3s;"></span>
          <span class="tenant-toggle-knob" style="position:absolute;height:18px;width:18px;left:${isOn ? '22px' : '3px'};bottom:3px;background:#fff;border-radius:50%;transition:.3s;pointer-events:none;"></span>
        </label>
      </div>
    `;
  }).join('');

  const branding = tenant.branding || {};
  const limitDefinitions = tenantLimits?.definitions || {};
  const planModuleLimits = tenantLimits?.planLimits || {};
  const overrideModuleLimits = tenantLimits?.overrides || {};
  const effectiveModuleLimits = tenantLimits?.effective || {};
  const moduleLimitRows = (() => {
    const moduleKeys = [...new Set([
      ...Object.keys(limitDefinitions || {}),
      ...Object.keys(planModuleLimits || {}),
      ...Object.keys(effectiveModuleLimits || {}),
      ...Object.keys(overrideModuleLimits || {}),
    ])].sort();

    const rows = [];
    moduleKeys.forEach(moduleKey => {
      const perModuleDefs = limitDefinitions[moduleKey] || {};
      const perModulePlan = planModuleLimits[moduleKey] || {};
      const perModuleOverride = overrideModuleLimits[moduleKey] || {};
      const perModuleEffective = effectiveModuleLimits[moduleKey] || {};
      const limitKeys = [...new Set([
        ...Object.keys(perModuleDefs),
        ...Object.keys(perModulePlan),
        ...Object.keys(perModuleOverride),
        ...Object.keys(perModuleEffective),
      ])].sort();

      limitKeys.forEach(limitKey => {
        const hasOverride = Object.prototype.hasOwnProperty.call(perModuleOverride, limitKey);
        const overrideValue = hasOverride ? perModuleOverride[limitKey] : '';
        const defaultValue = perModulePlan[limitKey];
        const effectiveValue = perModuleEffective[limitKey];
        const placeholder = (defaultValue === null || defaultValue === undefined) ? 'Unlimited' : String(defaultValue);
        const effectiveText = (effectiveValue === null || effectiveValue === undefined) ? 'Unlimited' : String(effectiveValue);
        const valueText = (overrideValue === null || overrideValue === undefined || overrideValue === '') ? '' : String(overrideValue);
        const label = perModuleDefs?.[limitKey]?.label || limitKey;

        rows.push(`
          <div style="display:grid; grid-template-columns:minmax(0,1.4fr) minmax(0,0.8fr) minmax(140px,0.6fr) minmax(0,0.8fr); gap:10px; align-items:center; padding:10px 12px; border:1px solid rgba(99,102,241,0.15); border-radius:10px; background:rgba(14,23,44,0.45);">
            <div style="min-width:0;">
              <div style="color:#e0e7ff; font-weight:600;">${escapeHtml(label)}</div>
              <div style="color:var(--text-secondary); font-size:0.8em; margin-top:3px;">${escapeHtml(getTenantModuleLabel(moduleKey))} <span style="font-family:monospace;">(${escapeHtml(limitKey)})</span></div>
            </div>
            <div style="color:var(--text-secondary); font-size:0.82em;">Plan: <span style="color:#c9d6ff; font-weight:600;">${escapeHtml(placeholder)}</span></div>
            <input data-tenant-limit-input="1" data-module-key="${escapeHtml(moduleKey)}" data-limit-key="${escapeHtml(limitKey)}" type="number" min="0" step="1" value="${escapeHtml(valueText)}" placeholder="${escapeHtml(placeholder)}" style="padding:9px 10px; background:rgba(30,41,59,0.8); border:1px solid rgba(99,102,241,0.22); border-radius:8px; color:#e0e7ff;">
            <div style="color:var(--text-secondary); font-size:0.82em;">Effective: <span style="color:#e2e8f0; font-weight:700;">${escapeHtml(effectiveText)}</span></div>
          </div>
        `);
      });
    });

    if (rows.length === 0) {
      return `<div style="padding:14px; border:1px dashed rgba(99,102,241,0.18); border-radius:10px; color:var(--text-secondary); text-align:center;">No module limits available for this tenant yet.</div>`;
    }
    return rows.join('');
  })();

  return `
    <div style="display:grid; gap:16px;">
      <div style="padding:10px 12px;border:1px solid rgba(99,102,241,0.2);border-radius:10px;background:rgba(30,41,59,0.45);color:#cbd5e1;font-size:0.82em;">
        <strong style="color:#e2e8f0;">You are editing tenant:</strong> ${escapeHtml(tenant.guildName || tenant.guildId)} <span style="font-family:monospace;opacity:.85;">(${escapeHtml(tenant.guildId)})</span>
      </div>

      <div id="tenantDetail-overview" style="display:${showOverviewSection ? 'grid' : 'none'}; gap:14px; grid-template-columns:minmax(0,1.2fr) minmax(0,0.8fr);">
        <div style="padding:14px; border:1px solid rgba(99,102,241,0.18); border-radius:12px; background:rgba(10,16,30,0.35);">
          <div style="display:flex; justify-content:space-between; align-items:center; gap:12px; margin-bottom:12px;">
            <div>
              <h4 style="margin:0; color:#c9d6ff;">${escapeHtml(tenant.guildName || tenant.guildId)}</h4>
              <div style="color:var(--text-secondary); font-size:0.82em; font-family:monospace; word-break:break-all; margin-top:4px;">${escapeHtml(tenant.guildId)}</div>
            </div>
            ${getTenantStatusBadge(tenant.status)}
          </div>
          <div style="display:grid; grid-template-columns:repeat(3,minmax(0,1fr)); gap:10px; color:#c9d6ff; font-size:0.88em;">
            <div style="padding:10px 12px; background:rgba(30,41,59,0.45); border-radius:10px;">
              <div style="color:var(--text-secondary); font-size:0.8em;">Plan</div>
              <div style="font-weight:600; margin-top:4px;">${escapeHtml(getTenantPlanLabel(tenant.planKey))}</div>
            </div>
            <div style="padding:10px 12px; background:rgba(30,41,59,0.45); border-radius:10px;">
              <div style="color:var(--text-secondary); font-size:0.8em;">Modules</div>
              <div style="font-weight:600; margin-top:4px;">${escapeHtml(String(tenant.enabledModulesCount || 0))}/${escapeHtml(String(tenant.totalModulesCount || 0))}</div>
            </div>
            <div style="padding:10px 12px; background:rgba(30,41,59,0.45); border-radius:10px;">
              <div style="color:var(--text-secondary); font-size:0.8em;">Managed</div>
              <div style="font-weight:600; margin-top:4px;">${tenant.readOnlyManaged ? 'Read only' : 'Editable'}</div>
            </div>
          </div>
        </div>
        <div style="padding:14px; border:1px solid rgba(99,102,241,0.18); border-radius:12px; background:rgba(10,16,30,0.35);">
          <div style="color:#c9d6ff; font-weight:600; margin-bottom:10px;">Recent Audit</div>
          <div id="tenantAuditLogList" style="display:grid; gap:10px;">${renderTenantAuditLog(selectedTenantAuditCache)}</div>
        </div>
      </div>

      <div id="tenantDetail-controls" style="display:${showControlsSection ? 'grid' : 'none'};gap:16px; grid-template-columns:minmax(0,0.8fr) minmax(0,1.2fr);">
        <div style="padding:14px; border:1px solid rgba(99,102,241,0.18); border-radius:12px; background:rgba(10,16,30,0.35); min-width:0;">
          <div style="display:flex; justify-content:space-between; align-items:center; gap:12px; margin-bottom:12px; flex-wrap:wrap;">
            <h4 style="margin:0; color:#c9d6ff;">Monetization Template</h4>
            <div style="display:flex; gap:8px; align-items:center; flex-wrap:wrap; justify-content:flex-end; margin-left:auto; max-width:100%;">
              <button class="btn-secondary" id="tenantTemplatePreviewBtn" onclick="previewTenantTemplate()" style="padding:8px 14px; white-space:nowrap;">Preview</button>
              <button class="btn-secondary" id="tenantTemplateRollbackBtn" onclick="rollbackTenantTemplate()" style="padding:8px 14px; white-space:nowrap;">Rollback Last</button>
              <button class="btn-primary" id="tenantTemplateApplyBtn" onclick="applyTenantTemplate()" style="padding:8px 14px; white-space:nowrap;">Apply Template</button>
            </div>
          </div>
          <label style="display:grid; gap:8px; color:#e0e7ff; font-size:0.9em;">
            <span>Template</span>
            <select id="tenantTemplateSelect" onchange="updateTenantTemplateDescription()" style="padding:10px 12px; background:rgba(30,41,59,0.8); border:1px solid rgba(99,102,241,0.22); border-radius:8px; color:#e0e7ff;">
              ${templateOptions || '<option value="">No templates available</option>'}
            </select>
          </label>
          <div id="tenantTemplateDescription" style="margin-top:12px; color:var(--text-secondary); font-size:0.82em; line-height:1.5;">
            ${escapeHtml(superadminTemplateCatalog?.[0]?.description || 'Apply a template to set plan, module toggles, and module limits in one action.')}
          </div>
          <div id="tenantTemplatePreview" style="margin-top:12px; padding:10px 12px; border:1px solid rgba(99,102,241,0.16); border-radius:10px; background:rgba(14,23,44,0.45); color:#cbd5ff; font-size:0.82em; line-height:1.5;">
            ${renderTenantTemplatePreview(selectedTenantTemplatePreview)}
          </div>
        </div>

        <div style="padding:14px; border:1px solid rgba(99,102,241,0.18); border-radius:12px; background:rgba(10,16,30,0.35); min-width:0;">
          <div style="display:flex; justify-content:space-between; align-items:center; gap:12px; margin-bottom:12px; flex-wrap:wrap;">
            <h4 style="margin:0; color:#c9d6ff;">Plan Assignment</h4>
            <button class="btn-primary" id="tenantPlanApplyBtn" onclick="applyTenantPlan()" style="padding:8px 14px; white-space:nowrap; margin-left:auto;">Apply</button>
          </div>
          <label style="display:grid; gap:8px; color:#e0e7ff; font-size:0.9em;">
            <span>Plan</span>
            <select id="tenantPlanSelect" style="padding:10px 12px; background:rgba(30,41,59,0.8); border:1px solid rgba(99,102,241,0.22); border-radius:8px; color:#e0e7ff;">
              ${planOptions}
            </select>
          </label>
          <div style="margin-top:12px; color:var(--text-secondary); font-size:0.82em; line-height:1.5;">
            ${escapeHtml(tenant.planDescription || '')}
          </div>
        </div>

        <div style="padding:14px; border:1px solid rgba(99,102,241,0.18); border-radius:12px; background:rgba(10,16,30,0.35);">
          <div style="display:flex; justify-content:space-between; align-items:center; gap:12px; margin-bottom:12px;">
            <h4 style="margin:0; color:#c9d6ff;">Tenant Status</h4>
            <button class="btn-secondary" id="tenantStatusSaveBtn" onclick="saveTenantStatus()" style="padding:8px 14px;">Save</button>
          </div>
          <label style="display:grid; gap:8px; color:#e0e7ff; font-size:0.9em;">
            <span>Status</span>
            <select id="tenantStatusSelect" style="padding:10px 12px; background:rgba(30,41,59,0.8); border:1px solid rgba(99,102,241,0.22); border-radius:8px; color:#e0e7ff;">
              <option value="active"${String(tenant.status || 'active') === 'active' ? ' selected' : ''}>Active</option>
              <option value="suspended"${String(tenant.status || 'active') === 'suspended' ? ' selected' : ''}>Suspended</option>
            </select>
          </label>
          ${allowTenantMockData ? `
          <div style="display:flex; align-items:center; justify-content:space-between; margin-top:12px; padding:10px 12px; border:1px solid rgba(99,102,241,0.16); border-radius:10px; background:rgba(14,23,44,0.45);">
            <div style="color:#e0e7ff; font-size:0.9em; font-weight:600;">Tenant Mock Data</div>
            <label style="position:relative;display:inline-block;width:44px;height:24px;">
              <input id="tenantMockDataSwitch" type="checkbox" ${(tenant.limits?.mock_data_enabled ? 'checked' : '')} onchange="this.parentElement.querySelector('.track').style.background=this.checked?'var(--gold)':'#555'; this.parentElement.querySelector('.knob').style.left=this.checked?'22px':'3px';" style="opacity:0;width:0;height:0;">
              <span class="track" style="position:absolute;inset:0;background:${tenant.limits?.mock_data_enabled ? 'var(--gold)' : '#555'};border-radius:24px;transition:.25s;"></span>
              <span class="knob" style="position:absolute;width:18px;height:18px;left:${tenant.limits?.mock_data_enabled ? '22px' : '3px'};bottom:3px;background:#fff;border-radius:50%;transition:.25s;pointer-events:none;"></span>
            </label>
          </div>
          <div style="margin-top:8px; text-align:right;">
            <button class="btn-secondary" id="tenantMockDataSaveBtn" onclick="saveTenantMockData()" style="padding:8px 14px;">Save Mock Data</button>
          </div>
          ` : ''}
          <div style="margin-top:12px; padding:10px 12px; border:1px solid rgba(99,102,241,0.16); border-radius:10px; background:rgba(14,23,44,0.45); color:#c9d6ff; font-size:0.85em;">
            <div style="font-weight:600; margin-bottom:8px;">Billing Snapshot</div>
            <div style="display:grid; grid-template-columns:repeat(2,minmax(0,1fr)); gap:6px;">
              <div><span style="color:var(--text-secondary);">Provider:</span> ${escapeHtml(billingProvider)}</div>
              <div><span style="color:var(--text-secondary);">Interval:</span> ${escapeHtml(billingInterval)}</div>
              <div><span style="color:var(--text-secondary);">Status:</span> ${escapeHtml(billingStatus)}</div>
              <div><span style="color:var(--text-secondary);">Until:</span> ${escapeHtml(billingEnd)}</div>
            </div>
          </div>
        </div>

      </div>

      <div id="tenantDetail-branding" style="display:${showBrandingSection ? 'block' : 'none'};">
        <div style="padding:14px; border:1px solid rgba(99,102,241,0.18); border-radius:12px; background:rgba(10,16,30,0.35);">
          <div style="display:flex; justify-content:space-between; align-items:center; gap:12px; margin-bottom:12px;">
            <h4 style="margin:0; color:#c9d6ff;">Branding</h4>
            <button class="btn-primary" id="tenantBrandSaveBtn" onclick="saveTenantBranding()" style="padding:8px 14px;">Save</button>
          </div>
          <div style="display:grid; gap:10px;">
            <label style="display:grid; gap:6px; color:#e0e7ff; font-size:0.9em;">
              <span>Bot display name</span>
              <input id="tenantBrandBotDisplayName" type="text" value="${escapeHtml(branding.bot_display_name || '')}" style="padding:10px 12px; background:rgba(30,41,59,0.8); border:1px solid rgba(99,102,241,0.22); border-radius:8px; color:#e0e7ff;">
            </label>
            <label style="display:grid; gap:6px; color:#e0e7ff; font-size:0.9em;">
              <span>Brand emoji</span>
              <input id="tenantBrandEmoji" type="text" value="${escapeHtml(branding.brand_emoji || '')}" style="padding:10px 12px; background:rgba(30,41,59,0.8); border:1px solid rgba(99,102,241,0.22); border-radius:8px; color:#e0e7ff;">
            </label>
            <label style="display:grid; gap:6px; color:#e0e7ff; font-size:0.9em;">
              <span>Brand color</span>
              <input id="tenantBrandColor" type="text" value="${escapeHtml(branding.brand_color || '')}" placeholder="#FFD700" style="padding:10px 12px; background:rgba(30,41,59,0.8); border:1px solid rgba(99,102,241,0.22); border-radius:8px; color:#e0e7ff;">
            </label>
            <label style="display:grid; gap:6px; color:#e0e7ff; font-size:0.9em;">
              <span>Logo URL</span>
              <input id="tenantBrandLogoUrl" type="text" value="${escapeHtml(branding.logo_url || '')}" style="padding:10px 12px; background:rgba(30,41,59,0.8); border:1px solid rgba(99,102,241,0.22); border-radius:8px; color:#e0e7ff;">
            </label>
            <div style="display:flex; gap:8px; align-items:center; flex-wrap:wrap;">
              <input id="tenantBrandLogoFile" type="file" accept="image/png,image/jpeg,image/webp" style="font-size:0.82em;color:#c7d2fe;">
              <button class="btn-secondary" id="tenantLogoUploadBtn" onclick="uploadTenantLogo()" style="padding:8px 12px;">Upload Logo</button>
            </div>
            <label style="display:grid; gap:6px; color:#e0e7ff; font-size:0.9em;">
              <span>Support URL</span>
              <input id="tenantBrandSupportUrl" type="text" value="${escapeHtml(branding.support_url || '')}" style="padding:10px 12px; background:rgba(30,41,59,0.8); border:1px solid rgba(99,102,241,0.22); border-radius:8px; color:#e0e7ff;">
            </label>
            <label style="display:grid; gap:6px; color:#e0e7ff; font-size:0.9em;">
              <span>Server avatar URL</span>
              <input id="tenantBrandServerAvatarUrl" type="text" value="${escapeHtml(branding.bot_server_avatar_url || '')}" style="padding:10px 12px; background:rgba(30,41,59,0.8); border:1px solid rgba(99,102,241,0.22); border-radius:8px; color:#e0e7ff;">
            </label>
            <label style="display:grid; gap:6px; color:#e0e7ff; font-size:0.9em;">
              <span>Server banner URL</span>
              <input id="tenantBrandServerBannerUrl" type="text" value="${escapeHtml(branding.bot_server_banner_url || '')}" style="padding:10px 12px; background:rgba(30,41,59,0.8); border:1px solid rgba(99,102,241,0.22); border-radius:8px; color:#e0e7ff;">
            </label>
            <label style="display:grid; gap:6px; color:#e0e7ff; font-size:0.9em;">
              <span>Server bio</span>
              <textarea id="tenantBrandServerBio" rows="3" style="padding:10px 12px; background:rgba(30,41,59,0.8); border:1px solid rgba(99,102,241,0.22); border-radius:8px; color:#e0e7ff; resize:vertical;">${escapeHtml(branding.bot_server_bio || '')}</textarea>
            </label>
          </div>
        </div>
      </div>

      <div id="tenantDetail-modules" style="display:${showModulesSection ? 'block' : 'none'};">
        <div style="padding:14px; border:1px solid rgba(99,102,241,0.18); border-radius:12px; background:rgba(10,16,30,0.35);">
          <h4 style="margin:0 0 12px; color:#c9d6ff;">Module Bundle</h4>
          <div style="display:grid; grid-template-columns:repeat(2,minmax(0,1fr)); gap:10px;">
            ${moduleToggles}
          </div>
        </div>
        <div style="margin-top:14px; padding:14px; border:1px solid rgba(99,102,241,0.18); border-radius:12px; background:rgba(10,16,30,0.35);">
          <div style="display:flex; justify-content:space-between; align-items:center; gap:12px; margin-bottom:12px; flex-wrap:wrap;">
            <h4 style="margin:0; color:#c9d6ff;">Module Limits</h4>
            <button class="btn-primary" id="tenantModuleLimitsSaveBtn" onclick="saveTenantModuleLimits()" style="padding:8px 14px;">Save Limits</button>
          </div>
          <div style="margin-bottom:10px; color:var(--text-secondary); font-size:0.82em;">Set tenant-specific overrides per module. Leave a value empty to use the plan default.</div>
          <div style="display:grid; gap:8px;">
            ${moduleLimitRows}
          </div>
        </div>
      </div>
    </div>
  `;
}

function getWorkspaceCapabilityMatrix() {
  return {
    overview: true,
    tenants: !!isSuperadmin,
    billing: !!isSuperadmin,
    security: !!isSuperadmin,
    integrations: !!isSuperadmin,
  };
}

function renderWorkspaceLockedState(label) {
  return `
    <div class="sa-v2-empty">
      <strong>${escapeHtml(label)} is locked</strong>
      <p>This workspace is available for Superadmins only.</p>
    </div>
  `;
}

function renderWorkspaceActivityItems(items = []) {
  if (!Array.isArray(items) || items.length === 0) {
    return '<div class="sa-v2-empty">No recent platform activity.</div>';
  }
  return items.map((item) => {
    const actor = formatDiscordIdentityLabel(item.actorId || 'system', item.actorDisplayName || null);
    return `
      <div class="sa-v2-activity-item">
        <div class="sa-v2-activity-main">${escapeHtml(item.action || 'unknown')}</div>
        <div class="sa-v2-activity-meta">${escapeHtml(actor)}  ${escapeHtml(item.guildId || 'n/a')}  ${escapeHtml(item.createdAt ? new Date(item.createdAt).toLocaleString() : 'Unknown')}</div>
      </div>
    `;
  }).join('');
}

function renderWorkspaceOverview(tenants = [], billingEntries = []) {
  const total = tenants.length;
  const active = tenants.filter((tenant) => String(tenant.status || '').toLowerCase() === 'active').length;
  const suspended = tenants.filter((tenant) => String(tenant.status || '').toLowerCase() === 'suspended').length;
  const paid = billingEntries.filter((entry) => ['active', 'trialing', 'paid', 'approved', 'success'].includes(String(entry.subscriptionStatus || '').toLowerCase())).length;
  return `
    <div class="sa-v2-grid">
      <article class="sa-v2-card"><h4>Tenants</h4><div class="sa-v2-kpi">${escapeHtml(String(total))}</div><p>Total onboarded servers</p></article>
      <article class="sa-v2-card"><h4>Active</h4><div class="sa-v2-kpi">${escapeHtml(String(active))}</div><p>Currently active tenants</p></article>
      <article class="sa-v2-card"><h4>Suspended</h4><div class="sa-v2-kpi">${escapeHtml(String(suspended))}</div><p>Needs follow-up</p></article>
      <article class="sa-v2-card"><h4>Paid Billing</h4><div class="sa-v2-kpi">${escapeHtml(String(paid))}</div><p>Verified paid states</p></article>
    </div>
  `;
}

function renderWorkspaceScopedError(message, retryLabel = 'Retry', retryAction = 'loadSuperadminView()') {
  return `
    <div class="sa-v2-empty" style="text-align:left;">
      <div style="color:#fca5a5; margin-bottom:10px;">${escapeHtml(message || 'This section failed to load.')}</div>
      <button class="btn-secondary" onclick="${retryAction}">${escapeHtml(retryLabel)}</button>
    </div>
  `;
}

function renderWorkspaceDataHealth(loadState = {}) {
  const checks = [
    { key: 'tenants', label: 'Tenants', failed: false },
    { key: 'activityFailed', label: 'Activity', failed: !!loadState.activityFailed },
    { key: 'billingFailed', label: 'Billing', failed: !!loadState.billingFailed },
    { key: 'adminsFailed', label: 'Superadmins', failed: !!loadState.adminsFailed },
    { key: 'globalFailed', label: 'Integrations', failed: !!loadState.globalFailed },
    { key: 'plansFailed', label: 'Plans', failed: !!loadState.plansFailed },
    { key: 'tenantDetailFailed', label: 'Tenant Detail', failed: !!loadState.tenantDetailFailed },
    { key: 'tenantAuditFailed', label: 'Tenant Audit', failed: !!loadState.tenantAuditFailed },
  ];
  return `
    <div style="display:flex; flex-wrap:wrap; gap:8px; margin:8px 0 12px;">
      ${checks.map((item) => `
        <button class="sa-v2-chip" style="border:${item.failed ? '1px solid rgba(239,68,68,0.45); color:#fecaca;' : '1px solid rgba(16,185,129,0.35); color:#bbf7d0;'} background:rgba(15,23,42,0.55);" ${item.failed ? 'onclick="loadSuperadminView()"' : 'disabled'}>
          ${item.failed ? 'Issue' : 'OK'}: ${escapeHtml(item.label)}
        </button>
      `).join('')}
    </div>
  `;
}

function renderWorkspaceTenantDetail(tenant, detail, auditLogs) {
  if (!tenant || !detail) {
    return '<div class="sa-v2-empty">Select a tenant from the left list to open details.</div>';
  }

  const currentTab = String(superadminWorkspaceTenantTab || 'plan');
  const tabBtn = (tab, label) => `<button class="sa-v2-pill ${currentTab === tab ? 'active' : ''}" data-sa-tenant-tab="${escapeHtml(tab)}" onclick="onSuperadminTenantTabClick(event)">${label}</button>`;
  if (currentTab === 'audit') {
    return `
      <div class="sa-v2-detail-header">
        <h4>${escapeHtml(tenant.guildName || tenant.guildId)}</h4>
        <div>${getTenantStatusBadge(tenant.status)}</div>
      </div>
      <div class="sa-v2-pill-row">${tabBtn('plan', 'Plan & Billing')}${tabBtn('modules', 'Modules')}${tabBtn('branding', 'Branding')}${tabBtn('audit', 'Audit')}</div>
      <div class="sa-v2-scroll">${renderTenantAuditLog(auditLogs || [])}</div>
    `;
  }

  if (currentTab === 'modules') {
    return `
      <div class="sa-v2-detail-header">
        <h4>${escapeHtml(tenant.guildName || tenant.guildId)}</h4>
        <div>${getTenantStatusBadge(tenant.status)}</div>
      </div>
      <div class="sa-v2-pill-row">${tabBtn('plan', 'Plan & Billing')}${tabBtn('modules', 'Modules')}${tabBtn('branding', 'Branding')}${tabBtn('audit', 'Audit')}</div>
      <div>${renderTenantDetailPanel(detail, null, currentTab)}</div>
    `;
  }

  if (currentTab === 'branding') {
    return `
      <div class="sa-v2-detail-header">
        <h4>${escapeHtml(tenant.guildName || tenant.guildId)}</h4>
        <div>${getTenantStatusBadge(tenant.status)}</div>
      </div>
      <div class="sa-v2-pill-row">${tabBtn('plan', 'Plan & Billing')}${tabBtn('modules', 'Modules')}${tabBtn('branding', 'Branding')}${tabBtn('audit', 'Audit')}</div>
      <div>${renderTenantDetailPanel(detail, null, currentTab)}</div>
    `;
  }

  return `
    <div class="sa-v2-detail-header">
      <h4>${escapeHtml(tenant.guildName || tenant.guildId)}</h4>
      <div>${getTenantStatusBadge(tenant.status)}</div>
    </div>
    <div class="sa-v2-pill-row">${tabBtn('plan', 'Plan & Billing')}${tabBtn('modules', 'Modules')}${tabBtn('branding', 'Branding')}${tabBtn('audit', 'Audit')}</div>
    <div>${renderTenantDetailPanel(detail, null, currentTab)}</div>
  `;
}

function setSuperadminWorkspaceTab(tab) {
  superadminWorkspaceV2 = String(tab || 'overview');
  superadminWorkspaceFocus = '';
  const url = new URL(window.location);
  url.searchParams.set('saWs', superadminWorkspaceV2);
  url.searchParams.delete('saFocus');
  window.history.replaceState({}, '', url);
  loadSuperadminView();
}

function setSuperadminWorkspaceTenantTab(tab) {
  superadminWorkspaceTenantTab = String(tab || 'plan');
  const url = new URL(window.location);
  url.searchParams.set('saTenantTab', superadminWorkspaceTenantTab);
  window.history.replaceState({}, '', url);
  loadSuperadminView();
}

function setSuperadminWorkspaceTenantSearch(value) {
  superadminWorkspaceSearch = String(value || '');
}

function setSuperadminWorkspaceBillingSearch(value) {
  superadminWorkspaceBillingSearch = String(value || '');
}

function setSuperadminWorkspaceBillingStatus(value) {
  superadminWorkspaceBillingStatus = String(value || 'all');
}

function onSuperadminTenantTabClick(event) {
  const tab = event?.currentTarget?.dataset?.saTenantTab;
  if (!tab) return;
  setSuperadminWorkspaceTenantTab(tab);
}

function onSuperadminWorkspaceTabClick(event) {
  const tab = event?.currentTarget?.dataset?.saWorkspaceTab;
  if (!tab) return;
  setSuperadminWorkspaceTab(tab);
}

function setSuperadminWorkspaceBillingSortBy(value) {
  superadminWorkspaceBillingSortBy = String(value || 'updatedAt');
}

function setSuperadminWorkspaceBillingSortDir(value) {
  superadminWorkspaceBillingSortDir = String(value || 'desc').toLowerCase() === 'asc' ? 'asc' : 'desc';
}

function resetSuperadminWorkspaceTenantFilters() {
  superadminWorkspaceSearch = '';
  superadminTenantPage = 1;
  loadSuperadminView();
}

function resetSuperadminWorkspaceBillingFilters() {
  superadminWorkspaceBillingSearch = '';
  superadminWorkspaceBillingStatus = 'all';
  superadminWorkspaceBillingPage = 1;
  superadminWorkspaceBillingSortBy = 'updatedAt';
  superadminWorkspaceBillingSortDir = 'desc';
  loadSuperadminView();
}

function setSuperadminWorkspaceBillingSort(sortBy) {
  const normalized = String(sortBy || 'updatedAt').trim();
  if (superadminWorkspaceBillingSortBy === normalized) {
    superadminWorkspaceBillingSortDir = superadminWorkspaceBillingSortDir === 'asc' ? 'desc' : 'asc';
  } else {
    superadminWorkspaceBillingSortBy = normalized;
    superadminWorkspaceBillingSortDir = 'desc';
  }
  superadminWorkspaceBillingPage = 1;
  loadSuperadminView();
}

function superadminWorkspaceBillingPrevPage() {
  if (superadminWorkspaceBillingPage <= 1) return;
  superadminWorkspaceBillingPage -= 1;
  loadSuperadminView();
}

function superadminWorkspaceBillingNextPage(totalPages = 1) {
  const maxPages = Math.max(Number(totalPages || 1), 1);
  if (superadminWorkspaceBillingPage >= maxPages) return;
  superadminWorkspaceBillingPage += 1;
  loadSuperadminView();
}

function superadminWorkspaceBillingOverride(guildId, currentStatus = '', currentInterval = '') {
  const normalizedGuildId = String(guildId || '').trim();
  if (!normalizedGuildId) return;
  const statusInput = prompt('Override subscription status (e.g. approved, active, suspended, rejected):', String(currentStatus || '').trim() || 'approved');
  if (statusInput === null) return;
  const normalizedStatus = String(statusInput || '').trim().toLowerCase();
  if (!normalizedStatus) {
    showError('Subscription status is required for override.');
    return;
  }
  const intervalInput = prompt('Billing interval (monthly/yearly, optional):', String(currentInterval || '').trim());
  if (intervalInput === null) return;
  const normalizedInterval = String(intervalInput || '').trim().toLowerCase();
  superadminBillingAction(normalizedGuildId, 'override', {
    subscriptionStatus: normalizedStatus,
    billingInterval: normalizedInterval || null,
  });
}

function superadminRejectBillingReceipt(guildId, receiptId = null) {
  const normalizedGuildId = String(guildId || '').trim();
  if (!normalizedGuildId) return;
  const noteInput = prompt('Optional rejection note for this payment receipt:', '');
  if (noteInput === null) return;
  superadminBillingAction(normalizedGuildId, 'reject', {
    receiptId: Number(receiptId || 0) || null,
    note: String(noteInput || '').trim() || null,
  });
}

function openSuperadminBillingReceiptReview(guildId) {
  const normalizedGuildId = String(guildId || '').trim();
  if (!normalizedGuildId) return;
  const entry = (Array.isArray(superadminWorkspaceBillingEntriesCache) ? superadminWorkspaceBillingEntriesCache : [])
    .find(item => String(item?.guildId || '') === normalizedGuildId);
  if (!entry) {
    showError('Could not find billing record in current workspace.');
    return;
  }
  const receipt = entry.latestReceipt || null;
  showConfirmModal(`Billing Review: ${entry.guildName || entry.guildId}`, '', null, 'Approve');
  const body = document.getElementById('confirmMessage');
  if (body) body.innerHTML = '<div style="color:var(--text-secondary);">Loading receipt history...</div>';
  confirmCallback = async () => false;
  const btn = document.getElementById('confirmButton');
  if (btn) btn.textContent = 'Approve';

  const renderReceiptModal = async (statusFilter = 'all') => {
    try {
      const qs = new URLSearchParams();
      qs.set('limit', '25');
      if (statusFilter && statusFilter !== 'all') qs.set('status', statusFilter);
      const res = await fetch(`/api/superadmin/workspace/billing/${encodeURIComponent(normalizedGuildId)}/receipts?${qs.toString()}`, {
        credentials: 'include',
      });
      const json = await res.json().catch(() => ({}));
      const receipts = (res.ok && json?.success !== false && Array.isArray(json?.receipts)) ? json.receipts : [];
      const actions = (res.ok && json?.success !== false && Array.isArray(json?.actions)) ? json.actions : [];
      const receiptRows = receipts.length
        ? receipts.map((item) => `
          <div style="padding:10px;border:1px solid rgba(99,102,241,0.18);border-radius:8px;background:rgba(15,23,42,0.4);display:grid;gap:6px;">
            <div style="display:flex;justify-content:space-between;gap:8px;flex-wrap:wrap;">
              <div><strong>#${escapeHtml(String(item.id || ''))}</strong>  ${escapeHtml(item.status || 'pending')}</div>
              <div style="font-size:0.78em;color:var(--text-secondary);">${escapeHtml(item.createdAt ? new Date(item.createdAt).toLocaleString() : '')}</div>
            </div>
            <div style="font-size:0.84em;"><strong>TX:</strong> ${escapeHtml(item.txSignature || 'n/a')}</div>
            <div style="font-size:0.84em;"><strong>Token/Amount:</strong> ${escapeHtml(item.tokenSymbol || 'n/a')} ${item.amount !== null && item.amount !== undefined ? escapeHtml(String(item.amount)) : 'n/a'}</div>
            <div style="font-size:0.84em;"><strong>Plan/Interval:</strong> ${escapeHtml(item.planKey || 'n/a')} / ${escapeHtml(item.billingInterval || 'n/a')}</div>
            <div style="display:flex;gap:6px;flex-wrap:wrap;">
              <button class="btn-secondary" style="padding:4px 8px;" onclick="superadminVerifyBillingReceiptOnChain('${escapeJsString(normalizedGuildId)}', ${Number(item.id || 0)})">Verify On-Chain</button>
              <button class="btn-secondary" style="padding:4px 8px;" onclick="superadminBillingApproveReceipt('${escapeJsString(normalizedGuildId)}', ${Number(item.id || 0)}, '${escapeJsString(String(item.planKey || ''))}', '${escapeJsString(String(item.billingInterval || ''))}')">Approve Receipt</button>
              <button class="btn-secondary" style="padding:4px 8px;" onclick="superadminRejectBillingReceipt('${escapeJsString(normalizedGuildId)}', ${Number(item.id || 0)})">Reject Receipt</button>
            </div>
          </div>
        `).join('')
        : '<div style="color:var(--text-secondary);">No receipts found for this tenant.</div>';
      const actionRows = actions.length
        ? actions.map((row) => `
          <div style="padding:8px 10px;border:1px solid rgba(99,102,241,0.16);border-radius:8px;background:rgba(15,23,42,0.35);">
            <div style="font-size:0.8em;color:#c9d6ff;"><strong>${escapeHtml(row.action || 'billing_action')}</strong>  ${escapeHtml(row.createdAt ? new Date(row.createdAt).toLocaleString() : '')}</div>
            <div style="font-size:0.78em;color:var(--text-secondary);">Actor: ${escapeHtml(row.actorId || 'unknown')}</div>
            ${row.note ? `<div style="font-size:0.8em;color:#e0e7ff;margin-top:4px;"><strong>Note:</strong> ${escapeHtml(row.note)}</div>` : ''}
          </div>
        `).join('')
        : '<div style="color:var(--text-secondary);">No billing action history yet.</div>';

      if (body) {
        body.innerHTML = `
          <div style="display:grid;gap:10px;">
            <div style="font-size:0.9em;color:var(--text-secondary);">Review and process payment receipts for this tenant.</div>
            <div style="padding:10px;border:1px solid rgba(99,102,241,0.18);border-radius:8px;background:rgba(15,23,42,0.4);">
              <div><strong>Tenant:</strong> ${escapeHtml(entry.guildName || entry.guildId)}</div>
              <div><strong>Status:</strong> ${escapeHtml(entry.subscriptionStatus || 'unknown')}</div>
              <div><strong>Provider:</strong> ${escapeHtml(entry.provider || 'n/a')}</div>
              <div><strong>Queue:</strong> ${escapeHtml(entry.verificationStatus || 'pending')}</div>
            </div>
            <div style="display:flex;align-items:center;justify-content:space-between;gap:8px;flex-wrap:wrap;">
              <div style="font-size:0.82em;color:var(--text-secondary);">Receipts</div>
              <select id="superadminReceiptStatusFilter" style="padding:6px 8px;">
                <option value="all"${statusFilter === 'all' ? ' selected' : ''}>All</option>
                <option value="pending"${statusFilter === 'pending' ? ' selected' : ''}>Pending</option>
                <option value="approved"${statusFilter === 'approved' ? ' selected' : ''}>Approved</option>
                <option value="rejected"${statusFilter === 'rejected' ? ' selected' : ''}>Rejected</option>
              </select>
            </div>
            <div style="display:grid;gap:8px;max-height:280px;overflow:auto;">${receiptRows}</div>
            <div style="font-size:0.82em;color:var(--text-secondary);">Operator Notes History</div>
            <div style="display:grid;gap:8px;max-height:180px;overflow:auto;">${actionRows}</div>
          </div>
        `;
        const filterEl = document.getElementById('superadminReceiptStatusFilter');
        if (filterEl) {
          filterEl.onchange = () => {
            const nextStatus = String(filterEl.value || 'all');
            renderReceiptModal(nextStatus).catch(() => {});
          };
        }
      }
    } catch (_error) {
      if (body) body.innerHTML = '<div style="color:#fca5a5;">Failed to load receipt history.</div>';
    }
  };

  renderReceiptModal('all').catch(() => {});
}

function superadminBillingApproveReceipt(guildId, receiptId, planKey = '', billingInterval = '') {
  const normalizedGuildId = String(guildId || '').trim();
  const normalizedReceiptId = Number(receiptId || 0);
  if (!normalizedGuildId || !Number.isFinite(normalizedReceiptId) || normalizedReceiptId <= 0) return;
  closeConfirmModal();
  superadminBillingAction(normalizedGuildId, 'approve', {
    receiptId: normalizedReceiptId,
    planKey: String(planKey || '').trim().toLowerCase() || null,
    billingInterval: String(billingInterval || '').trim().toLowerCase() || null,
  });
}

async function superadminVerifyBillingReceiptOnChain(guildId, receiptId) {
  const normalizedGuildId = String(guildId || '').trim();
  const normalizedReceiptId = Number(receiptId || 0);
  if (!normalizedGuildId || !Number.isFinite(normalizedReceiptId) || normalizedReceiptId <= 0) return;
  try {
    const res = await fetch(`/api/superadmin/workspace/billing/${encodeURIComponent(normalizedGuildId)}/verify-receipt`, {
      method: 'POST',
      credentials: 'include',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ receiptId: normalizedReceiptId }),
    });
    const json = await res.json().catch(() => ({}));
    if (!res.ok || json?.success === false) {
      throw new Error(json?.message || json?.error?.message || `HTTP ${res.status}`);
    }
    const verified = !!json?.verified;
    const reason = String(json?.reason || (verified ? 'Verified' : 'Not verified'));
    if (verified) {
      showSuccess(`Receipt #${normalizedReceiptId} verified on-chain. ${reason}`);
    } else {
      showInfo(`Receipt #${normalizedReceiptId} not verified: ${reason}`);
    }
  } catch (error) {
    showError(`On-chain verification failed: ${error?.message || 'unknown error'}`);
  }
}

function superadminBillingAction(guildId, action, extraPayload = null) {
  const normalizedGuildId = String(guildId || '').trim();
  const normalizedAction = String(action || '').trim().toLowerCase();
  if (!normalizedGuildId || !normalizedAction) return;

  const labels = {
    approve: 'Approve billing',
    reject: 'Reject billing',
    override: 'Override billing',
  };
  const descriptions = {
    approve: 'This marks the billing record as approved and sets tenant status to active.',
    reject: 'This marks the billing record as rejected and sets tenant status to suspended.',
    override: 'This applies a manual billing override for this tenant.',
  };

  const payload = {
    action: normalizedAction,
    ...(extraPayload && typeof extraPayload === 'object' ? extraPayload : {}),
  };

  showConfirmModal(
    `${labels[normalizedAction] || 'Apply billing action'}?`,
    descriptions[normalizedAction] || 'Apply this billing action?',
    async () => {
      try {
        const response = await fetch(`/api/superadmin/workspace/billing/${encodeURIComponent(normalizedGuildId)}/action`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          credentials: 'include',
          body: JSON.stringify(payload),
        });
        const data = await response.json().catch(() => ({}));
        if (!response.ok || data?.success === false) {
          reportAdminUiSaveFailure('superadminBillingAction', new Error(data?.message || `HTTP ${response.status}`), { billingAction: normalizedAction, guildId: normalizedGuildId });
          showError(data?.message || `Failed to ${normalizedAction} billing`);
          return;
        }
        showSuccess(`Billing action applied: ${normalizedAction}`);
        loadSuperadminView();
      } catch (error) {
        reportAdminUiSaveFailure('superadminBillingAction', error, { billingAction: normalizedAction, guildId: normalizedGuildId });
        showError(formatAdminWorkspaceError(`Failed to ${normalizedAction} billing`, error));
      }
    },
    labels[normalizedAction] || 'Confirm'
  );
}

function setSuperadminWorkspaceFocus(focus = '') {
  superadminWorkspaceFocus = String(focus || '').trim();
  const url = new URL(window.location);
  if (superadminWorkspaceFocus) url.searchParams.set('saFocus', superadminWorkspaceFocus);
  else url.searchParams.delete('saFocus');
  window.history.replaceState({}, '', url);
  loadSuperadminView();
}

async function loadSuperadminWorkspaceHubV2() {
  const content = document.getElementById('adminSuperadminContent');
  if (!content) return;
  const startMs = Date.now();

  const capabilities = getWorkspaceCapabilityMatrix();
  const url = new URL(window.location);
  const qsWs = String(url.searchParams.get('saWs') || '').trim();
  const qsTenantTab = String(url.searchParams.get('saTenantTab') || '').trim();
  const qsTenantId = normalizeGuildId(String(url.searchParams.get('saTenantId') || '').trim());
  const qsFocus = String(url.searchParams.get('saFocus') || '').trim();
  if (qsWs && SUPERADMIN_WORKSPACES.has(qsWs)) superadminWorkspaceV2 = qsWs;
  if (!SUPERADMIN_WORKSPACES.has(String(superadminWorkspaceV2 || ''))) superadminWorkspaceV2 = 'overview';
  if (qsTenantTab) superadminWorkspaceTenantTab = qsTenantTab;
  if (qsTenantId) selectedTenantGuildId = qsTenantId;
  superadminWorkspaceFocus = qsFocus;
  const workspace = String(superadminWorkspaceV2 || 'overview');

  content.innerHTML = '<div style="padding:20px;text-align:center;"><div class="spinner"></div><p style="margin-top:8px;">Loading admin workspace...</p></div>';

  try {
    const workspaceWarnings = [];
    const workspaceLoadState = {
      activityFailed: false,
      billingFailed: false,
      adminsFailed: false,
      globalFailed: false,
      plansFailed: false,
      tenantDetailFailed: false,
      tenantAuditFailed: false,
    };
    const headers = buildTenantRequestHeaders();
    const tenantsQs = new URLSearchParams();
    if (superadminWorkspaceSearch.trim()) tenantsQs.set('q', superadminWorkspaceSearch.trim());
    tenantsQs.set('page', String(superadminTenantPage || 1));
    tenantsQs.set('pageSize', String(superadminTenantPageSize || 25));

    const billingQs = new URLSearchParams();
    if (superadminWorkspaceBillingSearch.trim()) billingQs.set('q', superadminWorkspaceBillingSearch.trim());
    if (superadminWorkspaceBillingStatus && superadminWorkspaceBillingStatus !== 'all') billingQs.set('status', superadminWorkspaceBillingStatus);
    billingQs.set('page', String(superadminWorkspaceBillingPage || 1));
    billingQs.set('pageSize', String(superadminWorkspaceBillingPageSize || 25));
    billingQs.set('sortBy', String(superadminWorkspaceBillingSortBy || 'updatedAt'));
    billingQs.set('sortDir', String(superadminWorkspaceBillingSortDir || 'desc'));

    const [tenantsRes, activityRes, billingRes, adminsRes, globalSettingsRes, plansRes] = await Promise.all([
      fetch(`/api/superadmin/workspace/tenants?${tenantsQs.toString()}`, { credentials: 'include', headers }),
      fetch('/api/superadmin/workspace/activity?limit=25', { credentials: 'include' }),
      fetch(`/api/superadmin/workspace/billing?${billingQs.toString()}`, { credentials: 'include' }),
      fetch('/api/superadmin/admins', { credentials: 'include' }),
      fetch('/api/superadmin/global-settings', { credentials: 'include' }),
      fetch('/api/superadmin/workspace/plans', { credentials: 'include' }),
    ]);

    const tenantsJson = await tenantsRes.json().catch(() => ({}));
    const activityJson = await activityRes.json().catch(() => ({}));
    const billingJson = await billingRes.json().catch(() => ({}));
    const adminsJson = await adminsRes.json().catch(() => ({}));
    const globalSettingsJson = await globalSettingsRes.json().catch(() => ({}));
    const plansJson = await plansRes.json().catch(() => ({}));
    if (!tenantsRes.ok || tenantsJson?.success === false) {
      throw new Error(tenantsJson?.message || 'Failed to load tenant workspace');
    }
    if (!activityRes.ok || activityJson?.success === false) {
      workspaceLoadState.activityFailed = true;
      workspaceWarnings.push('Recent activity feed is temporarily unavailable.');
    }
    if (!billingRes.ok || billingJson?.success === false) {
      workspaceLoadState.billingFailed = true;
      workspaceWarnings.push('Billing ledger data is temporarily unavailable.');
    }
    if (!adminsRes.ok || adminsJson?.success === false) {
      workspaceLoadState.adminsFailed = true;
      workspaceWarnings.push('Superadmin access list is temporarily unavailable.');
    }
    if (!globalSettingsRes.ok || globalSettingsJson?.success === false) {
      workspaceLoadState.globalFailed = true;
      workspaceWarnings.push('Global integration settings are temporarily unavailable.');
    }
    if (!plansRes.ok || plansJson?.success === false) {
      workspaceLoadState.plansFailed = true;
    }

    const tenants = Array.isArray(tenantsJson?.tenants) ? tenantsJson.tenants : [];
    const billingEntries = (billingRes.ok && billingJson?.success !== false && Array.isArray(billingJson?.entries)) ? billingJson.entries : [];
    superadminWorkspaceBillingEntriesCache = Array.isArray(billingEntries) ? billingEntries : [];
    const billingPagination = billingJson?.pagination || { page: 1, pageSize: superadminWorkspaceBillingPageSize || 25, total: billingEntries.length, totalPages: 1 };
    const billingSorting = billingJson?.sorting || { sortBy: superadminWorkspaceBillingSortBy || 'updatedAt', sortDir: superadminWorkspaceBillingSortDir || 'desc' };
    superadminWorkspaceBillingPage = Number(billingPagination.page || 1);
    superadminWorkspaceBillingPageSize = Number(billingPagination.pageSize || superadminWorkspaceBillingPageSize || 25);
    superadminWorkspaceBillingSortBy = String(billingSorting.sortBy || superadminWorkspaceBillingSortBy || 'updatedAt');
    superadminWorkspaceBillingSortDir = String(billingSorting.sortDir || superadminWorkspaceBillingSortDir || 'desc');
    const activityItems = (activityRes.ok && activityJson?.success !== false && Array.isArray(activityJson?.items)) ? activityJson.items : [];
    const superadmins = (adminsRes.ok && adminsJson?.success !== false && Array.isArray(adminsJson?.superadmins)) ? adminsJson.superadmins : [];
    const globalSettings = globalSettingsJson?.settings || {};
    superadminWorkspacePlansCache = (plansRes.ok && plansJson?.success !== false && Array.isArray(plansJson?.plans))
      ? plansJson.plans
      : [];
    superadminWorkspaceActivityCache = activityItems;

    if (!selectedTenantGuildId && tenants.length > 0) {
      selectedTenantGuildId = tenants[0].guildId;
    } else if (selectedTenantGuildId && !tenants.some((tenant) => tenant.guildId === selectedTenantGuildId)) {
      // Recover from stale URL/query selection when a filtered tenant is no longer visible.
      selectedTenantGuildId = tenants[0]?.guildId || null;
      const nextUrl = new URL(window.location);
      if (selectedTenantGuildId) nextUrl.searchParams.set('saTenantId', selectedTenantGuildId);
      else nextUrl.searchParams.delete('saTenantId');
      window.history.replaceState({}, '', nextUrl);
    }

    const selectedTenantSummary = tenants.find((tenant) => tenant.guildId === selectedTenantGuildId) || null;
    if (selectedTenantSummary && capabilities.tenants) {
      const [detailRes, auditRes] = await Promise.all([
        fetch(`/api/superadmin/tenants/${encodeURIComponent(selectedTenantSummary.guildId)}`, { credentials: 'include' }),
        fetch(`/api/superadmin/tenants/${encodeURIComponent(selectedTenantSummary.guildId)}/audit?limit=25`, { credentials: 'include' }),
      ]);
      const detailJson = await detailRes.json().catch(() => ({}));
      const auditJson = await auditRes.json().catch(() => ({}));
      if (!detailRes.ok || detailJson?.success === false) {
        workspaceLoadState.tenantDetailFailed = true;
        workspaceWarnings.push(`Tenant detail failed to load for ${selectedTenantSummary.guildName || selectedTenantSummary.guildId}.`);
      }
      if (!auditRes.ok || auditJson?.success === false) {
        workspaceLoadState.tenantAuditFailed = true;
        workspaceWarnings.push(`Tenant audit failed to load for ${selectedTenantSummary.guildName || selectedTenantSummary.guildId}.`);
      }
      selectedTenantDetailCache = detailJson?.success ? detailJson.tenant : null;
      selectedTenantAuditCache = auditJson?.success ? (auditJson.auditLogs || []) : [];
    }

    const tabButton = (key, label) => {
      const enabled = !!capabilities[key];
      return `<button class="sa-v2-tab ${workspace === key ? 'active' : ''}" data-sa-workspace-tab="${escapeHtml(key)}" ${enabled ? 'onclick="onSuperadminWorkspaceTabClick(event)"' : ''} ${enabled ? '' : 'disabled'}>${label}</button>`;
    };

    let workspaceBody = '';
    if (workspace === 'overview') {
      workspaceBody = renderWorkspaceOverview(tenants, billingEntries);
    } else if (workspace === 'tenants') {
      workspaceBody = capabilities.tenants
        ? `
          <div class="sa-v2-split">
            <div class="sa-v2-panel">
              <div class="sa-v2-toolbar">
                <input type="text" value="${escapeHtml(superadminWorkspaceSearch)}" placeholder="Search tenant by name, id, or plan..." oninput="setSuperadminWorkspaceTenantSearch(this.value)">
                <button class="btn-secondary" onclick="loadSuperadminView()">Search</button>
                <button class="btn-secondary" onclick="resetSuperadminWorkspaceTenantFilters()">Clear</button>
              </div>
              <div class="sa-v2-list">
                ${(tenants.length ? tenants.map((tenant) => renderTenantRow(tenant)).join('') : '<div class="sa-v2-empty">No tenants found for this filter.</div>')}
              </div>
            </div>
            <div class="sa-v2-panel">
              ${
                (workspaceLoadState.tenantDetailFailed || workspaceLoadState.tenantAuditFailed)
                  ? renderWorkspaceScopedError('Tenant detail is partially unavailable. You can retry this panel.', 'Retry Tenant Detail', 'loadSuperadminView()')
                  : renderWorkspaceTenantDetail(selectedTenantSummary, selectedTenantDetailCache, selectedTenantAuditCache)
              }
            </div>
          </div>
        `
        : renderWorkspaceLockedState('Tenants workspace');
    } else if (workspace === 'billing') {
      workspaceBody = capabilities.billing
        ? `
          <div class="sa-v2-panel">
            <div class="sa-v2-toolbar">
              <input type="text" value="${escapeHtml(superadminWorkspaceBillingSearch)}" placeholder="Search by guild, status, provider..." oninput="setSuperadminWorkspaceBillingSearch(this.value)">
              <select onchange="setSuperadminWorkspaceBillingStatus(this.value)">
                <option value="all"${superadminWorkspaceBillingStatus === 'all' ? ' selected' : ''}>All statuses</option>
                <option value="active"${superadminWorkspaceBillingStatus === 'active' ? ' selected' : ''}>Active</option>
                <option value="suspended"${superadminWorkspaceBillingStatus === 'suspended' ? ' selected' : ''}>Suspended</option>
                <option value="paid"${superadminWorkspaceBillingStatus === 'paid' ? ' selected' : ''}>Paid</option>
                <option value="trialing"${superadminWorkspaceBillingStatus === 'trialing' ? ' selected' : ''}>Trialing</option>
              </select>
              <select onchange="setSuperadminWorkspaceBillingSortBy(this.value)">
                <option value="updatedAt"${superadminWorkspaceBillingSortBy === 'updatedAt' ? ' selected' : ''}>Sort: Updated</option>
                <option value="guildName"${superadminWorkspaceBillingSortBy === 'guildName' ? ' selected' : ''}>Sort: Tenant</option>
                <option value="subscriptionStatus"${superadminWorkspaceBillingSortBy === 'subscriptionStatus' ? ' selected' : ''}>Sort: Status</option>
                <option value="provider"${superadminWorkspaceBillingSortBy === 'provider' ? ' selected' : ''}>Sort: Provider</option>
                <option value="billingInterval"${superadminWorkspaceBillingSortBy === 'billingInterval' ? ' selected' : ''}>Sort: Interval</option>
              </select>
              <select onchange="setSuperadminWorkspaceBillingSortDir(this.value)">
                <option value="desc"${superadminWorkspaceBillingSortDir === 'desc' ? ' selected' : ''}>Desc</option>
                <option value="asc"${superadminWorkspaceBillingSortDir === 'asc' ? ' selected' : ''}>Asc</option>
              </select>
              <button class="btn-secondary" onclick="loadSuperadminView()">Apply</button>
              <button class="btn-secondary" onclick="resetSuperadminWorkspaceBillingFilters()">Clear</button>
            </div>
            ${
              workspaceLoadState.billingFailed
                ? renderWorkspaceScopedError('Billing ledger failed to load for this workspace view.', 'Retry Billing', 'loadSuperadminView()')
                : `
            <div class="sa-v2-table-wrap">
              <table class="sa-v2-table">
                <thead><tr><th>Tenant</th><th>Status</th><th>Provider</th><th>Interval</th><th>Last Payment</th><th>Period End</th><th>Queue</th><th>Actions</th></tr></thead>
                <tbody>
                  ${billingEntries.length ? billingEntries.map((entry) => `
                    <tr>
                      <td><strong>${escapeHtml(entry.guildName || entry.guildId)}</strong><div class="muted" style="font-size:0.76em;">${escapeHtml(entry.guildId || '')}</div></td>
                      <td>${escapeHtml(entry.subscriptionStatus || 'unknown')}</td>
                      <td>${escapeHtml(entry.provider || 'n/a')}</td>
                      <td>${escapeHtml(entry.billingInterval || 'n/a')}</td>
                      <td>${escapeHtml(entry.lastPaymentAt ? new Date(entry.lastPaymentAt).toLocaleString() : '')}</td>
                      <td>${escapeHtml(entry.currentPeriodEnd ? new Date(entry.currentPeriodEnd).toLocaleString() : '')}</td>
                      <td>
                        ${escapeHtml(entry.verificationStatus || 'pending')}
                        ${Number(entry.pendingReceiptsCount || 0) > 0 ? `<div class="muted" style="font-size:0.74em;margin-top:3px;">${escapeHtml(String(entry.pendingReceiptsCount))} receipt(s) pending</div>` : ''}
                        ${entry.latestReceipt?.txSignature ? `<div class="muted" style="font-size:0.72em;margin-top:3px;">TX: ${escapeHtml(String(entry.latestReceipt.txSignature).slice(0, 14))}...</div>` : ''}
                      </td>
                      <td>
                        <div style="display:flex; gap:6px; flex-wrap:wrap;">
                          <button class="btn-secondary" style="padding:4px 8px;" onclick="openSuperadminBillingReceiptReview('${escapeJsString(entry.guildId || '')}')">Review</button>
                          <button class="btn-secondary" style="padding:4px 8px;" onclick="superadminBillingAction('${escapeJsString(entry.guildId || '')}', 'approve', ${entry.latestReceipt?.id ? `{ receiptId: ${Number(entry.latestReceipt.id)}, planKey: '${escapeJsString(entry.latestReceipt.planKey || '')}', billingInterval: '${escapeJsString(entry.latestReceipt.billingInterval || '')}' }` : 'null'})">Approve</button>
                          <button class="btn-secondary" style="padding:4px 8px;" onclick="superadminRejectBillingReceipt('${escapeJsString(entry.guildId || '')}', ${entry.latestReceipt?.id ? Number(entry.latestReceipt.id) : 'null'})">Reject</button>
                          <button class="btn-secondary" style="padding:4px 8px;" onclick="superadminWorkspaceBillingOverride('${escapeJsString(entry.guildId || '')}', '${escapeJsString(entry.subscriptionStatus || '')}', '${escapeJsString(entry.billingInterval || '')}')">Override</button>
                        </div>
                      </td>
                    </tr>
                  `).join('') : '<tr><td colspan="8">No billing records found for the current filters.</td></tr>'}
                </tbody>
              </table>
            </div>
            <div style="display:flex; justify-content:space-between; align-items:center; gap:10px; margin-top:10px; flex-wrap:wrap;">
              <div class="sa-v2-inline-note" style="margin:0;">Page ${escapeHtml(String(superadminWorkspaceBillingPage || 1))} of ${escapeHtml(String(Math.max(Number(billingPagination.totalPages || 1), 1)))}  ${escapeHtml(String(billingPagination.total || 0))} records</div>
              <div style="display:flex; gap:8px;">
                <button class="btn-secondary" onclick="superadminWorkspaceBillingPrevPage()" ${Number(superadminWorkspaceBillingPage || 1) <= 1 ? 'disabled' : ''}>Prev</button>
                <button class="btn-secondary" onclick="superadminWorkspaceBillingNextPage(${Number(billingPagination.totalPages || 1)})" ${Number(superadminWorkspaceBillingPage || 1) >= Number(billingPagination.totalPages || 1) ? 'disabled' : ''}>Next</button>
              </div>
            </div>
            <div class="sa-v2-inline-note">Use Approve/Reject/Override to manage billing verification lifecycle directly from this queue.</div>
            `
            }
          </div>
        `
        : renderWorkspaceLockedState('Billing workspace');
    } else if (workspace === 'security') {
      if (!capabilities.security) {
        workspaceBody = renderWorkspaceLockedState('Security & Access');
      } else if (superadminWorkspaceFocus === 'superadmins') {
        const rows = superadmins.length
          ? superadmins.map((entry) => {
              const removable = entry.source !== 'env';
              const sourceLabel = entry.source === 'env' ? 'Root env' : 'DB';
              return `
                <div style="display:flex; justify-content:space-between; gap:12px; align-items:center; padding:10px 12px; border-bottom:1px solid rgba(99,102,241,0.15);">
                  <div style="min-width:0;">
                    <div style="color:#e0e7ff; font-weight:600; font-family:monospace; word-break:break-all;">${escapeHtml(entry.userId)}</div>
                    <div style="color:var(--text-secondary); font-size:0.82em; margin-top:4px;">${escapeHtml(sourceLabel)}</div>
                  </div>
                  <button class="btn-secondary" ${removable ? `onclick="removeSuperadmin('${escapeJsString(entry.userId)}')"` : 'disabled'}>${removable ? 'Remove' : 'Protected'}</button>
                </div>
              `;
            }).join('')
          : '<div class="sa-v2-empty">No superadmins configured.</div>';
        workspaceBody = `
          <div class="sa-v2-panel">
            <div class="sa-v2-toolbar" style="grid-template-columns:minmax(0,1fr) auto auto;">
              <input id="adminSuperadminUserIdInput" type="text" placeholder="Discord ID" onkeydown="if(event.key==='Enter'){event.preventDefault(); addSuperadminFromInput();}">
              <button id="adminSuperadminAddBtn" class="btn-primary" onclick="addSuperadminFromInput()">Add Superadmin</button>
              <button class="btn-secondary" onclick="setSuperadminWorkspaceFocus('')">Back</button>
            </div>
            <div class="sa-v2-list">${rows}</div>
          </div>
        `;
      } else if (superadminWorkspaceFocus === 'identity') {
        workspaceBody = `
          <div class="sa-v2-panel">
            <div class="sa-v2-detail-header"><h4>Identity Controls</h4><button class="btn-secondary" onclick="setSuperadminWorkspaceFocus('')">Back</button></div>
            <div style="display:grid;grid-template-columns:minmax(260px,0.9fr) minmax(0,1.1fr);gap:12px;">
              <div style="display:grid; gap:10px;">
                <div style="display:grid; gap:8px;">
                  <div style="display:grid; grid-template-columns:minmax(0,1fr) auto; gap:8px;">
                    <input id="superadminIdentitySearchInput" type="text" value="${escapeHtml(superadminIdentitySearch)}" placeholder="Search by Discord ID, username, or wallet..." oninput="applySuperadminIdentityFilter(this.value)">
                    <button class="btn-secondary" onclick="loadSuperadminIdentityView()">Refresh</button>
                  </div>
                  <div style="display:grid; grid-template-columns:minmax(0,1fr) minmax(0,1fr); gap:8px;">
                    <input id="superadminIdentityNewDiscordId" type="text" placeholder="Discord User ID">
                    <input id="superadminIdentityNewUsername" type="text" placeholder="Username (optional)">
                  </div>
                  <div style="display:grid; grid-template-columns:minmax(0,1fr) auto auto auto; gap:8px; align-items:center;">
                    <input id="superadminIdentityNewWallet" type="text" placeholder="Wallet address (optional)">
                    <label style="display:flex;align-items:center;gap:6px;color:#c9d6ff;font-size:0.82em;"><input id="superadminIdentityNewPrimary" type="checkbox">Primary</label>
                    <label style="display:flex;align-items:center;gap:6px;color:#c9d6ff;font-size:0.82em;"><input id="superadminIdentityNewFavorite" type="checkbox">Favorite</label>
                    <button id="superadminIdentityQuickAddBtn" class="btn-primary" onclick="quickAddSuperadminIdentity()">Create / Link</button>
                  </div>
                </div>
                <div id="superadminIdentityList" style="display:grid; gap:8px; max-height:520px; overflow:auto;"></div>
              </div>
              <div id="superadminIdentityDetail" style="padding:12px; border:1px solid rgba(99,102,241,0.16); border-radius:10px; background:rgba(10,16,30,0.4); color:var(--text-secondary);">
                Select a user to manage identity overrides.
              </div>
            </div>
          </div>
        `;
      } else {
        workspaceBody = `
          <div class="sa-v2-grid">
            <article class="sa-v2-card sa-v2-card--action" onclick="setSuperadminWorkspaceFocus('superadmins')">
              <h4>Superadmin Access</h4>
              <p>Manage root/global superadmin access list.</p>
              <button class="btn-secondary" onclick="event.stopPropagation(); setSuperadminWorkspaceFocus('superadmins')">Open Superadmins</button>
            </article>
            <article class="sa-v2-card sa-v2-card--action" onclick="setSuperadminWorkspaceFocus('identity')">
              <h4>Identity Controls</h4>
              <p>Trusted/manual identity controls and wallet linking tools.</p>
              <button class="btn-secondary" onclick="event.stopPropagation(); setSuperadminWorkspaceFocus('identity')">Open Identity</button>
            </article>
          </div>
        `;
      }
    } else {
      if (!capabilities.integrations) {
        workspaceBody = renderWorkspaceLockedState('Integrations & System');
      } else if (superadminWorkspaceFocus === 'aiProviders') {
        workspaceBody = `
          <div class="sa-v2-panel">
            <div class="sa-v2-detail-header"><h4>AI Provider Routing</h4><button class="btn-secondary" onclick="setSuperadminWorkspaceFocus('')">Back</button></div>
            <div style="display:grid; grid-template-columns:repeat(4,minmax(120px,1fr)); gap:10px;">
              <label style="display:grid; gap:6px;"><span style="font-size:0.8em; color:var(--text-secondary);">Default Provider</span><select id="sa_aiProviderDefault"><option value="openai" ${(globalSettings.aiAssistantDefaultProvider || 'openai') === 'openai' ? 'selected' : ''}>OpenAI</option><option value="gemini" ${(globalSettings.aiAssistantDefaultProvider || 'openai') === 'gemini' ? 'selected' : ''}>Gemini</option></select></label>
              <label style="display:grid; gap:6px;"><span style="font-size:0.8em; color:var(--text-secondary);">Fallback Provider</span><select id="sa_aiProviderFallback"><option value="" ${(globalSettings.aiAssistantFallbackProvider || '') === '' ? 'selected' : ''}>None</option><option value="openai" ${(globalSettings.aiAssistantFallbackProvider || '') === 'openai' ? 'selected' : ''}>OpenAI</option><option value="gemini" ${(globalSettings.aiAssistantFallbackProvider || '') === 'gemini' ? 'selected' : ''}>Gemini</option></select></label>
              <label style="display:grid; gap:6px;"><span style="font-size:0.8em; color:var(--text-secondary);">OpenAI Model</span><input id="sa_aiModelOpenai" type="text" value="${escapeHtml(globalSettings.aiAssistantDefaultModelOpenai || 'gpt-5.4')}"></label>
              <label style="display:grid; gap:6px;"><span style="font-size:0.8em; color:var(--text-secondary);">Gemini Model</span><input id="sa_aiModelGemini" type="text" value="${escapeHtml(globalSettings.aiAssistantDefaultModelGemini || 'gemini-2.0-flash')}"></label>
            </div>
            <div style="display:grid; grid-template-columns:repeat(2,minmax(220px,1fr)); gap:10px; margin-top:10px;">
              <label style="display:grid; gap:6px;">
                <span style="font-size:0.8em; color:var(--text-secondary);">OpenAI API Key (optional update)</span>
                <input id="sa_openaiApiKey" type="password" value="" placeholder="sk-...">
              </label>
              <label style="display:grid; gap:6px;">
                <span style="font-size:0.8em; color:var(--text-secondary);">Gemini API Key (optional update)</span>
                <input id="sa_geminiApiKey" type="password" value="" placeholder="AIza...">
              </label>
            </div>
            <div style="display:flex; gap:14px; flex-wrap:wrap; margin-top:10px;">
              <label style="display:flex; align-items:center; gap:8px;"><input id="sa_openaiApiKeyClear" type="checkbox">Clear stored OpenAI key</label>
              <label style="display:flex; align-items:center; gap:8px;"><input id="sa_geminiApiKeyClear" type="checkbox">Clear stored Gemini key</label>
            </div>
            <div class="gp-actions-row"><button class="btn-primary" onclick="saveAiProviderSettings()">Save AI Settings</button></div>
          </div>
        `;
      } else if (superadminWorkspaceFocus === 'xProvider') {
        workspaceBody = `
          <div class="sa-v2-panel">
            <div class="sa-v2-detail-header"><h4>X Provider</h4><button class="btn-secondary" onclick="setSuperadminWorkspaceFocus('')">Back</button></div>
            <div style="display:grid; grid-template-columns:1fr 1fr; gap:10px;">
              <label style="display:grid; gap:6px;"><span style="font-size:0.82em; color:var(--text-secondary);">X Client ID</span><input id="sa_xClientId" type="text" value="${escapeHtml(globalSettings.xClientId || '')}"></label>
              <label style="display:grid; gap:6px;"><span style="font-size:0.82em; color:var(--text-secondary);">X Redirect URI (optional)</span><input id="sa_xRedirectUri" type="text" value="${escapeHtml(globalSettings.xRedirectUri || '')}" placeholder="https://guildpilot.app/auth/x/callback"></label>
            </div>
            <div style="display:grid; grid-template-columns:1fr 1fr; gap:10px; margin-top:10px;">
              <label style="display:grid; gap:6px;"><span style="font-size:0.82em; color:var(--text-secondary);">Polling Interval (sec)</span><input id="sa_xPollingInterval" type="number" min="30" max="3600" value="${escapeHtml(String(globalSettings.xPollingIntervalSeconds || 300))}"></label>
              <div></div>
            </div>
            <div style="display:grid; grid-template-columns:1fr 1fr; gap:10px; margin-top:10px;">
              <label style="display:grid; gap:6px;"><span style="font-size:0.82em; color:var(--text-secondary);">X Client Secret (optional update)</span><input id="sa_xClientSecret" type="password" value=""></label>
              <label style="display:grid; gap:6px;"><span style="font-size:0.82em; color:var(--text-secondary);">X Bearer Token (optional update)</span><input id="sa_xBearerToken" type="password" value=""></label>
            </div>
            <div style="display:grid; grid-template-columns:1fr 1fr; gap:10px; margin-top:8px; color:var(--text-secondary); font-size:0.82em;">
              <div>
                Client Secret:
                <strong style="color:${globalSettings.xClientSecretConfigured ? '#86efac' : '#fca5a5'};">
                  ${globalSettings.xClientSecretConfigured ? 'Configured' : 'Not configured'}
                </strong>
                ${globalSettings.xClientSecretMasked ? `<span style="margin-left:6px; color:#a5b4fc;">(${escapeHtml(globalSettings.xClientSecretMasked)})</span>` : ''}
              </div>
              <div>
                Bearer Token:
                <strong style="color:${globalSettings.xBearerTokenConfigured ? '#86efac' : '#fca5a5'};">
                  ${globalSettings.xBearerTokenConfigured ? 'Configured' : 'Not configured'}
                </strong>
                ${globalSettings.xBearerTokenMasked ? `<span style="margin-left:6px; color:#a5b4fc;">(${escapeHtml(globalSettings.xBearerTokenMasked)})</span>` : ''}
              </div>
            </div>
            <div style="display:flex; gap:14px; flex-wrap:wrap; margin-top:10px;">
              <label style="display:flex; align-items:center; gap:8px;"><input id="sa_xClientSecretClear" type="checkbox">Clear stored X client secret</label>
              <label style="display:flex; align-items:center; gap:8px;"><input id="sa_xBearerTokenClear" type="checkbox">Clear stored X bearer token</label>
            </div>
            <label style="display:flex; align-items:center; gap:10px; margin-top:10px;"><input id="sa_xPollingEnabled" type="checkbox" ${globalSettings.xPollingEnabled ? 'checked' : ''}>Enable X polling</label>
            <div class="sa-v2-inline-note" style="margin-top:8px;">Secrets are never shown in full for security. Entering a new value replaces the stored value.</div>
            <div class="gp-actions-row">
              <button class="btn-secondary" onclick="testXProviderApi()">Test X API</button>
              <button class="btn-primary" onclick="saveXProviderSettings()">Save X Settings</button>
            </div>
          </div>
        `;
      } else if (superadminWorkspaceFocus === 'chainEmojis') {
        const chainEmojiMap = globalSettings.chainEmojiMap || {};
        workspaceBody = `
          <div class="sa-v2-panel">
            <div class="sa-v2-detail-header"><h4>Chain Emojis & Replay</h4><button class="btn-secondary" onclick="setSuperadminWorkspaceFocus('')">Back</button></div>
            <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:10px;">
              ${['solana','usdc','ethereum','base','polygon','arbitrum','optimism','bsc','avalanche'].map(chain => `<label style="display:grid;gap:6px;"><span style="font-size:0.82em;color:var(--text-secondary);text-transform:capitalize;">${chain}</span><input id="sa_chainEmoji_${chain}" type="text" value="${escapeHtml(chainEmojiMap[chain] || '')}" placeholder="<:emoji:123...> or unicode"></label>`).join('')}
            </div>
            <div style="display:grid; grid-template-columns:minmax(0,1fr) auto; gap:10px; margin-top:10px;">
              <input id="sa_nftReplayTx" type="text" placeholder="Paste NFT tx signature to replay activity parsing">
              <button class="btn-secondary" onclick="replayNftActivityTx()">Replay Tx</button>
            </div>
            <div class="gp-actions-row"><button class="btn-primary" onclick="saveChainEmojiMap()">Save Chain Emojis</button></div>
          </div>
        `;
      } else if (superadminWorkspaceFocus === 'billingSettings') {
        workspaceBody = `
          <div class="sa-v2-panel">
            <div class="sa-v2-detail-header"><h4>Billing & Payments</h4><button class="btn-secondary" onclick="setSuperadminWorkspaceFocus('')">Back</button></div>
            <div style="display:grid; grid-template-columns:minmax(0,1fr) minmax(0,1fr); gap:10px;">
              <label style="display:grid; gap:6px;">
                <span style="font-size:0.82em; color:var(--text-secondary);">Receiving Wallet (SOL/USDC on Solana)</span>
                <input id="sa_billingReceiveWallet" type="text" value="${escapeHtml(globalSettings.billingReceiveWallet || '')}" placeholder="Solana wallet address">
              </label>
              <label style="display:grid; gap:6px;">
                <span style="font-size:0.82em; color:var(--text-secondary);">Support URL (optional)</span>
                <input id="sa_billingSupportUrl" type="url" value="${escapeHtml(globalSettings.billingSupportUrl || '')}" placeholder="https://...">
              </label>
            </div>
            <label style="display:flex; align-items:center; gap:10px; margin-top:10px;">
              <input id="sa_billingOnchainVerifyEnabled" type="checkbox" ${globalSettings.billingOnchainVerifyEnabled ? 'checked' : ''}>
              Enable on-chain receipt verification
            </label>
            <div class="sa-v2-inline-note" style="margin-top:10px;">
              Tenant admins submit payment receipts from Plans. Superadmins review and approve in Billing workspace.
            </div>
            <div class="gp-actions-row"><button class="btn-primary" onclick="saveBillingSettings()">Save Billing Settings</button></div>
          </div>
        `;
      } else {
        workspaceBody = `
          <div class="sa-v2-grid">
            <article class="sa-v2-card sa-v2-card--action" onclick="setSuperadminWorkspaceFocus('aiProviders')"><h4>AI Provider Routing</h4><p>Provider defaults and model routing.</p><button class="btn-secondary" onclick="event.stopPropagation(); setSuperadminWorkspaceFocus('aiProviders')">Open AI Settings</button></article>
            <article class="sa-v2-card sa-v2-card--action" onclick="setSuperadminWorkspaceFocus('xProvider')"><h4>X Provider</h4><p>OAuth and polling settings.</p><button class="btn-secondary" onclick="event.stopPropagation(); setSuperadminWorkspaceFocus('xProvider')">Open X Settings</button></article>
            <article class="sa-v2-card sa-v2-card--action" onclick="setSuperadminWorkspaceFocus('chainEmojis')"><h4>Chain Emojis & Replay</h4><p>Global chain map and replay tools.</p><button class="btn-secondary" onclick="event.stopPropagation(); setSuperadminWorkspaceFocus('chainEmojis')">Open Chain Controls</button></article>
            <article class="sa-v2-card sa-v2-card--action" onclick="setSuperadminWorkspaceFocus('billingSettings')"><h4>Billing & Payments</h4><p>Receiving wallet and payment verification controls.</p><button class="btn-secondary" onclick="event.stopPropagation(); setSuperadminWorkspaceFocus('billingSettings')">Open Billing Settings</button></article>
          </div>
        `;
      }
    }

    content.innerHTML = `
      <div class="sa-v2-shell">
        <div class="sa-v2-header">
          <div>
            <h3>Admin Workspace Hub</h3>
            <p>Role-aware operational panel with tenant split view and billing ledger.</p>
          </div>
          <div class="sa-v2-chip-row">
            <span class="sa-v2-chip">Role: ${escapeHtml(isSuperadmin ? 'Superadmin' : 'Tenant Admin')}</span>
            <span class="sa-v2-chip">Active Guild: ${escapeHtml(activeGuildId || 'none')}</span>
            <span class="sa-v2-chip">UI: Superadmin V2</span>
          </div>
        </div>
        <div class="sa-v2-tabs">
          ${tabButton('overview', 'Overview')}
          ${tabButton('tenants', 'Tenants')}
          ${tabButton('billing', 'Billing')}
          ${tabButton('security', 'Security & Access')}
          ${tabButton('integrations', 'Integrations & System')}
        </div>
        ${renderWorkspaceDataHealth(workspaceLoadState)}
        ${workspaceWarnings.length ? `<div class="sa-v2-inline-note" style="margin:8px 0 12px; border-color:rgba(245,158,11,0.35); color:#fde68a;">${workspaceWarnings.map((item) => escapeHtml(item)).join(' ')}</div>` : ''}
        <div class="sa-v2-main">
          <div class="sa-v2-body">${workspaceBody}</div>
          <aside class="sa-v2-rail">
            <div class="sa-v2-rail-card">
              <h4>Quick Actions</h4>
              <div class="sa-v2-quick-actions">
                <button class="btn-secondary" onclick="loadSuperadminView()">Refresh Workspace</button>
                <button class="btn-secondary" onclick="setSuperadminWorkspaceTab('tenants')">Open Tenants</button>
                <button class="btn-secondary" onclick="setSuperadminWorkspaceTab('billing')">Open Billing</button>
              </div>
            </div>
            <div class="sa-v2-rail-card">
              <h4>Recent Activity</h4>
              <div class="sa-v2-activity-list">
                ${
                  workspaceLoadState.activityFailed
                    ? renderWorkspaceScopedError('Recent activity feed failed to load.', 'Retry Activity', 'loadSuperadminView()')
                    : renderWorkspaceActivityItems(superadminWorkspaceActivityCache)
                }
              </div>
            </div>
          </aside>
        </div>
      </div>
    `;
    if (workspace === 'security' && superadminWorkspaceFocus === 'identity') {
      setTimeout(() => loadSuperadminIdentityView(), 0);
    }
    if (workspaceWarnings.length) {
      reportAdminUiTelemetry('workspace_partial_failure', { workspace, warnings: workspaceWarnings });
    }
    reportAdminUiTelemetry('ttfmr_ms', { workspace, ms: Date.now() - startMs });
  } catch (error) {
    reportAdminUiTelemetry('workspace_load_failure', { workspace, message: error?.message || String(error) });
    content.innerHTML = `<div class="sa-v2-empty">${escapeHtml(formatAdminWorkspaceError('Failed to load workspace hub', error))}</div>`;
  }
}

async function loadSuperadminView() {
  return loadSuperadminWorkspaceHubV2();
}





function renderSuperadminIdentityDetail(profile) {
  if (!profile?.user) {
    return `<div style="color:var(--text-secondary);">Select a user from the list to manage identity overrides.</div>`;
  }

  const user = profile.user;
  const flags = profile.flags || {};
  const wallets = Array.isArray(profile.wallets) ? profile.wallets : [];
  const walletRows = wallets.length > 0
    ? wallets.map(wallet => `
      <div style="display:grid; grid-template-columns:minmax(0,1fr) auto; gap:8px; align-items:center; padding:8px 10px; border:1px solid rgba(99,102,241,0.15); border-radius:10px; background:rgba(14,23,44,0.45);">
        <div style="min-width:0;">
          <div style="color:#e0e7ff; font-family:monospace; font-size:0.84em; word-break:break-all;">${escapeHtml(wallet.walletAddress || '')}</div>
          <div style="margin-top:4px; display:flex; gap:6px; flex-wrap:wrap;">
            ${wallet.primaryWallet ? '<span style="padding:2px 7px;border-radius:999px;background:rgba(16,185,129,0.18);color:#bbf7d0;font-size:0.72em;">Primary</span>' : ''}
            ${wallet.favoriteWallet ? '<span style="padding:2px 7px;border-radius:999px;background:rgba(251,191,36,0.18);color:#fde68a;font-size:0.72em;">Favorite</span>' : ''}
          </div>
        </div>
        <button class="btn-secondary" onclick="removeSuperadminIdentityWallet('${escapeJsString(user.discordId)}', '${escapeJsString(wallet.walletAddress || '')}')" style="padding:6px 10px; font-size:0.82em;">Unlink</button>
      </div>
    `).join('')
    : `<div style="padding:10px; text-align:center; color:var(--text-secondary); border:1px dashed rgba(99,102,241,0.18); border-radius:10px;">No wallets linked yet.</div>`;

  return `
    <div style="display:grid; gap:12px;">
      <div style="display:flex; justify-content:space-between; align-items:flex-start; gap:12px;">
        <div>
          <div style="color:#e0e7ff; font-size:1.02em; font-weight:700;">${escapeHtml(user.username || user.discordId)}</div>
          <div style="color:var(--text-secondary); font-size:0.8em; font-family:monospace; margin-top:3px; word-break:break-all;">${escapeHtml(user.discordId)}</div>
        </div>
        <div style="display:flex; gap:6px; flex-wrap:wrap; justify-content:flex-end;">
          ${flags.trustedIdentity ? '<span style="padding:2px 8px;border-radius:999px;background:rgba(16,185,129,0.18);color:#bbf7d0;font-size:0.72em;">Trusted</span>' : ''}
          ${flags.manualVerified ? '<span style="padding:2px 8px;border-radius:999px;background:rgba(245,158,11,0.18);color:#fde68a;font-size:0.72em;">Manual</span>' : ''}
        </div>
      </div>

      <div style="display:grid; grid-template-columns:repeat(2,minmax(0,1fr)); gap:8px; font-size:0.82em;">
        <div style="padding:10px; border:1px solid rgba(99,102,241,0.14); border-radius:10px; background:rgba(30,41,59,0.45);">
          <div style="color:var(--text-secondary);">Wallets</div>
          <div style="color:#e0e7ff; font-weight:700; margin-top:3px;">${escapeHtml(String(wallets.length))}</div>
        </div>
        <div style="padding:10px; border:1px solid rgba(99,102,241,0.14); border-radius:10px; background:rgba(30,41,59,0.45);">
          <div style="color:var(--text-secondary);">NFTs</div>
          <div style="color:#e0e7ff; font-weight:700; margin-top:3px;">${escapeHtml(String(user.totalNfts || 0))}</div>
        </div>
      </div>

      <div style="padding:12px; border:1px solid rgba(99,102,241,0.15); border-radius:10px; background:rgba(14,23,44,0.45);">
        <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:10px; gap:10px;">
          <h5 style="margin:0; color:#c9d6ff;">Identity Flags</h5>
          <button id="superadminIdentityFlagsSaveBtn" class="btn-primary" onclick="saveSuperadminIdentityFlags()" style="padding:6px 12px; font-size:0.82em;">Save Flags</button>
        </div>
        <div style="display:flex; gap:16px; flex-wrap:wrap; margin-bottom:10px;">
          <label style="display:flex; align-items:center; gap:8px; color:#e0e7ff; font-size:0.88em; cursor:pointer;">
            <input id="superadminIdentityTrustedInput" type="checkbox" ${flags.trustedIdentity ? 'checked' : ''}>
            <span>Trusted Identity</span>
          </label>
          <label style="display:flex; align-items:center; gap:8px; color:#e0e7ff; font-size:0.88em; cursor:pointer;">
            <input id="superadminIdentityManualInput" type="checkbox" ${flags.manualVerified ? 'checked' : ''}>
            <span>Manual Verified</span>
          </label>
        </div>
        <label style="display:grid; gap:6px;">
          <span style="font-size:0.8em; color:var(--text-secondary);">Notes (internal)</span>
          <textarea id="superadminIdentityNotesInput" rows="3" maxlength="2000" style="padding:9px 10px; background:rgba(30,41,59,0.8); border:1px solid rgba(99,102,241,0.22); border-radius:8px; color:#e0e7ff; resize:vertical;">${escapeHtml(flags.notes || '')}</textarea>
        </label>
      </div>

      <div style="padding:12px; border:1px solid rgba(99,102,241,0.15); border-radius:10px; background:rgba(14,23,44,0.45);">
        <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:10px; gap:10px;">
          <h5 style="margin:0; color:#c9d6ff;">Linked Wallets</h5>
          <button id="superadminIdentityWalletAddBtn" class="btn-primary" onclick="addSuperadminIdentityWallet()" style="padding:6px 12px; font-size:0.82em;">Link Wallet</button>
        </div>
        <div style="display:grid; grid-template-columns:minmax(0,1fr) auto auto; gap:8px; margin-bottom:10px;">
          <input id="superadminIdentityWalletInput" type="text" placeholder="Solana wallet address" style="padding:9px 10px; background:rgba(30,41,59,0.8); border:1px solid rgba(99,102,241,0.22); border-radius:8px; color:#e0e7ff; font-family:monospace; font-size:0.84em;">
          <label style="display:flex; align-items:center; gap:6px; color:#c9d6ff; font-size:0.8em;">
            <input id="superadminIdentityWalletPrimaryInput" type="checkbox">
            Primary
          </label>
          <label style="display:flex; align-items:center; gap:6px; color:#c9d6ff; font-size:0.8em;">
            <input id="superadminIdentityWalletFavoriteInput" type="checkbox">
            Favorite
          </label>
        </div>
        <div style="display:grid; gap:8px;">${walletRows}</div>
      </div>

      <div style="padding:12px; border:1px solid rgba(99,102,241,0.15); border-radius:10px; background:rgba(14,23,44,0.45);">
        <h5 style="margin:0 0 10px; color:#c9d6ff;">Identity Audit</h5>
        <div id="superadminIdentityAuditList" style="display:grid; gap:8px;">${renderSuperadminIdentityAudit(superadminIdentityAuditCache)}</div>
      </div>
    </div>
  `;
}

async function loadSuperadminIdentityView() {
  const listEl = document.getElementById('superadminIdentityList');
  const detailEl = document.getElementById('superadminIdentityDetail');
  if (!listEl || !detailEl) return;

  listEl.innerHTML = `<div style="padding:16px; text-align:center;"><div class="spinner"></div><div style="margin-top:8px; color:var(--text-secondary); font-size:0.85em;">Loading users...</div></div>`;

  try {
    const query = new URLSearchParams();
    if (superadminIdentitySearch.trim()) query.set('q', superadminIdentitySearch.trim());
    query.set('limit', '40');
    query.set('offset', '0');

    const response = await fetch(`/api/superadmin/identity/users?${query.toString()}`, { credentials: 'include' });
    const data = await response.json();
    if (!data.success) {
      listEl.innerHTML = `<div style="padding:14px; color:#fca5a5;">${escapeHtml(data.message || 'Failed to load users')}</div>`;
      return;
    }

    superadminIdentityCache = Array.isArray(data.users) ? data.users : [];
    if (!superadminIdentitySelectedUserId || !superadminIdentityCache.some(user => user.discordId === superadminIdentitySelectedUserId)) {
      superadminIdentitySelectedUserId = superadminIdentityCache[0]?.discordId || '';
    }

    listEl.innerHTML = renderSuperadminIdentityRows(superadminIdentityCache);

    const searchEl = document.getElementById('superadminIdentitySearchInput');
    if (searchEl && superadminIdentitySearch) {
      const len = searchEl.value.length;
      searchEl.focus();
      searchEl.setSelectionRange(len, len);
    }

    if (superadminIdentitySelectedUserId) {
      await loadSuperadminIdentityDetail(superadminIdentitySelectedUserId);
    } else {
      detailEl.innerHTML = renderSuperadminIdentityDetail(null);
    }
  } catch (error) {
    listEl.innerHTML = `<div style="padding:14px; color:#fca5a5;">Error loading identity users: ${escapeHtml(error.message || 'Unknown error')}</div>`;
  }
}

function applySuperadminIdentityFilter(query) {
  superadminIdentitySearch = String(query || '');
  if (superadminIdentitySearchTimer) clearTimeout(superadminIdentitySearchTimer);
  superadminIdentitySearchTimer = setTimeout(() => {
    loadSuperadminIdentityView();
  }, 220);
}

function selectSuperadminIdentityUser(discordId) {
  superadminIdentitySelectedUserId = String(discordId || '').trim();
  if (!superadminIdentitySelectedUserId) return;
  loadSuperadminIdentityDetail(superadminIdentitySelectedUserId);
  const listEl = document.getElementById('superadminIdentityList');
  if (listEl) {
    listEl.innerHTML = renderSuperadminIdentityRows(superadminIdentityCache);
  }
}

async function loadSuperadminIdentityDetail(discordId) {
  const detailEl = document.getElementById('superadminIdentityDetail');
  if (!detailEl) return;

  const normalizedDiscordId = String(discordId || '').trim();
  if (!normalizedDiscordId) {
    detailEl.innerHTML = renderSuperadminIdentityDetail(null);
    return;
  }

  detailEl.innerHTML = `<div style="padding:16px; text-align:center;"><div class="spinner"></div><div style="margin-top:8px; color:var(--text-secondary); font-size:0.85em;">Loading profile...</div></div>`;

  try {
    const [profileRes, auditRes] = await Promise.all([
      fetch(`/api/superadmin/identity/users/${encodeURIComponent(normalizedDiscordId)}`, { credentials: 'include' }),
      fetch(`/api/superadmin/identity/audit?discordId=${encodeURIComponent(normalizedDiscordId)}&limit=25`, { credentials: 'include' }),
    ]);

    const [profileData, auditData] = await Promise.all([profileRes.json(), auditRes.json()]);

    if (!profileData.success) {
      detailEl.innerHTML = `<div style="padding:14px; color:#fca5a5;">${escapeHtml(profileData.message || 'Failed to load user profile')}</div>`;
      return;
    }

    superadminIdentitySelectedUserId = normalizedDiscordId;
    superadminIdentityAuditCache = auditData?.success && Array.isArray(auditData.auditLogs) ? auditData.auditLogs : [];

    detailEl.innerHTML = renderSuperadminIdentityDetail(profileData.profile);
    const listEl = document.getElementById('superadminIdentityList');
    if (listEl) {
      listEl.innerHTML = renderSuperadminIdentityRows(superadminIdentityCache);
    }
  } catch (error) {
    detailEl.innerHTML = `<div style="padding:14px; color:#fca5a5;">Error loading user detail: ${escapeHtml(error.message || 'Unknown error')}</div>`;
  }
}

async function saveSuperadminIdentityFlags() {
  const discordId = String(superadminIdentitySelectedUserId || '').trim();
  if (!discordId) return;

  const btn = document.getElementById('superadminIdentityFlagsSaveBtn');
  const trustedInput = document.getElementById('superadminIdentityTrustedInput');
  const manualInput = document.getElementById('superadminIdentityManualInput');
  const notesInput = document.getElementById('superadminIdentityNotesInput');
  if (!trustedInput || !manualInput || !notesInput) return;

  if (btn) {
    btn.disabled = true;
    btn.textContent = 'Saving...';
  }

  try {
    const response = await fetch(`/api/superadmin/identity/users/${encodeURIComponent(discordId)}/flags`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify({
        trustedIdentity: !!trustedInput.checked,
        manualVerified: !!manualInput.checked,
        notes: notesInput.value || '',
      }),
    });
    const data = await response.json();
    if (!data.success) {
      showError(data.message || 'Failed to save identity flags');
      return;
    }

    showSuccess('Identity flags saved');
    await loadSuperadminIdentityView();
  } catch (error) {
    showError(`Failed to save identity flags: ${error.message}`);
  } finally {
    if (btn) {
      btn.disabled = false;
      btn.textContent = 'Save Flags';
    }
  }
}

async function addSuperadminIdentityWallet() {
  const discordId = String(superadminIdentitySelectedUserId || '').trim();
  if (!discordId) return;

  const walletInput = document.getElementById('superadminIdentityWalletInput');
  const primaryInput = document.getElementById('superadminIdentityWalletPrimaryInput');
  const favoriteInput = document.getElementById('superadminIdentityWalletFavoriteInput');
  const btn = document.getElementById('superadminIdentityWalletAddBtn');
  if (!walletInput || !primaryInput || !favoriteInput || !btn) return;

  const walletAddress = String(walletInput.value || '').trim();
  if (!walletAddress) {
    showError('Wallet address is required');
    return;
  }

  btn.disabled = true;
  btn.textContent = 'Linking...';
  try {
    const response = await fetch(`/api/superadmin/identity/users/${encodeURIComponent(discordId)}/wallets`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify({
        walletAddress,
        primaryWallet: !!primaryInput.checked,
        favoriteWallet: !!favoriteInput.checked,
      }),
    });
    const data = await response.json();
    if (!data.success) {
      showError(data.message || 'Failed to link wallet');
      return;
    }

    walletInput.value = '';
    primaryInput.checked = false;
    favoriteInput.checked = false;
    showSuccess('Wallet linked');
    await loadSuperadminIdentityView();
  } catch (error) {
    showError(`Failed to link wallet: ${error.message}`);
  } finally {
    btn.disabled = false;
    btn.textContent = 'Link Wallet';
  }
}

async function quickAddSuperadminIdentity() {
  const discordInput = document.getElementById('superadminIdentityNewDiscordId');
  const usernameInput = document.getElementById('superadminIdentityNewUsername');
  const walletInput = document.getElementById('superadminIdentityNewWallet');
  const primaryInput = document.getElementById('superadminIdentityNewPrimary');
  const favoriteInput = document.getElementById('superadminIdentityNewFavorite');
  const btn = document.getElementById('superadminIdentityQuickAddBtn');

  if (!discordInput || !usernameInput || !walletInput || !primaryInput || !favoriteInput || !btn) return;

  const discordId = String(discordInput.value || '').trim();
  const username = String(usernameInput.value || '').trim();
  const walletAddress = String(walletInput.value || '').trim();

  if (!discordId) {
    showError('Discord User ID is required.');
    return;
  }

  btn.disabled = true;
  btn.textContent = 'Saving...';
  try {
    if (walletAddress) {
      const response = await fetch(`/api/superadmin/identity/users/${encodeURIComponent(discordId)}/wallets`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify({
          walletAddress,
          username: username || null,
          primaryWallet: !!primaryInput.checked,
          favoriteWallet: !!favoriteInput.checked,
        }),
      });
      const data = await response.json();
      if (!data.success) {
        showError(data.message || 'Failed to link wallet');
        return;
      }
      showSuccess('Identity created and wallet linked.');
    } else {
      const response = await fetch('/api/superadmin/identity/users/ensure', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify({
          discordId,
          username: username || null,
          reason: 'quick_add',
        }),
      });
      const data = await response.json();
      if (!data.success) {
        showError(data.message || 'Failed to create identity profile');
        return;
      }
      showSuccess('Identity profile created.');
    }

    discordInput.value = '';
    usernameInput.value = '';
    walletInput.value = '';
    primaryInput.checked = false;
    favoriteInput.checked = false;

    superadminIdentitySearch = discordId;
    superadminIdentitySelectedUserId = discordId;
    await loadSuperadminIdentityView();
  } catch (error) {
    showError(`Failed to save identity: ${error.message}`);
  } finally {
    btn.disabled = false;
    btn.textContent = 'Create / Link';
  }
}

function removeSuperadminIdentityWallet(discordId, walletAddress) {
  const normalizedDiscordId = String(discordId || '').trim();
  const normalizedWallet = String(walletAddress || '').trim();
  if (!normalizedDiscordId || !normalizedWallet) return;

  showConfirmModal(
    'Unlink Wallet?',
    `Unlink wallet ${normalizedWallet} from ${normalizedDiscordId}?`,
    async () => {
      try {
        const response = await fetch(`/api/superadmin/identity/users/${encodeURIComponent(normalizedDiscordId)}/wallets/${encodeURIComponent(normalizedWallet)}`, {
          method: 'DELETE',
          credentials: 'include',
        });
        const data = await response.json();
        if (!data.success) {
          showError(data.message || 'Failed to unlink wallet');
          return;
        }
        showSuccess('Wallet unlinked');
        await loadSuperadminIdentityView();
      } catch (error) {
        showError(`Failed to unlink wallet: ${error.message}`);
      }
    },
    'Unlink'
  );
}


function selectTenantGuild(guildId) {
  selectedTenantGuildId = guildId;
  const url = new URL(window.location);
  const normalized = normalizeGuildId(String(guildId || ''));
  if (normalized) url.searchParams.set('saTenantId', normalized);
  else url.searchParams.delete('saTenantId');
  window.history.replaceState({}, '', url);
  loadSuperadminView();
}

function updateTenantTemplateDescription() {
  const select = document.getElementById('tenantTemplateSelect');
  const desc = document.getElementById('tenantTemplateDescription');
  if (!select || !desc) return;

  const templateKey = String(select.value || '').trim();
  const template = (superadminTemplateCatalog || []).find(item => item.key === templateKey);
  desc.textContent = template?.description || 'Apply a template to set plan, module toggles, and module limits in one action.';

  selectedTenantTemplatePreview = null;
  const previewEl = document.getElementById('tenantTemplatePreview');
  if (previewEl) {
    previewEl.innerHTML = renderTenantTemplatePreview(null);
  }
  previewTenantTemplate({ silent: true });
}

async function previewTenantTemplate(options = {}) {
  if (!selectedTenantGuildId) return;
  const { silent = false } = options;

  const select = document.getElementById('tenantTemplateSelect');
  const btn = document.getElementById('tenantTemplatePreviewBtn');
  const previewEl = document.getElementById('tenantTemplatePreview');
  if (!select || !btn || !previewEl) return;

  const templateKey = String(select.value || '').trim();
  if (!templateKey) {
    selectedTenantTemplatePreview = null;
    previewEl.innerHTML = renderTenantTemplatePreview(null);
    if (!silent) showError('Select a template first.');
    return;
  }

  btn.disabled = true;
  btn.textContent = 'Previewing...';
  previewEl.innerHTML = '<div style="color:var(--text-secondary);">Loading template preview...</div>';

  try {
    const query = new URLSearchParams({ templateKey });
    const response = await fetch(`/api/superadmin/tenants/${encodeURIComponent(selectedTenantGuildId)}/template-preview?${query.toString()}`, {
      credentials: 'include'
    });
    const data = await response.json();
    if (!data.success) {
      selectedTenantTemplatePreview = null;
      previewEl.innerHTML = renderTenantTemplatePreview(null);
      if (!silent) showError(data.message || 'Failed to preview template');
      return;
    }

    selectedTenantTemplatePreview = data.preview || null;
    previewEl.innerHTML = renderTenantTemplatePreview(selectedTenantTemplatePreview);
  } catch (error) {
    selectedTenantTemplatePreview = null;
    previewEl.innerHTML = renderTenantTemplatePreview(null);
    if (!silent) showError(`Failed to preview template: ${error.message}`);
  } finally {
    btn.disabled = false;
    btn.textContent = 'Preview';
  }
}

async function applyTenantTemplate() {
  if (!selectedTenantGuildId) return;

  const select = document.getElementById('tenantTemplateSelect');
  const btn = document.getElementById('tenantTemplateApplyBtn');
  if (!select || !btn) return;

  const templateKey = String(select.value || '').trim();
  if (!templateKey) {
    showError('Select a template first.');
    return;
  }

  btn.disabled = true;
  btn.textContent = 'Applying...';

  try {
    const response = await fetch(`/api/superadmin/tenants/${encodeURIComponent(selectedTenantGuildId)}/apply-template`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify({ templateKey })
    });
    const data = await response.json();

    if (data.success) {
      showSuccess(`Template applied: ${data.template?.label || templateKey}`);
      selectedTenantTemplatePreview = null;
      await loadSuperadminView();
    } else {
      showError(data.message || 'Failed to apply template');
    }
  } catch (error) {
    showError(`Failed to apply template: ${error.message}`);
  } finally {
    btn.disabled = false;
    btn.textContent = 'Apply Template';
  }
}

async function rollbackTenantTemplate() {
  if (!selectedTenantGuildId) return;

  const btn = document.getElementById('tenantTemplateRollbackBtn');
  if (!btn) return;

  showConfirmModal(
    'Rollback Template?',
    'This restores the tenant to the state before the last applied template (plan, module toggles, and module limit overrides).',
    async () => {
      btn.disabled = true;
      btn.textContent = 'Rolling Back...';
      try {
        const response = await fetch(`/api/superadmin/tenants/${encodeURIComponent(selectedTenantGuildId)}/rollback-template`, {
          method: 'POST',
          credentials: 'include',
          headers: { 'Content-Type': 'application/json' },
        });
        const data = await response.json();
        if (!data.success) {
          showError(data.message || 'Failed to rollback template');
          return;
        }

        showSuccess(`Template rollback completed (audit #${data.rolledBackFromAuditId || 'n/a'})`);
        selectedTenantTemplatePreview = null;
        await loadSuperadminView();
      } catch (error) {
        showError(`Failed to rollback template: ${error.message}`);
      } finally {
        btn.disabled = false;
        btn.textContent = 'Rollback Last';
      }
    },
    'Rollback'
  );
}

async function applyTenantPlan() {
  if (!selectedTenantGuildId) return;

  const select = document.getElementById('tenantPlanSelect');
  const btn = document.getElementById('tenantPlanApplyBtn');
  if (!select || !btn) return;
  const nextPlan = String(select.value || '').toLowerCase();
  const currentPlan = String(selectedTenantDetailCache?.planKey || '').toLowerCase();

  const runApply = async () => {
    btn.disabled = true;
    btn.textContent = 'Applying...';
    try {
      const response = await fetch(`/api/superadmin/tenants/${encodeURIComponent(selectedTenantGuildId)}/plan`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify({ plan: select.value })
      });
      const data = await response.json();

      if (data.success) {
        showSuccess('Tenant plan updated');
        await loadSuperadminView();
      } else {
        reportAdminUiSaveFailure('applyTenantPlan', new Error(data.message || 'Failed to update tenant plan'), { guildId: selectedTenantGuildId, nextPlan });
        showError(data.message || 'Failed to update tenant plan');
      }
    } catch (error) {
      reportAdminUiSaveFailure('applyTenantPlan', error, { guildId: selectedTenantGuildId, nextPlan });
      showError(formatAdminWorkspaceError('Failed to update tenant plan', error));
    } finally {
      btn.disabled = false;
      btn.textContent = 'Apply';
    }
  };

  if (getTenantPlanRank(nextPlan) < getTenantPlanRank(currentPlan)) {
    showConfirmModal(
      'Downgrade Tenant Plan?',
      `This changes the tenant from ${getTenantPlanLabel(currentPlan)} to ${getTenantPlanLabel(nextPlan)} and can reduce module limits or disable paid capabilities. Continue?`,
      runApply,
      'Downgrade'
    );
    return;
  }

  await runApply();
}

async function toggleTenantModule(moduleKey, checkbox) {
  if (!selectedTenantGuildId || !checkbox) return;

  const desiredEnabled = !!checkbox.checked;
  const previousValue = !desiredEnabled;
  const syncToggleVisual = (isEnabled) => {
    const track = checkbox.parentElement?.querySelector?.('.tenant-toggle-track');
    const knob = checkbox.parentElement?.querySelector?.('.tenant-toggle-knob');
    if (track) track.style.background = isEnabled ? 'var(--gold)' : '#555';
    if (knob) knob.style.left = isEnabled ? '22px' : '3px';
  };
  const persistToggle = async () => {
    try {
      const response = await fetch(`/api/superadmin/tenants/${encodeURIComponent(selectedTenantGuildId)}/modules`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify({ moduleKey, enabled: desiredEnabled })
      });
      const data = await response.json();

      if (data.success) {
        showSuccess(`${getTenantModuleLabel(moduleKey)} updated`);
        await loadSuperadminView();
      } else {
        reportAdminUiSaveFailure('toggleTenantModule', new Error(data.message || 'Failed to update module'), { guildId: selectedTenantGuildId, moduleKey, desiredEnabled });
        checkbox.checked = previousValue;
        syncToggleVisual(previousValue);
        showError(`Failed to update module (${response.status}): ${data.message || data.error?.message || JSON.stringify(data)}`);
      }
    } catch (error) {
      reportAdminUiSaveFailure('toggleTenantModule', error, { guildId: selectedTenantGuildId, moduleKey, desiredEnabled });
      checkbox.checked = previousValue;
      syncToggleVisual(previousValue);
      showError(`Failed to update tenant module: ${error.message}`);
    }
  };

  if (!desiredEnabled) {
    const moduleLabel = getTenantModuleLabel(moduleKey);
    showConfirmModal(
      'Disable Module?',
      `This will disable "${moduleLabel}" for the tenant and may interrupt live automations. Continue?`,
      persistToggle,
      'Disable'
    );
    checkbox.checked = previousValue;
    syncToggleVisual(previousValue);
    return;
  }

  await persistToggle();
}

async function saveTenantStatus() {
  if (!selectedTenantGuildId) return;

  const select = document.getElementById('tenantStatusSelect');
  const btn = document.getElementById('tenantStatusSaveBtn');
  if (!select || !btn) return;
  const nextStatus = String(select.value || '').toLowerCase();
  const currentStatus = String(selectedTenantDetailCache?.status || selectedTenantDetailCache?.tenantStatus || '').toLowerCase();

  const runSave = async () => {
    btn.disabled = true;
    btn.textContent = 'Saving...';
    try {
      const response = await fetch(`/api/superadmin/tenants/${encodeURIComponent(selectedTenantGuildId)}/status`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify({ status: select.value })
      });
      const data = await response.json();

      if (data.success) {
        showSuccess('Tenant status updated');
        await loadSuperadminView();
      } else {
        reportAdminUiSaveFailure('saveTenantStatus', new Error(data.message || 'Failed to update tenant status'), { guildId: selectedTenantGuildId, nextStatus });
        showError(data.message || 'Failed to update tenant status');
      }
    } catch (error) {
      reportAdminUiSaveFailure('saveTenantStatus', error, { guildId: selectedTenantGuildId, nextStatus });
      showError(`Failed to update tenant status: ${error.message}`);
    } finally {
      btn.disabled = false;
      btn.textContent = 'Save';
    }
  };

  if (currentStatus !== 'suspended' && nextStatus === 'suspended') {
    showConfirmModal(
      'Suspend Tenant?',
      'This will disable access for this tenant until re-activated. Continue with suspension?',
      runSave,
      'Suspend'
    );
    return;
  }

  await runSave();
}

async function saveTenantMockData() {
  if (!selectedTenantGuildId) return;
  if (!isMockModeEnabled()) {
    showError('Tenant mock data is disabled in live mode.');
    return;
  }

  const input = document.getElementById('tenantMockDataSwitch');
  const btn = document.getElementById('tenantMockDataSaveBtn');
  if (!input || !btn) return;

  btn.disabled = true;
  btn.textContent = 'Saving...';
  try {
    const response = await fetch(`/api/superadmin/tenants/${encodeURIComponent(selectedTenantGuildId)}/mock-data`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify({ enabled: !!input.checked })
    });
    const data = await response.json();
    if (data.success) {
      showSuccess(`Mock data ${input.checked ? 'enabled' : 'disabled'} for tenant`);
      await loadSuperadminView();
    } else {
      reportAdminUiSaveFailure('saveTenantMockData', new Error(data.message || 'Failed to update mock data setting'), { guildId: selectedTenantGuildId, enabled: !!input.checked });
      showError(data.message || 'Failed to update mock data setting');
    }
  } catch (error) {
    reportAdminUiSaveFailure('saveTenantMockData', error, { guildId: selectedTenantGuildId, enabled: !!input.checked });
    showError(formatAdminWorkspaceError('Failed to update mock data setting', error));
  } finally {
    btn.disabled = false;
    btn.textContent = 'Save Mock Data';
  }
}

async function saveTenantModuleLimits() {
  if (!selectedTenantGuildId) return;

  const btn = document.getElementById('tenantModuleLimitsSaveBtn');
  const inputs = Array.from(document.querySelectorAll('[data-tenant-limit-input="1"]'));
  if (!btn || inputs.length === 0) return;

  const overrides = {};
  for (const input of inputs) {
    const moduleKey = String(input.dataset.moduleKey || '').trim();
    const limitKey = String(input.dataset.limitKey || '').trim();
    if (!moduleKey || !limitKey) continue;

    const raw = String(input.value || '').trim();
    if (!overrides[moduleKey]) overrides[moduleKey] = {};

    if (raw === '') {
      overrides[moduleKey][limitKey] = null;
      continue;
    }

    const numeric = Number(raw);
    if (!Number.isFinite(numeric) || numeric < 0) {
      showError(`Invalid value for ${getTenantModuleLabel(moduleKey)} -> ${limitKey}. Use a non-negative number or leave empty.`);
      return;
    }

    overrides[moduleKey][limitKey] = Math.floor(numeric);
  }

  btn.disabled = true;
  btn.textContent = 'Saving...';
  try {
    const response = await fetch(`/api/superadmin/tenants/${encodeURIComponent(selectedTenantGuildId)}/limits`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify({ overrides }),
    });
    const data = await response.json();
    if (data.success) {
      selectedTenantLimitsCache = data.limits || null;
      showSuccess('Tenant module limits saved');
      await loadSuperadminView();
    } else {
      console.error('[admin-ui-v2][save_failure]', { action: 'saveTenantModuleLimits', error: data.message || 'Failed to save module limits' });
      showError(data.message || 'Failed to save module limits');
    }
  } catch (error) {
    console.error('[admin-ui-v2][save_failure]', { action: 'saveTenantModuleLimits', error: error?.message || String(error) });
    showError(formatAdminWorkspaceError('Failed to save module limits', error));
  } finally {
    btn.disabled = false;
    btn.textContent = 'Save Limits';
  }
}

async function uploadTenantLogo() {
  if (!selectedTenantGuildId) return;
  const input = document.getElementById('tenantBrandLogoFile');
  const btn = document.getElementById('tenantLogoUploadBtn');
  if (!input || !input.files || input.files.length === 0) {
    return showError('Select a logo file first.');
  }

  const file = input.files[0];
  const maxBytes = 2 * 1024 * 1024;
  if (file.size > maxBytes) {
    return showError('Logo too large (max 2MB).');
  }

  const reader = new FileReader();
  const dataUrl = await new Promise((resolve, reject) => {
    reader.onload = () => resolve(reader.result);
    reader.onerror = reject;
    reader.readAsDataURL(file);
  }).catch(() => null);

  if (!dataUrl) return showError('Failed to read logo file.');

  btn.disabled = true;
  btn.textContent = 'Uploading...';
  try {
    const response = await fetch(`/api/superadmin/tenants/${encodeURIComponent(selectedTenantGuildId)}/logo-upload`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify({ dataUrl })
    });
    const data = await response.json();
    if (data.success) {
      const logoInput = document.getElementById('tenantBrandLogoUrl');
      if (logoInput) logoInput.value = data.logo_url || '';
      showSuccess('Logo uploaded');
      await loadSuperadminView();
    } else {
      console.error('[admin-ui-v2][save_failure]', { action: 'uploadTenantLogo', error: data.message || 'Failed to upload logo' });
      showError(data.message || 'Failed to upload logo');
    }
  } catch (error) {
    console.error('[admin-ui-v2][save_failure]', { action: 'uploadTenantLogo', error: error?.message || String(error) });
    showError(formatAdminWorkspaceError('Failed to upload logo', error));
  } finally {
    btn.disabled = false;
    btn.textContent = 'Upload Logo';
  }
}

