async function loadAdminProposals() {
  if (!isAdmin) return;
  const content = document.getElementById('adminProposalsContent');
  if (!content) return;

  content.innerHTML = `<div style="text-align:center; padding: var(--space-5); color: var(--text-secondary);"><div class="spinner"></div><p>Loading proposals...</p></div>`;

  try {
    const response = await fetch('/api/admin/proposals', { credentials: 'include' });
    const data = await response.json();
    if (!data.success) throw new Error(data.message || 'Failed to load proposals');

    const proposals = data.proposals || [];
    if (!proposals.length) {
      content.innerHTML = `<div class="empty-state"><div class="empty-state-title">No proposals found</div></div>`;
      return;
    }

    const statusOrder = ['pending_review', 'on_hold', 'supporting', 'voting', 'concluded', 'vetoed', 'draft', 'expired', 'passed', 'rejected', 'quorum_not_met'];
    const grouped = {};
    for (const p of proposals) {
      const s = p.status || 'draft';
      if (!grouped[s]) grouped[s] = [];
      grouped[s].push(p);
    }

    const statusLabels = {
      pending_review: 'Pending Review', on_hold: 'On Hold', supporting: 'Supporting',
      voting: 'Voting', concluded: 'Concluded', vetoed: 'Vetoed', draft: 'Draft',
      expired: 'Expired', passed: 'Passed', rejected: 'Rejected', quorum_not_met: 'Quorum Not Met'
    };

    const categoryColors = {
      'Partnership': '#3b82f6', 'Treasury Allocation': '#f59e0b',
      'Rule Change': '#ef4444', 'Community Event': '#10b981', 'Other': '#8b5cf6'
    };

    let html = '';
    for (const status of statusOrder) {
      const items = grouped[status];
      if (!items || !items.length) continue;

      html += `<div style="margin-bottom:20px;">
        <h4 style="color:var(--text-primary); margin-bottom:10px; font-size:1em; border-bottom:1px solid var(--border-default); padding-bottom:6px;">
          ${statusLabels[status] || status} (${items.length})
        </h4>
        <div style="display:grid; gap:10px;">`;

      for (const p of items) {
        const catColor = categoryColors[p.category] || '#8b5cf6';
        const commentCount = p.comment_count || 0;
        const vetoVotes = p.veto_votes ? JSON.parse(p.veto_votes || '[]').length : 0;

        let actions = '';
        if (status === 'pending_review') {
          actions = `<div style="display:flex; gap:8px; margin-top:8px;">
            <button onclick="adminProposalAction('${escapeJsString(p.proposal_id)}', 'approve')" style="padding:6px 14px; background:#10b981; border:none; border-radius:6px; color:#fff; cursor:pointer; font-size:0.85em;">Approve</button>
            <button onclick="adminProposalHold('${escapeJsString(p.proposal_id)}')" style="padding:6px 14px; background:#f59e0b; border:none; border-radius:6px; color:#fff; cursor:pointer; font-size:0.85em;">Hold</button>
          </div>`;
        } else if (status === 'on_hold') {
          actions = `<div style="display:flex; gap:8px; margin-top:8px;">
            <button onclick="adminProposalAction('${escapeJsString(p.proposal_id)}', 'approve')" style="padding:6px 14px; background:#10b981; border:none; border-radius:6px; color:#fff; cursor:pointer; font-size:0.85em;">Approve</button>
            ${p.on_hold_reason ? `<span style="color:var(--text-secondary); font-size:0.85em; align-self:center;">Reason: ${escapeHtml(p.on_hold_reason)}</span>` : ''}
          </div>`;
        } else if (status === 'supporting') {
          actions = `<div style="display:flex; gap:8px; margin-top:8px;">
            <button onclick="adminProposalAction('${escapeJsString(p.proposal_id)}', 'promote')" style="padding:6px 14px; background:#6366f1; border:none; border-radius:6px; color:#fff; cursor:pointer; font-size:0.85em;">Promote to Voting</button>
          </div>`;
        } else if (status === 'voting') {
          const totalVoted = (p.yes_vp || 0) + (p.no_vp || 0) + (p.abstain_vp || 0);
          const quorumPct = p.total_vp > 0 ? Math.round((totalVoted / p.total_vp) * 100) : 0;
          actions = `<div style="margin-top:8px;">
            <div style="font-size:0.85em; color:var(--text-secondary); margin-bottom:6px;">
              Yes: ${p.yes_vp || 0} VP | No: ${p.no_vp || 0} VP | Abstain: ${p.abstain_vp || 0} VP | Quorum: ${quorumPct}% / ${p.quorum_required || '?'} VP needed
              ${vetoVotes > 0 ? ` | Veto votes: ${vetoVotes}` : ''}
              ${p.paused ? ' | <span style="color:#ef4444;">PAUSED</span>' : ''}
            </div>
            <div style="display:flex; gap:8px;">
              <button onclick="adminProposalAction('${escapeJsString(p.proposal_id)}', 'conclude')" style="padding:6px 14px; background:#ef4444; border:none; border-radius:6px; color:#fff; cursor:pointer; font-size:0.85em;">Conclude</button>
              <button onclick="adminProposalAction('${escapeJsString(p.proposal_id)}', 'pause')" style="padding:6px 14px; background:#f59e0b; border:none; border-radius:6px; color:#fff; cursor:pointer; font-size:0.85em;">${p.paused ? 'Unpause' : 'Pause'}</button>
            </div>
          </div>`;
        } else if (status === 'vetoed') {
          actions = p.veto_reason ? `<div style="margin-top:6px; font-size:0.85em; color:#ef4444;">Veto reason: ${escapeHtml(p.veto_reason)}</div>` : '';
        }

        html += `<div style="padding:12px; border:1px solid var(--border-default); border-radius:10px; background: var(--bg-tertiary);">
          <div style="display:flex; justify-content:space-between; gap:12px; flex-wrap:wrap;">
            <strong>${escapeHtml(p.title || 'Untitled')}</strong>
            <div style="display:flex; gap:6px; align-items:center;">
              <span style="padding:2px 8px; border-radius:4px; font-size:0.8em; background:${catColor}20; color:${catColor}; border:1px solid ${catColor}40;">${escapeHtml(p.category || 'Other')}</span>
              <span class="status-badge status-${escapeHtml(p.status || 'draft')}">${escapeHtml(p.status || 'draft')}</span>
            </div>
          </div>
          <div style="color:var(--text-secondary); font-size:0.85em; margin-top:6px;">
            ID: ${escapeHtml(p.proposal_id || '')}  Creator: ${escapeHtml(p.creator_id || '')}
            ${p.cost_indication ? `  Cost: ${escapeHtml(p.cost_indication)}` : ''}
          </div>
          ${actions}
        </div>`;
      }

      html += '</div></div>';
    }

    content.innerHTML = html;
  } catch (e) {
    content.innerHTML = `<div class="error-state"><div class="error-message">${escapeHtml(e.message)}</div></div>`;
  }
}

async function adminProposalAction(proposalId, action) {
  const endpoints = {
    approve: `/api/admin/governance/proposals/${proposalId}/approve`,
    promote: `/api/admin/governance/proposals/${proposalId}/promote`,
    conclude: `/api/admin/governance/proposals/${proposalId}/conclude`,
    pause: `/api/admin/governance/proposals/${proposalId}/pause`
  };
  const labels = { approve: 'Approve', promote: 'Promote to Voting', conclude: 'Conclude Voting', pause: 'Toggle Pause' };

  showConfirmModal(`${labels[action]}?`, `Are you sure you want to ${labels[action].toLowerCase()} proposal ${proposalId}?`, async () => {
    try {
      const response = await fetch(endpoints[action], { method: 'POST', headers: { 'Content-Type': 'application/json' }, credentials: 'include' });
      const data = await response.json();
      if (data.success) {
        showSuccess(`Proposal ${proposalId}: ${labels[action]} successful`);
        await loadAdminProposals();
      } else {
        showError(data.message || `Failed to ${action}`);
      }
    } catch (e) {
      showError('Error: ' + e.message);
    }
  }, labels[action]);
}

function adminProposalHold(proposalId) {
  showConfirmModal('Place on Hold', '', null);
  const body = document.getElementById('confirmMessage');
  const btn = document.getElementById('confirmButton');
  const title = document.getElementById('confirmTitle');
  title.textContent = 'Place Proposal on Hold';
  btn.textContent = 'Place on Hold';
  btn.classList.remove('btn-danger');
  btn.classList.add('btn-primary');

  body.innerHTML = `
    <div>
      <label style="display:block; color:#c9d6ff; font-size:0.9em; margin-bottom:6px;">Reason (optional)</label>
      <input id="holdReasonInput" type="text" placeholder="Why is this on hold?" style="width:100%; padding:10px 12px; background:rgba(30,41,59,0.8); border:1px solid rgba(99,102,241,0.22); border-radius:8px; color:#e0e7ff; font-size:0.9em;">
    </div>
  `;

  confirmCallback = async () => {
    const reason = document.getElementById('holdReasonInput')?.value.trim() || '';
    try {
      const response = await fetch(`/api/admin/governance/proposals/${proposalId}/hold`, {
        method: 'POST', headers: { 'Content-Type': 'application/json' },
        credentials: 'include', body: JSON.stringify({ reason })
      });
      const data = await response.json();
      if (data.success) {
        showSuccess(`Proposal ${proposalId} placed on hold`);
        await loadAdminProposals();
      } else {
        showError(data.message || 'Failed to hold proposal');
      }
    } catch (e) {
      showError('Error: ' + e.message);
    }
  };
}

let portalSettingsData = null;

function getBattleSettingsFieldIds(scope = 'settings') {
  if (scope === 'module') {
    return {
      min: 'battleModulePauseMinInput',
      max: 'battleModulePauseMaxInput',
      elite: 'battleModuleElitePrepInput',
      forced: 'battleModuleForcedEliminationIntervalInput',
      era: 'battleModuleDefaultEraSelect',
    };
  }
  return {
    min: 'battlePauseMinInput',
    max: 'battlePauseMaxInput',
    elite: 'battleElitePrepInput',
    forced: 'battleForcedEliminationIntervalInput',
    era: 'battleDefaultEraSelect',
  };
}

async function loadBattleTimingSettings(scope = 'settings') {
  try {
    const [settingsRes, erasRes] = await Promise.all([
      fetch('/api/admin/settings', { credentials: 'include', headers: buildTenantRequestHeaders() }),
      fetch('/api/admin/battle/eras', { credentials: 'include', headers: buildTenantRequestHeaders() }).catch(() => null),
    ]);

    const data = await settingsRes.json();
    const s = data.settings || {};
    const ids = getBattleSettingsFieldIds(scope);

    const minEl = document.getElementById(ids.min);
    const maxEl = document.getElementById(ids.max);
    const eliteEl = document.getElementById(ids.elite);
    const forcedEl = document.getElementById(ids.forced);
    if (minEl) minEl.value = s.battleRoundPauseMinSec ?? 5;
    if (maxEl) maxEl.value = s.battleRoundPauseMaxSec ?? 10;
    if (eliteEl) eliteEl.value = s.battleElitePrepSec ?? 12;
    if (forcedEl) forcedEl.value = s.battleForcedEliminationIntervalRounds ?? 3;

    let eras = [{ key: 'mafia', name: 'Mafia (default)' }];
    if (erasRes && erasRes.ok) {
      const eraData = await erasRes.json();
      if (Array.isArray(eraData.eras) && eraData.eras.length) eras = eraData.eras;
    }

    const currentEra = s.battleDefaultEra || 'mafia';
    const opts = eras.map(e => `<option style="background:rgba(30,41,59,1);color:#e0e7ff;" value="${escapeHtml(e.key)}">${escapeHtml(e.name)}</option>`).join('');

    if (scope === 'settings') {
      const battlePane = document.getElementById('settingsTab-battle');
      if (battlePane && !document.getElementById('battleDefaultEraWrap')) {
        const eraWrap = document.createElement('div');
        eraWrap.id = 'battleDefaultEraWrap';
        eraWrap.style.cssText = 'margin-top:16px;border-top:1px solid rgba(99,102,241,0.15);padding-top:16px;position:relative;z-index:1;';
        eraWrap.innerHTML = `
          <label class="form-label">Default Battle Era</label>
          <select id="battleDefaultEraSelect" class="form-input" style="width:220px;background:rgba(30,41,59,0.95);color:#e0e7ff;border:1px solid rgba(99,102,241,0.22);">
            ${opts}
          </select>
          <p style="color:var(--text-secondary); font-size:0.82em; margin-top:4px;">Era used when no era is specified in /battle create. Custom eras must be assigned by a Superadmin.</p>
        `;
        const saveBtn = battlePane.querySelector('button');
        const saveBtnContainer = saveBtn ? saveBtn.closest('div') : null;
        if (saveBtnContainer) {
          saveBtnContainer.parentElement.insertBefore(eraWrap, saveBtnContainer);
        } else {
          battlePane.querySelector('.card > div')?.appendChild(eraWrap);
        }
      }
    }

    const eraSelect = document.getElementById(ids.era);
    if (eraSelect) {
      eraSelect.innerHTML = opts;
      eraSelect.value = currentEra;
    }
  } catch (e) {
    console.error('[Battle settings] load error:', e);
  }
}

async function loadBattleModuleSettings() {
  return loadBattleTimingSettings('module');
}

async function saveBattleTimingSettings(scope = 'settings') {
  const ids = getBattleSettingsFieldIds(scope);
  const minVal = parseFloat(document.getElementById(ids.min)?.value);
  const maxVal = parseFloat(document.getElementById(ids.max)?.value);
  const eliteVal = parseFloat(document.getElementById(ids.elite)?.value);
  const forcedIntervalVal = parseInt(document.getElementById(ids.forced)?.value, 10);
  if (isNaN(minVal) || isNaN(maxVal) || isNaN(eliteVal) || isNaN(forcedIntervalVal)) return showError('Please enter valid numbers for all timing fields.');
  if (minVal > maxVal) return showError('Minimum pause cannot be greater than maximum pause.');
  if (forcedIntervalVal < 1 || forcedIntervalVal > 20) return showError('Forced elimination interval must be between 1 and 20 rounds.');
  const eraVal = document.getElementById(ids.era)?.value || 'mafia';
  try {
    const res = await fetch('/api/admin/settings', {
      method: 'PUT',
      credentials: 'include',
      headers: { 'Content-Type': 'application/json', ...buildTenantRequestHeaders() },
      body: JSON.stringify({
        battleRoundPauseMinSec: minVal,
        battleRoundPauseMaxSec: maxVal,
        battleElitePrepSec: eliteVal,
        battleForcedEliminationIntervalRounds: forcedIntervalVal,
        battleDefaultEra: eraVal
      })
    });
    const data = await res.json();
    if (data.success) showSuccess(scope === 'module' ? 'Minigames settings saved!' : 'Battle settings saved!');
    else showError(data.message || 'Failed to save battle settings.');
  } catch (e) {
    showError('Error saving battle settings.');
  }
}

async function saveBattleModuleSettings() {
  return saveBattleTimingSettings('module');
}

async function loadAdminSettingsView() {
  if (!isAdmin) return;
  const content = document.getElementById('adminSettingsContent');
  if (!content) return;

  content.innerHTML = `<div style="text-align:center; padding: var(--space-5); color: var(--text-secondary);"><div class="spinner"></div><p>Loading settings...</p></div>`;

  // --- Shared inline-style constants ---
  const cardStyle = 'background:rgba(14,23,44,0.5);border:1px solid rgba(99,102,241,0.22);border-radius:10px;padding:var(--space-5);margin-bottom:var(--space-5);';
  const cardHeader = 'color:#c9d6ff;font-size:var(--font-lg);font-weight:700;margin:0 0 var(--space-4) 0;padding-bottom:var(--space-3);border-bottom:1px solid rgba(99,102,241,0.15);';

  try {
    // Step 1: Fetch settings first
    const settingsRes = await fetch('/api/admin/settings', { credentials: 'include', headers: buildTenantRequestHeaders() });
    const settingsJson = await settingsRes.json();
    if (!settingsJson.success) throw new Error(settingsJson.message || 'Failed to load settings');
    portalSettingsData = settingsJson.settings;
    const s = portalSettingsData;
    const tenantReadOnlyModules = !!(s.multiTenantEnabled && s.readOnlyManaged && !isSuperadmin);
    // assignedModuleKeys: null = single-tenant (all visible), array = multi-tenant assigned keys
    const assignedKeys = s.assignedModuleKeys || null;

    // Update settings tab visibility immediately (assigned-only filtering)
    applySettingsTabVisibility(s);

    // Module toggle mapping: settingsKey -> { label, icon, moduleKey (for assigned check) }
    const MODULE_TOGGLE_DEFS = [
      { id: 'moduleMinigamesEnabled',    label: 'Minigames',       icon: '', moduleKey: 'minigames'     },
      { id: 'moduleGovernanceEnabled',   label: 'Governance',      icon: 'G',  moduleKey: 'governance'    },
      { id: 'moduleVerificationEnabled', label: 'Verification',    icon: 'V',  moduleKey: 'verification'  },
      { id: 'moduleBrandingEnabled',     label: 'Branding',        icon: 'BR', moduleKey: 'branding'      },
      { id: 'moduleMissionsEnabled',     label: 'Missions',        icon: 'H',  moduleKey: 'heist'         },
      { id: 'moduleVaultEnabled',        label: 'Vault',           icon: '', moduleKey: 'vault'         },
      { id: 'moduleTelegramBridgeEnabled', label: 'Telegram Bridge', icon: 'TG', moduleKey: 'telegrambridge' },
      { id: 'moduleAutoMessagesEnabled', label: 'Auto Messages', icon: 'AM', moduleKey: 'automessages' },
      { id: 'moduleWelcomeEnabled',      label: 'Welcome',         icon: '', moduleKey: 'welcome'       },
      { id: 'moduleWalletTrackerEnabled',label: 'Wallet Tracker',  icon: 'W',  moduleKey: 'wallettracker' },
      { id: 'moduleAiAssistantEnabled',  label: 'AI Assistant',    icon: 'AI', moduleKey: 'aiassistant'  },
      { id: 'moduleInviteTrackerEnabled',label: 'Invite Tracker',  icon: '', moduleKey: 'invites'       },
      { id: 'moduleTreasuryEnabled',     label: 'Treasury',        icon: '$',  moduleKey: 'treasury'      },
      { id: 'moduleNftTrackerEnabled',   label: 'NFT Tracker',     icon: 'N',  moduleKey: 'nfttracker'    },
      { id: 'moduleTokenTrackerEnabled', label: 'Token Tracker',   icon: '\ud83e\ude99',  moduleKey: 'tokentracker'  },
      { id: 'moduleRoleClaimEnabled',    label: 'Self-Serve Roles',icon: 'R',  moduleKey: 'selfserveroles'},
      { id: 'moduleTicketingEnabled',    label: 'Ticketing',       icon: 'TK', moduleKey: 'ticketing'     },
      { id: 'moduleEngagementEnabled',   label: 'Engagement',      icon: 'E',  moduleKey: 'engagement'    },
      { id: 'moduleGuildGuardEnabled',   label: 'Guild Guard',     icon: 'GG', moduleKey: 'guildguard'    },
    ];

    // Build module toggle helper (styled toggle switch)
    const moduleToggle = (id, label, icon, defaultVal) => {
      const checked = (s[id] ?? defaultVal) ? ' checked' : '';
      return `<div style="display:flex;align-items:center;justify-content:space-between;padding:var(--space-3) var(--space-4);background:rgba(30,41,59,0.8);border:1px solid rgba(99,102,241,0.22);border-radius:8px;transition:border-color .2s;">
        <label for="ps_${id}" style="cursor:pointer;font-weight:500;font-size:0.9em;color:#e0e7ff;display:flex;align-items:center;gap:var(--space-2);">
          <span style="font-size:1.25em;">${icon}</span> ${label}
        </label>
        <label style="position:relative;display:inline-block;width:44px;height:24px;flex-shrink:0;">
          <input type="checkbox" id="ps_${id}"${checked} style="opacity:0;width:0;height:0;"
            onchange="this.parentElement.querySelector('span').style.background=this.checked?'var(--gold)':'#555';">
          <span style="position:absolute;cursor:pointer;top:0;left:0;right:0;bottom:0;background:${(s[id] ?? defaultVal) ? 'var(--gold)' : '#555'};border-radius:24px;transition:.3s;"></span>
          <span style="position:absolute;content:'';height:18px;width:18px;left:${(s[id] ?? defaultVal) ? '22px' : '3px'};bottom:3px;background:#fff;border-radius:50%;transition:.3s;pointer-events:none;"
            class="ps-toggle-knob"></span>
        </label>
      </div>`;
    };

    // Render only assigned modules in tenant settings
    const visibleToggles = MODULE_TOGGLE_DEFS
      .filter(m => assignedKeys === null || assignedKeys.includes(m.moduleKey))
      .map(m => moduleToggle(m.id, m.label, m.icon, false))
      .join('');

    // Attach toggle animation via event delegation (after HTML injected)
    const attachToggleListeners = () => {
      content.querySelectorAll('input[type="checkbox"][id^="ps_module"]').forEach(cb => {
        cb.addEventListener('change', function() {
          const knob = this.parentElement.querySelector('.ps-toggle-knob');
          if (knob) knob.style.left = this.checked ? '22px' : '3px';
        });
      });
    };


    // Step 2: Inject HTML skeleton
    content.innerHTML = `
      <!-- ENV STATUS BAR -->
      <div id="adminEnvStatusBar" style="margin-bottom:var(--space-4);"></div>

      <!-- MODULE CONTROL  always visible -->
      <div style="${cardStyle}">
        <h3 style="${cardHeader}"> Module Control</h3>
        ${visibleToggles ? `<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:var(--space-3);">${visibleToggles}</div>` : '<p style="color:var(--text-secondary);font-size:0.9em;">No modules assigned. Contact your Superadmin to enable modules for this server.</p>'}
      </div>

      <!-- Action Buttons  always visible -->
      <div style="display:flex;gap:var(--space-3);justify-content:flex-end;padding-top:var(--space-4);border-top:1px solid rgba(99,102,241,0.15);">
        <button class="btn-danger" onclick="resetPortalSettings()" style="font-size:0.85em;padding:8px 16px;"> Reset to Defaults</button>
        <button class="btn-primary" onclick="savePortalSettings()" style="font-size:0.85em;padding:8px 16px;"> Save All Settings</button>
      </div>
    `;

    // Step 3: Attach toggle listeners now that DOM is ready
    attachToggleListeners();

    // In multi-tenant mode, module entitlements are managed by Superadmin only
    if (tenantReadOnlyModules) {
      const moduleControlCard = content.querySelector('h3')?.closest('div');
      const allModuleToggles = content.querySelectorAll('input[type="checkbox"][id^="ps_module"]');
      allModuleToggles.forEach(cb => {
        cb.disabled = true;
        cb.title = 'Managed by Superadmin plan';
      });
      if (moduleControlCard) {
        const note = document.createElement('div');
        note.style.cssText = 'margin-top:10px;padding:8px 10px;border-radius:8px;background:rgba(245,158,11,0.14);border:1px solid rgba(245,158,11,0.35);color:#fde68a;font-size:0.82em;';
        note.textContent = ' Module toggles are managed in Superadmin  Tenant Management.';
        moduleControlCard.appendChild(note);
      }
    }


    // Module-specific settings are now in their own tabs
  } catch (e) {
    const isAuthErr = e.message === 'Not authenticated' || e.message?.includes('authenticated') || e.message?.includes('Select a server');
    content.innerHTML = isAuthErr
      ? `<div style="text-align:center;padding:var(--space-5);">
           <p style="color:#fca5a5;font-size:0.9em;margin-bottom:16px;"> Your session has expired. Please log out and log back in.</p>
           <button class="btn-primary" onclick="logout()" style="font-size:0.9em;padding:10px 24px;">Log Out & Re-Login</button>
         </div>`
      : `<div class="error-state"><div class="error-message">${escapeHtml(e.message)}</div></div>`;
  }
}

function showSettingsSuccess(message) {
  const content = document.getElementById('adminSettingsContent');
  if (!content) return;
  const existing = content.querySelector('.settings-success-msg');
  if (existing) existing.remove();
  const msg = document.createElement('div');
  msg.className = 'settings-success-msg';
  msg.style.cssText = 'padding:var(--space-3) var(--space-4);background:rgba(16,185,129,0.15);border:1px solid rgba(16,185,129,0.4);border-radius:var(--radius-md);color:#86efac;font-weight:600;margin-bottom:var(--space-4);';
  msg.textContent = message;
  content.prepend(msg);
  setTimeout(() => msg.remove(), 5000);
}

async function savePortalSettings() {
  if (!portalSettingsData) return;

  // Only save module toggles that are actually rendered (handles assigned-module filtering)
  const moduleIds = [
    'moduleMinigamesEnabled', 'moduleBattleEnabled', 'moduleGovernanceEnabled', 'moduleVerificationEnabled', 'moduleBrandingEnabled',
    'moduleMissionsEnabled', 'moduleVaultEnabled', 'moduleTelegramBridgeEnabled', 'moduleAutoMessagesEnabled', 'moduleWelcomeEnabled', 'moduleWalletTrackerEnabled', 'moduleTreasuryEnabled', 'moduleNftTrackerEnabled', 'moduleTokenTrackerEnabled', 'moduleAiAssistantEnabled',
    'moduleRoleClaimEnabled', 'moduleTicketingEnabled', 'moduleEngagementEnabled', 'moduleGuildGuardEnabled',
  ];
  const newSettings = {};
  for (const id of moduleIds) {
    const el = document.getElementById('ps_' + id);
    if (el) newSettings[id] = el.checked; // only include rendered toggles
  }

  try {
    const response = await fetch('/api/admin/settings', {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify(newSettings)
    });
    const data = await response.json();
    if (!data.success) {
      showError(data.message || 'Failed to save settings');
      return;
    }

    showSettingsSuccess('Module toggles saved!');
    await loadAdminSettingsView();
  } catch (error) {
    console.error('Error saving settings:', error);
    showError('Failed to save settings');
  }
}

async function resetPortalSettings() {
  if (!confirm('Reset all settings to defaults? This cannot be undone.')) return;

  try {
    const response = await fetch('/api/admin/settings', {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify({ reset: true })
    });
    const data = await response.json();
    if (data.success) {
      showSettingsSuccess('Settings reset to defaults!');
      await loadAdminSettingsView();
    } else {
      showError(data.message || 'Failed to reset settings');
    }
  } catch (error) {
    console.error('Error resetting settings:', error);
    showError('Failed to reset settings');
  }
}

function vaultJsonParseInput(raw, fallback = null) {
  try {
    const text = String(raw || '').trim();
    if (!text) return fallback;
    return JSON.parse(text);
  } catch (_error) {
    return fallback;
  }
}

function vaultGetCachedActiveSeasonId() {
  const seasons = Array.isArray(vaultSettingsCache?.seasons) ? vaultSettingsCache.seasons : [];
  const active = seasons.find(season => Number(season?.active || 0) === 1);
  return active?.season_id || seasons[0]?.season_id || 'default';
}

function vaultFormatRows(rows, emptyText) {
  if (!Array.isArray(rows) || rows.length === 0) return emptyText;
  return rows.map((row, idx) => `${idx + 1}. ${row}`).join('\n');
}

function vaultFormatQuantity(value) {
  if (value === null || value === undefined || value === '') return 'Unlimited';
  const parsed = Number.parseInt(value, 10);
  if (!Number.isFinite(parsed)) return 'Unlimited';
  return `${Math.max(0, parsed)}`;
}

function vaultBuildChannelOptions(channels, selectedId) {
  const selected = String(selectedId || '').trim();
  if (!Array.isArray(channels) || channels.length === 0) {
    return '<option value="">No channels found</option>';
  }

  const grouped = channels.reduce((acc, channel) => {
    const name = String(channel?.parentName || 'No Category');
    if (!acc[name]) acc[name] = [];
    acc[name].push(channel);
    return acc;
  }, {});

  return Object.keys(grouped)
    .sort((a, b) => a.localeCompare(b))
    .map((groupName) => {
      const options = grouped[groupName]
        .sort((a, b) => String(a?.name || '').localeCompare(String(b?.name || '')))
        .map((channel) => {
          const id = String(channel?.id || '').trim();
          const channelName = String(channel?.name || id || 'unknown');
          const isSelected = id && id === selected ? ' selected' : '';
          return `<option value="${escapeHtml(id)}"${isSelected}>#${escapeHtml(channelName)}</option>`;
        })
        .join('');
      return `<optgroup label="${escapeHtml(groupName)}">${options}</optgroup>`;
    })
    .join('');
}

function vaultBuildChannelSelect(channels, selectedId, noneLabel = 'No channel selected') {
  const selected = String(selectedId || '').trim();
  const options = vaultBuildChannelOptions(channels, selected);
  const hasSelected = selected && String(options).includes(`value="${escapeHtml(selected)}"`);
  const fallbackSelectedOption = (selected && !hasSelected)
    ? `<option value="${escapeHtml(selected)}" selected>Unknown channel (${escapeHtml(selected)})</option>`
    : '';
  return `<option value="">${escapeHtml(noneLabel)}</option>${fallbackSelectedOption}${options}`;
}

function vaultBuildTicketCategorySelect(categories, selectedId, noneLabel = 'No ticket category') {
  const selected = String(selectedId || '').trim();
  const rows = Array.isArray(categories) ? categories : [];
  const options = rows
    .slice()
    .sort((a, b) => String(a?.name || '').localeCompare(String(b?.name || '')))
    .map((category) => {
      const id = String(category?.id || '').trim();
      if (!id) return '';
      const label = String(category?.name || `Category #${id}`);
      const status = category?.enabled === false || Number(category?.enabled) === 0 ? ' (disabled)' : '';
      return `<option value="${escapeHtml(id)}"${id === selected ? ' selected' : ''}>${escapeHtml(label + status)}</option>`;
    })
    .join('');
  const fallbackSelectedOption = (selected && !options.includes(`value="${escapeHtml(selected)}"`))
    ? `<option value="${escapeHtml(selected)}" selected>Unknown category (${escapeHtml(selected)})</option>`
    : '';
  return `<option value="">${escapeHtml(noneLabel)}</option>${fallbackSelectedOption}${options}`;
}

function vaultBuildKeyTierOptions(selectedId = '', includeAll = true) {
  const selected = String(selectedId || '').trim().toLowerCase();
  const tiers = vaultGetJsonArrayInputValue('vault_keyTiersJson', Array.isArray(vaultSettingsCache?.config?.keyTiers) ? vaultSettingsCache.config.keyTiers : []);
  const options = [];
  if (includeAll) options.push(`<option value=""${!selected ? ' selected' : ''}>All key tiers</option>`);
  tiers.forEach((tier) => {
    const id = String(tier?.id || '').trim().toLowerCase();
    if (!id) return;
    const label = String(tier?.name || id);
    options.push(`<option value="${escapeHtml(id)}"${id === selected ? ' selected' : ''}>${escapeHtml(label)} (${escapeHtml(id)})</option>`);
  });
  if (selected && !options.some(option => option.includes(`value="${escapeHtml(selected)}"`))) {
    options.push(`<option value="${escapeHtml(selected)}" selected>${escapeHtml(selected)}</option>`);
  }
  return options.join('');
}

function vaultCalculateRewardChanceText(reward, rewards = null, keyTierId = '') {
  const allRewards = Array.isArray(rewards) ? rewards : (Array.isArray(vaultSettingsCache?.rewards) ? vaultSettingsCache.rewards : []);
  const selectedTier = String(keyTierId || reward?.keyTier || '').trim().toLowerCase();
  const tierChain = (() => {
    const tiers = Array.isArray(vaultSettingsCache?.config?.keyTiers) ? vaultSettingsCache.config.keyTiers : [];
    const byId = new Map(tiers.map(tier => [String(tier?.id || '').trim().toLowerCase(), tier]));
    const chain = [];
    let cursor = selectedTier ? byId.get(selectedTier) : null;
    const seen = new Set();
    while (cursor && !seen.has(String(cursor.id || '').toLowerCase())) {
      const id = String(cursor.id || '').toLowerCase();
      chain.push(id);
      seen.add(id);
      cursor = cursor?.inheritsFrom ? byId.get(String(cursor.inheritsFrom || '').toLowerCase()) : null;
    }
    return new Set(chain);
  })();
  const eligible = allRewards.filter((item) => {
    if (!item || item.enabled === false || Number(item.weight || 0) <= 0) return false;
    const type = String(item?.type || '').toLowerCase();
    const code = String(item?.code || '').toLowerCase();
    if (type === 'no_reward' || code === 'no_reward' || code === 'nothing') return false;
    const itemTier = String(item?.keyTier || '').trim().toLowerCase();
    if (selectedTier && itemTier && !tierChain.has(itemTier) && itemTier !== selectedTier) return false;
    const qty = item.quantity === null || item.quantity === undefined || item.quantity === '' ? null : Number(item.quantity);
    return qty === null || qty > 0;
  });
  const total = eligible.reduce((sum, item) => sum + Math.max(0, Number(item.weight || 0)), 0);
  const weight = Math.max(0, Number(reward?.weight || 0));
  const pct = total > 0 ? ((weight / total) * 100) : 0;
  return `${pct.toFixed(2)}% of eligible prize pool`;
}

function vaultGetJsonArrayInputValue(inputId, fallback = []) {
  const parsed = vaultJsonParseInput(document.getElementById(inputId)?.value, null);
  return Array.isArray(parsed) ? parsed : fallback;
}

function vaultGetJsonObjectInputValue(inputId, fallback = {}) {
  const parsed = vaultJsonParseInput(document.getElementById(inputId)?.value, null);
  return parsed && typeof parsed === 'object' && !Array.isArray(parsed) ? parsed : fallback;
}

function vaultBuildKeyEconomySummaryHtml() {
  const tiers = vaultGetJsonArrayInputValue('vault_keyTiersJson', []);
  const bands = vaultGetJsonArrayInputValue('vault_paymentBandsJson', []);
  const conversions = vaultGetJsonArrayInputValue('vault_keyTierConversionsJson', []);
  const enabledTiers = tiers.filter(tier => tier?.enabled !== false).length;
  const enabledConversions = conversions.filter(rule => rule?.enabled !== false).length;
  const tierChips = tiers.length
    ? tiers.slice(0, 5).map((tier) => `<span class="vault-economy-chip">${escapeHtml(String(tier?.name || tier?.id || 'Tier'))}</span>`).join('')
    : '<span class="vault-economy-muted">No tiers configured</span>';
  const moreChip = tiers.length > 5 ? `<span class="vault-economy-chip">+${tiers.length - 5} more</span>` : '';
  return `
    <div class="vault-economy-card">
      <div class="vault-economy-head">
        <div>
          <h4>Key Economy Summary</h4>
          <p>Overview of the current active tiers, payment bands, and upgrades.</p>
        </div>
      </div>
      <div class="vault-economy-metrics">
        <div><strong>${enabledTiers}/${tiers.length}</strong><span>Enabled tiers</span></div>
        <div><strong>${bands.length}</strong><span>Payment bands</span></div>
        <div><strong>${enabledConversions}</strong><span>Upgrade rules</span></div>
      </div>
      <div class="vault-economy-tier-strip">${tierChips}${moreChip}</div>
    </div>
  `;
}

function vaultRenderSimpleConfigEditors() {
  const tiersWrap = document.getElementById('vaultSimpleTiersRows');
  const grantsWrap = document.getElementById('vaultSimpleGrantsRows');
  const bandsWrap = document.getElementById('vaultSimpleBandsRows');
  const conversionsWrap = document.getElementById('vaultSimpleConversionsRows');
  const summaryWrap = document.getElementById('vaultKeyEconomySummary');
  if (summaryWrap) summaryWrap.innerHTML = vaultBuildKeyEconomySummaryHtml();
  if (!tiersWrap || !grantsWrap || !bandsWrap || !conversionsWrap) return;

  const tiers = vaultGetJsonArrayInputValue('vault_keyTiersJson', []);
  const bands = vaultGetJsonArrayInputValue('vault_paymentBandsJson', []);
  const conversions = vaultGetJsonArrayInputValue('vault_keyTierConversionsJson', []);

  tiersWrap.innerHTML = tiers.length ? `
    <table class="vault-admin-table">
      <thead><tr><th align="left">Tier ID</th><th align="left">Name</th><th align="left">Inherits</th><th align="left">Enabled</th><th align="left">Actions</th></tr></thead>
      <tbody>
        ${tiers.map((tier, idx) => `
          <tr data-vault-simple-tier-row="${idx}">
            <td><code>${escapeHtml(String(tier?.id || ''))}</code></td>
            <td>${escapeHtml(String(tier?.name || '-'))}</td>
            <td>${escapeHtml(String(tier?.inheritsFrom || '-'))}</td>
            <td>${tier?.enabled === false ? 'No' : 'Yes'}</td>
            <td style="display:flex;gap:6px;">
              <button class="btn-secondary" onclick="vaultOpenConfigRowModal('tier', ${idx})">Edit</button>
              <button class="btn-danger" onclick="vaultRemoveSimpleTierRow(${idx})">Remove</button>
            </td>
          </tr>
        `).join('')}
      </tbody>
    </table>
  ` : '<p style="color:var(--text-secondary);">No tiers yet.</p>';

  if (grantsWrap) {
    grantsWrap.innerHTML = '<p style="color:var(--text-secondary);">Mint grants are hidden for V1. Payment bands decide key assignment; existing advanced grant values are preserved internally.</p>';
  }

    bandsWrap.innerHTML = bands.length ? `
    <table class="vault-admin-table">
      <thead><tr><th align="left">Tier</th><th align="left">Min</th><th align="left">Max</th><th align="left">Keys Granted</th><th align="left">Bonus Free</th><th align="left">Actions</th></tr></thead>
      <tbody>
        ${bands.map((band, idx) => {
          const tokenType = String(band?.tokenType || 'native');
          let decimals = 9;
          let label = 'SOL';
          if (tokenType === 'usdc') { decimals = 6; label = 'USDC'; }
          else if (tokenType === 'custom') { decimals = Number(band?.tokenDecimals || 9); label = escapeHtml(band?.tokenSymbol || 'SPL'); }
          const minDecimals = (Number(band?.minLamports ?? band?.min_lamports ?? 0) || 0) / (10 ** decimals);
          const maxVal = band?.maxLamports === null || band?.maxLamports === undefined ? null : Number(band?.maxLamports);
          const maxDecimals = maxVal === null ? '∞' : (maxVal / (10 ** decimals));
          return `
          <tr data-vault-simple-band-row="${idx}">
            <td><code>${escapeHtml(String(band?.keyTier || band?.key_tier || ''))}</code></td>
            <td><span class="vault-economy-chip" style="margin-right:6px;">${label}</span> ${minDecimals}</td>
            <td>${maxDecimals}</td>
            <td>${Number(band?.paid || 0)}</td>
            <td>${Number(band?.free || 0)}</td>
            <td style="display:flex;gap:6px;">
              <button class="btn-secondary" onclick="vaultOpenConfigRowModal('band', ${idx})">Edit</button>
              <button class="btn-danger" onclick="vaultRemoveSimpleBandRow(${idx})">Remove</button>
            </td>
          </tr>
        `;
        }).join('')}
      </tbody>
    </table>
  ` : '<p style="color:var(--text-secondary);">No payment bands yet.</p>';

  conversionsWrap.innerHTML = conversions.length ? `
    <table class="vault-admin-table">
      <thead><tr><th align="left">From</th><th align="left">To</th><th align="left">From Amount</th><th align="left">To Amount</th><th align="left">Enabled</th><th align="left">Actions</th></tr></thead>
      <tbody>
        ${conversions.map((rule, idx) => `
          <tr data-vault-simple-conversion-row="${idx}">
            <td><code>${escapeHtml(String(rule?.fromTier || rule?.from_tier || ''))}</code></td>
            <td><code>${escapeHtml(String(rule?.toTier || rule?.to_tier || ''))}</code></td>
            <td>${Math.max(1, Number(rule?.fromAmount ?? rule?.from_amount ?? 1) || 1)}</td>
            <td>${Math.max(1, Number(rule?.toAmount ?? rule?.to_amount ?? 1) || 1)}</td>
            <td>${rule?.enabled === false ? 'No' : 'Yes'}</td>
            <td style="display:flex;gap:6px;">
              <button class="btn-secondary" onclick="vaultOpenConfigRowModal('conversion', ${idx})">Edit</button>
              <button class="btn-danger" onclick="vaultRemoveSimpleConversionRow(${idx})">Remove</button>
            </td>
          </tr>
        `).join('')}
      </tbody>
    </table>
  ` : '<p style="color:var(--text-secondary);">No upgrade rules yet.</p>';
  vaultRenderWinChanceRows();
}

function vaultSyncSimpleEditorsToJson() {
  const tiers = vaultGetJsonArrayInputValue('vault_keyTiersJson', [])
    .map((tier) => ({
      id: String(tier?.id || '').trim().toLowerCase(),
      name: String(tier?.name || '').trim(),
      inheritsFrom: String(tier?.inheritsFrom || '').trim() || null,
      enabled: tier?.enabled !== false,
    }))
    .filter((tier) => tier.id && tier.name);
  const uniqueById = new Map();
  tiers.forEach((tier) => uniqueById.set(tier.id, tier));
  const normalizedTiers = Array.from(uniqueById.values());

  const existingGrants = vaultGetJsonObjectInputValue('vault_keyTierGrantsJson', {});
  const hasVisibleGrantInputs = !!document.querySelector('[data-vault-grant-paid]');
  const grants = {};
  normalizedTiers.forEach((tier) => {
    if (!hasVisibleGrantInputs) {
      grants[tier.id] = existingGrants[tier.id] && typeof existingGrants[tier.id] === 'object'
        ? existingGrants[tier.id]
        : { paid: 0, free: 0, pressure: 0 };
      return;
    }
    const paidEl = document.querySelector(`[data-vault-grant-paid="${tier.id}"]`);
    const freeEl = document.querySelector(`[data-vault-grant-free="${tier.id}"]`);
    const pressureEl = document.querySelector(`[data-vault-grant-pressure="${tier.id}"]`);
    grants[tier.id] = {
      paid: Math.max(0, Number(paidEl?.value || 0) || 0),
      free: Math.max(0, Number(freeEl?.value || 0) || 0),
      pressure: Math.max(0, Number(pressureEl?.value || 0) || 0),
    };
  });

  const bands = vaultGetJsonArrayInputValue('vault_paymentBandsJson', [])
    .map((band) => ({
      keyTier: String(band?.keyTier || '').trim().toLowerCase() || 'default',
      minLamports: Math.max(0, Number(band?.minLamports ?? 0) || 0),
      maxLamports: band?.maxLamports === null || band?.maxLamports === '' || band?.maxLamports === undefined ? null : Math.max(0, Number(band?.maxLamports || 0) || 0),
      paid: Math.max(0, Number(band?.paid || 0) || 0),
      free: Math.max(0, Number(band?.free || 0) || 0),
    }))
    .filter((band) => !!band.keyTier);

  const conversions = vaultGetJsonArrayInputValue('vault_keyTierConversionsJson', [])
    .map((rule) => ({
      fromTier: String(rule?.fromTier || '').trim().toLowerCase(),
      toTier: String(rule?.toTier || '').trim().toLowerCase(),
      fromAmount: Math.max(1, Number(rule?.fromAmount || 1) || 1),
      toAmount: Math.max(1, Number(rule?.toAmount || 1) || 1),
      enabled: rule?.enabled !== false,
    }))
    .filter((rule) => rule.fromTier && rule.toTier);

  const tiersEl = document.getElementById('vault_keyTiersJson');
  const grantsEl = document.getElementById('vault_keyTierGrantsJson');
  const bandsEl = document.getElementById('vault_paymentBandsJson');
  const convEl = document.getElementById('vault_keyTierConversionsJson');
  if (tiersEl) tiersEl.value = JSON.stringify(normalizedTiers, null, 2);
  if (grantsEl) grantsEl.value = JSON.stringify(grants, null, 2);
  if (bandsEl) bandsEl.value = JSON.stringify(bands, null, 2);
  if (convEl) convEl.value = JSON.stringify(conversions, null, 2);
}

function vaultGetWinChancesInputValue() {
  const parsed = vaultGetJsonObjectInputValue('vault_winChancesJson', {});
  return parsed && typeof parsed === 'object' && !Array.isArray(parsed) ? parsed : {};
}

function vaultRenderWinChanceRows() {
  const wrap = document.getElementById('vaultWinChanceRows');
  if (!wrap) return;
  const tiers = vaultGetJsonArrayInputValue('vault_keyTiersJson', []);
  const chances = vaultGetWinChancesInputValue();
  if (!tiers.length) {
    wrap.innerHTML = '<p style="color:var(--text-secondary);">Add a key tier first.</p>';
    return;
  }
  wrap.innerHTML = `
    <table class="vault-admin-table">
      <thead><tr><th align="left">Key Tier</th><th align="left">Winner Chance</th><th align="left">Eligible Prizes</th><th align="left">Actions</th></tr></thead>
      <tbody>
        ${tiers.map((tier) => {
          const tierId = String(tier?.id || 'default').trim().toLowerCase() || 'default';
          const chance = Math.max(0, Math.min(100, Number(chances[tierId] ?? 25) || 0));
          const eligibleCount = (Array.isArray(vaultSettingsCache?.rewards) ? vaultSettingsCache.rewards : [])
            .filter((reward) => {
              if (!reward || reward.enabled === false || Number(reward.weight || 0) <= 0) return false;
              const type = String(reward?.type || '').toLowerCase();
              const code = String(reward?.code || '').toLowerCase();
              if (type === 'no_reward' || code === 'no_reward' || code === 'nothing') return false;
              return !reward.keyTier || String(reward.keyTier || '').toLowerCase() === tierId;
            }).length;
          return `
            <tr>
              <td><code>${escapeHtml(tierId)}</code><div style="font-size:0.78em;color:var(--text-secondary);">${escapeHtml(String(tier?.name || tierId))}</div></td>
              <td>${chance.toFixed(2)}%</td>
              <td>${eligibleCount}</td>
              <td style="display:flex;gap:6px;">
                <button class="btn-secondary" onclick="vaultOpenWinChanceModal('${escapeJsString(tierId)}')">Edit</button>
                <button class="btn-danger" onclick="vaultRemoveWinChance('${escapeJsString(tierId)}')">Remove</button>
              </td>
            </tr>
          `;
        }).join('')}
      </tbody>
    </table>
  `;
}

function vaultOpenWinChanceModal(tierId) {
  const normalizedTierId = String(tierId || 'default').trim().toLowerCase() || 'default';
  vaultWinChanceModalState = { tierId: normalizedTierId };
  const modal = document.getElementById('vaultWinChanceModal');
  const title = document.getElementById('vaultWinChanceModalTitle');
  const input = document.getElementById('vaultWinChancePercentInput');
  const chances = vaultGetWinChancesInputValue();
  if (!modal || !title || !input) return;
  title.textContent = `Edit Win Chance: ${normalizedTierId}`;
  input.value = String(Math.max(0, Math.min(100, Number(chances[normalizedTierId] ?? 25) || 0)));
  modal.style.display = 'flex';
}

function vaultCloseWinChanceModal() {
  const modal = document.getElementById('vaultWinChanceModal');
  if (modal) modal.style.display = 'none';
}

function vaultSaveWinChanceModal() {
  const tierId = String(vaultWinChanceModalState?.tierId || '').trim().toLowerCase();
  if (!tierId) return;
  const chance = Math.max(0, Math.min(100, Number(document.getElementById('vaultWinChancePercentInput')?.value || 0) || 0));
  const chances = vaultGetWinChancesInputValue();
  chances[tierId] = chance;
  const el = document.getElementById('vault_winChancesJson');
  if (el) el.value = JSON.stringify(chances, null, 2);
  vaultCloseWinChanceModal();
  vaultRenderWinChanceRows();
}

function vaultRemoveWinChance(tierId) {
  const normalizedTierId = String(tierId || '').trim().toLowerCase();
  const chances = vaultGetWinChancesInputValue();
  if (!normalizedTierId || !Object.prototype.hasOwnProperty.call(chances, normalizedTierId)) return;
  delete chances[normalizedTierId];
  const el = document.getElementById('vault_winChancesJson');
  if (el) el.value = JSON.stringify(chances, null, 2);
  vaultRenderWinChanceRows();
}

