function vaultOpenConfigRowModal(type, index = -1) {
  vaultConfigModalState = { type: String(type || ''), index: Number(index) };
  const modal = document.getElementById('vaultConfigRowModal');
  const title = document.getElementById('vaultConfigRowModalTitle');
  const body = document.getElementById('vaultConfigRowModalBody');
  if (!modal || !title || !body) return;

  if (type === 'tier') {
    const rows = vaultGetJsonArrayInputValue('vault_keyTiersJson', []);
    const row = Number(index) >= 0 ? (rows[index] || {}) : {};
    const tierId = String(row?.id || '').trim().toLowerCase();
    const bands = vaultGetJsonArrayInputValue('vault_paymentBandsJson', []);
    const existingBand = bands.find((band) => String(band?.keyTier || '').trim().toLowerCase() === tierId) || null;
    const conversions = vaultGetJsonArrayInputValue('vault_keyTierConversionsJson', []);
    const existingUpgrade = conversions.find((rule) => String(rule?.toTier || '').trim().toLowerCase() === tierId) || null;
    title.textContent = Number(index) >= 0 ? 'Edit Key Tier' : 'Add Key Tier';
    body.innerHTML = `
      <label class="form-label">Tier ID</label><input id="vaultModalTierId" class="form-input" value="${escapeHtml(String(row?.id || ''))}" placeholder="bronze">
      <label class="form-label">Tier Name</label><input id="vaultModalTierName" class="form-input" value="${escapeHtml(String(row?.name || ''))}" placeholder="Bronze Key">
      <label class="form-label">Inherits From</label><input id="vaultModalTierInherits" class="form-input" value="${escapeHtml(String(row?.inheritsFrom || ''))}" placeholder="optional">
      <label style="display:flex;gap:8px;align-items:center;margin-top:8px;"><input id="vaultModalTierEnabled" type="checkbox" ${row?.enabled === false ? '' : 'checked'}> Enabled</label>
      <hr style="border-color:rgba(99,102,241,0.15);margin:8px 0;">
      <label style="display:flex;gap:8px;align-items:center;"><input id="vaultModalTierBandEnabled" type="checkbox" ${existingBand ? 'checked' : ''}> Configure SOL Payment Band for this tier</label>
      <label class="form-label">Band Min Lamports</label><input id="vaultModalTierBandMin" class="form-input" type="number" min="0" value="${existingBand ? Math.max(0, Number(existingBand?.minLamports || 0) || 0) : 0}">
      <label class="form-label">Band Max Lamports (blank = no max)</label><input id="vaultModalTierBandMax" class="form-input" type="number" min="0" value="${existingBand?.maxLamports === null || existingBand?.maxLamports === undefined ? '' : (Math.max(0, Number(existingBand?.maxLamports || 0) || 0))}">
      <label class="form-label">Keys Granted</label><input id="vaultModalTierBandPaid" class="form-input" type="number" min="0" value="${existingBand ? Math.max(0, Number(existingBand?.paid || 0) || 0) : 1}">
      <label class="form-label">Bonus Free Keys</label><input id="vaultModalTierBandFree" class="form-input" type="number" min="0" value="${existingBand ? Math.max(0, Number(existingBand?.free || 0) || 0) : 0}">
      <hr style="border-color:rgba(99,102,241,0.15);margin:8px 0;">
      <label style="display:flex;gap:8px;align-items:center;"><input id="vaultModalTierUpgradeEnabled" type="checkbox" ${existingUpgrade ? 'checked' : ''}> Configure upgrade rule into this tier</label>
      <label class="form-label">Upgrade From Tier</label><input id="vaultModalTierUpgradeFrom" class="form-input" value="${escapeHtml(String(existingUpgrade?.fromTier || ''))}" placeholder="bronze">
      <label class="form-label">Required From Amount</label><input id="vaultModalTierUpgradeFromAmount" class="form-input" type="number" min="1" value="${Math.max(1, Number(existingUpgrade?.fromAmount || 10) || 10)}">
      <label class="form-label">Reward To Amount</label><input id="vaultModalTierUpgradeToAmount" class="form-input" type="number" min="1" value="${Math.max(1, Number(existingUpgrade?.toAmount || 1) || 1)}">
    `;
  } else if (type === 'band') {
    const rows = vaultGetJsonArrayInputValue('vault_paymentBandsJson', []);
    const row = Number(index) >= 0 ? (rows[index] || {}) : {};
    title.textContent = Number(index) >= 0 ? 'Edit Payment Band' : 'Add Payment Band';
    const tokenType = row.tokenType || 'native';
    let decimals = 9;
    if (tokenType === 'usdc') decimals = 6;
    else if (tokenType === 'custom') decimals = Number(row.tokenDecimals || 9);
    const minVal = (Number(row?.minLamports ?? 0) || 0) / (10 ** decimals);
    const maxVal = row?.maxLamports === null || row?.maxLamports === undefined ? '' : ((Number(row?.maxLamports) || 0) / (10 ** decimals));

    body.innerHTML = `
      <label class="form-label">Tier ID</label><input id="vaultModalBandTier" class="form-input" value="${escapeHtml(String(row?.keyTier || row?.key_tier || ''))}" placeholder="bronze">
      <label class="form-label">Token Type</label>
      <select id="vaultModalBandTokenType" class="form-input" onchange="
        const t = this.value; 
        document.getElementById('vaultModalBandCustomOpts').style.display = t === 'custom' ? 'block' : 'none';
      ">
        <option value="native" ${tokenType === 'native' ? 'selected' : ''}>Native SOL</option>
        <option value="usdc" ${tokenType === 'usdc' ? 'selected' : ''}>USDC</option>
        <option value="custom" ${tokenType === 'custom' ? 'selected' : ''}>Custom SPL</option>
      </select>
      <div id="vaultModalBandCustomOpts" style="display: ${tokenType === 'custom' ? 'block' : 'none'}; padding:8px; background:var(--background-secondary); border-radius:4px; margin:8px 0;">
        <label class="form-label">Token Mint Address</label>
        <input id="vaultModalBandTokenMint" class="form-input" value="${escapeHtml(String(row?.tokenMint || ''))}" placeholder="Token Address">
        <label class="form-label">Token Symbol</label>
        <input id="vaultModalBandTokenSymbol" class="form-input" value="${escapeHtml(String(row?.tokenSymbol || ''))}" placeholder="BONK">
        <label class="form-label">Token Decimals</label>
        <input id="vaultModalBandTokenDecimals" class="form-input" type="number" value="${Number(row?.tokenDecimals || 9)}">
      </div>
      <label class="form-label">Min Amount</label><input id="vaultModalBandMin" class="form-input" type="number" step="any" min="0" value="${minVal}">
      <label class="form-label">Max Amount (blank = no max)</label><input id="vaultModalBandMax" class="form-input" type="number" step="any" min="0" value="${maxVal}">
      <label class="form-label">Paid Keys</label><input id="vaultModalBandPaid" class="form-input" type="number" min="0" value="${Number(row?.paid || 0)}">
      <label class="form-label">Free Keys</label><input id="vaultModalBandFree" class="form-input" type="number" min="0" value="${Number(row?.free || 0)}">
    `;
  } else if (type === 'conversion') {
    const rows = vaultGetJsonArrayInputValue('vault_keyTierConversionsJson', []);
    const row = Number(index) >= 0 ? (rows[index] || {}) : {};
    title.textContent = Number(index) >= 0 ? 'Edit Upgrade Rule' : 'Add Upgrade Rule';
    body.innerHTML = `
      <label class="form-label">From Tier</label><input id="vaultModalConvFrom" class="form-input" value="${escapeHtml(String(row?.fromTier || row?.from_tier || ''))}">
      <label class="form-label">To Tier</label><input id="vaultModalConvTo" class="form-input" value="${escapeHtml(String(row?.toTier || row?.to_tier || ''))}">
      <label class="form-label">From Amount</label><input id="vaultModalConvFromAmount" class="form-input" type="number" min="1" value="${Math.max(1, Number(row?.fromAmount ?? row?.from_amount ?? 1) || 1)}">
      <label class="form-label">To Amount</label><input id="vaultModalConvToAmount" class="form-input" type="number" min="1" value="${Math.max(1, Number(row?.toAmount ?? row?.to_amount ?? 1) || 1)}">
      <label style="display:flex;gap:8px;align-items:center;margin-top:8px;"><input id="vaultModalConvEnabled" type="checkbox" ${row?.enabled === false ? '' : 'checked'}> Enabled</label>
    `;
  }
  modal.style.display = 'flex';
}

