function switchAiAssistantTab(tabKey) {
  const normalized = ['general', 'knowledgebase', 'channelmode', 'audit'].includes(String(tabKey || '').trim())
    ? String(tabKey).trim()
    : 'general';
  document.querySelectorAll('[data-aiassistant-tab]').forEach(button => {
    button.classList.toggle('active', button.getAttribute('data-aiassistant-tab') === normalized);
  });
  document.querySelectorAll('[data-aiassistant-tab-panel]').forEach(panel => {
    panel.style.display = panel.getAttribute('data-aiassistant-tab-panel') === normalized ? '' : 'none';
  });
}

async function saveAiAssistantSettings() {
  const allowedSelect = document.getElementById('aiassistant_allowed_channels');
  const allowedChannelIds = allowedSelect
    ? Array.from(allowedSelect.selectedOptions || []).map(opt => String(opt.value || '').trim()).filter(Boolean)
    : [];
  const allowedRoleSelect = document.getElementById('aiassistant_allowed_roles');
  const allowedRoleIds = allowedRoleSelect
    ? Array.from(allowedRoleSelect.selectedOptions || []).map(opt => String(opt.value || '').trim()).filter(Boolean)
    : [];

  const payload = {
    enabled: !!document.getElementById('aiassistant_enabled')?.checked,
    mentionEnabled: !!document.getElementById('aiassistant_mention_enabled')?.checked,
    provider: String(document.getElementById('aiassistant_provider')?.value || 'openai'),
    responseVisibility: String(document.getElementById('aiassistant_visibility')?.value || 'public'),
    cooldownSeconds: parseInt(document.getElementById('aiassistant_cooldown_seconds')?.value, 10) || 12,
    maxResponseChars: parseInt(document.getElementById('aiassistant_max_response_chars')?.value, 10) || 1600,
    perUserDailyLimit: parseInt(document.getElementById('aiassistant_per_user_daily_limit')?.value, 10) || 0,
    safetyFilterEnabled: !!document.getElementById('aiassistant_safety_filter_enabled')?.checked,
    moderationEnabled: !!document.getElementById('aiassistant_moderation_enabled')?.checked,
    modelOpenai: String(document.getElementById('aiassistant_model_openai')?.value || '').trim() || 'gpt-5.4',
    modelGemini: String(document.getElementById('aiassistant_model_gemini')?.value || '').trim() || 'gemini-2.0-flash',
    systemPrompt: String(document.getElementById('aiassistant_system_prompt')?.value || '').trim(),
    allowedChannelIds,
    allowedRoleIds,
    summaryEnabled: !!document.getElementById('aiassistant_summary_enabled')?.checked,
    summaryChannelId: String(document.getElementById('aiassistant_recap_channel')?.value || '').trim() || null,
    summaryActivityChannels: Array.from(document.getElementById('aiassistant_summary_activity_channels')?.selectedOptions || []).map(o => o.value).filter(Boolean),
    memoryEnabled: !!document.getElementById('aiassistant_memory_enabled')?.checked,
    memoryWindowMessages: parseInt(document.getElementById('aiassistant_memory_window_messages')?.value, 10) || 0,
    publicPersonaKey: String(document.getElementById('aiassistant_public_persona_key')?.value || '').trim() || 'default_public',
    adminPersonaKey: String(document.getElementById('aiassistant_admin_persona_key')?.value || '').trim() || 'default_admin',
    dailyTokenBudget: parseInt(document.getElementById('aiassistant_daily_token_budget')?.value, 10) || 0,
    burstPerMinute: parseInt(document.getElementById('aiassistant_burst_per_minute')?.value, 10) || 0,
    allowActionSuggestions: !!document.getElementById('aiassistant_allow_action_suggestions')?.checked,
  };

  try {
    const res = await fetch('/api/admin/aiassistant/settings', {
      method: 'PUT',
      credentials: 'include',
      headers: { 'Content-Type': 'application/json', ...buildTenantRequestHeaders() },
      body: JSON.stringify(payload),
    });
    const json = await res.json();
    if (!json.success) {
      showError(json.message || 'Failed to save AI assistant settings');
      return;
    }
    showSuccess('AI assistant settings saved');
    await loadAiAssistantSettingsView();
  } catch (error) {
    showError(`Failed to save AI assistant settings: ${error.message}`);
  }
}

async function saveAiAssistantChannelPolicies() {
  const modeFields = Array.from(document.querySelectorAll('[data-ai-channel-policy-field="mode"]'));
  if (!modeFields.length) {
    showError('No channel policy inputs found');
    return;
  }

  const policies = modeFields.map(modeEl => {
    const channelId = String(modeEl.getAttribute('data-channel-id') || '').trim();
    const minEl = document.querySelector(`[data-ai-channel-policy-field="minConfidence"][data-channel-id="${channelId}"]`);
    const cooldownEl = document.querySelector(`[data-ai-channel-policy-field="passiveCooldownSeconds"][data-channel-id="${channelId}"]`);
    const maxEl = document.querySelector(`[data-ai-channel-policy-field="passiveMaxPerHour"][data-channel-id="${channelId}"]`);
    return {
      channelId,
      mode: String(modeEl.value || 'mention'),
      minConfidence: parseInt(minEl?.value, 10) || 35,
      passiveCooldownSeconds: parseInt(cooldownEl?.value, 10) || 120,
      passiveMaxPerHour: parseInt(maxEl?.value, 10) || 6,
    };
  }).filter(item => /^\d{17,20}$/.test(item.channelId));

  try {
    const res = await fetch('/api/admin/aiassistant/channel-policies', {
      method: 'PUT',
      credentials: 'include',
      headers: { 'Content-Type': 'application/json', ...buildTenantRequestHeaders() },
      body: JSON.stringify({ policies }),
    });
    const json = await res.json();
    if (!json.success) {
      showError(json.message || 'Failed to save channel policies');
      return;
    }
    showSuccess('AI channel modes saved');
    await loadAiAssistantSettingsView();
  } catch (error) {
    showError(`Failed to save channel policies: ${error.message}`);
  }
}

