// ==================== INVITE TRACKER SETTINGS ====================

function inviteTrackerPeriodToDays(raw) {
  const value = String(raw || 'all').trim().toLowerCase();
  if (value === 'all') return null;
  const n = Number(value);
  return Number.isFinite(n) && n > 0 ? Math.floor(n) : null;
}

function formatInviteTimestampLocal(rawValue) {
  if (!rawValue) return 'Unknown';
  const raw = String(rawValue).trim();
  if (!raw) return 'Unknown';

  // Stored DB timestamps are UTC-like; normalize explicitly to local browser time.
  const normalizedIso = /[zZ]|[+\-]\d{2}:?\d{2}$/.test(raw)
    ? raw.replace(' ', 'T')
    : `${raw.replace(' ', 'T')}Z`;
  const date = new Date(normalizedIso);
  if (Number.isNaN(date.getTime())) return escapeHtml(raw);
  return date.toLocaleString();
}

function formatInviteUserLabel(username, userId) {
  const cleanName = String(username || '').trim();
  const cleanId = String(userId || '').trim();
  if (cleanName && cleanId) return `${escapeHtml(cleanName)} (${escapeHtml(cleanId)})`;
  if (cleanName) return escapeHtml(cleanName);
  if (cleanId) return escapeHtml(cleanId);
  return 'Unknown';
}

let inviteTrackerAutoRefreshHandle = null;

function stopInviteTrackerAutoRefresh() {
  if (inviteTrackerAutoRefreshHandle) {
    clearInterval(inviteTrackerAutoRefreshHandle);
    inviteTrackerAutoRefreshHandle = null;
  }
}

function startInviteTrackerAutoRefresh(intervalMs = 45000) {
  stopInviteTrackerAutoRefresh();
  inviteTrackerAutoRefreshHandle = setInterval(() => {
    const pane = document.getElementById('settingsTab-invites')
      || document.getElementById('inviteTrackerModuleSettingsPanel')
      || document.getElementById('inviteTrackerSettingsPanel');
    if (!pane || pane.style.display === 'none' || !document.body.contains(pane)) return;
    refreshInviteTrackerDashboard().catch(() => {});
  }, Math.max(10000, Number(intervalMs) || 45000));
}

