async function loadEngagementTasks() {
  const el = document.getElementById('engagementTasksView');
  if (!el) return;
  el.innerHTML = '<div class="loading-state"><div class="loading-spinner"></div><p class="loading-text">Loading...</p></div>';
  try {
    const canAdminEngagement = !!(typeof isAdmin !== 'undefined' && isAdmin) || !!(typeof isSuperadmin !== 'undefined' && isSuperadmin);
    const endpoint = canAdminEngagement
      ? '/api/admin/engagement/tasks?limit=50'
      : '/api/user/engagement/tasks?limit=50&status=active';
    const res = await fetch(endpoint, { credentials: 'include', headers: buildTenantRequestHeaders() });
    const data = await res.json();
    if (!data.success || !data.tasks?.length) {
      el.innerHTML = canAdminEngagement
        ? '<p style="color:var(--text-secondary);">No tasks yet. Create one manually or ingest a monitored post.</p>'
        : '<p style="color:var(--text-secondary);">No active tasks available right now.</p>';
      return;
    }

    const rows = data.tasks.map((task) => {
      const endsAtMs = task.ends_at ? new Date(task.ends_at).getTime() : Number.NaN;
      const isExpired = String(task.status || '').toLowerCase() === 'expired'
        || (Number.isFinite(endsAtMs) && endsAtMs <= Date.now());
      const completions = Array.isArray(task.completions) ? task.completions : [];
      const completionSet = new Set(completions.map((entry) => String(entry.action_type || '').trim()));
      const requiredActions = Array.isArray(task.required_actions) ? task.required_actions : [];
      const completedCount = requiredActions.filter((action) => completionSet.has(action)).length;
      const totalReward = formatEngagementAmount(Object.values(task.reward_config || {}).reduce((sum, value) => sum + Number(value || 0), 0));
      const statusBadge = `<span class="status-badge ${isExpired ? 'status-paused' : (task.status === 'active' ? 'status-live' : 'status-paused')}">${isExpired ? 'expired' : escapeHtml(task.status || 'active')}</span>`;
      const taskName = escapeHtml(task.title || `${task.provider} task`);
      const taskMeta = `<div style="font-size:0.78em;color:var(--text-muted);margin-top:4px;">${escapeHtml(task.provider)} • ${escapeHtml(task.trigger_type)}</div>`;
      const actionTags = requiredActions.map((action) => {
        const done = completionSet.has(action);
        return `<span style="display:inline-flex;align-items:center;gap:5px;padding:3px 8px;border:1px solid rgba(99,102,241,0.22);border-radius:999px;font-size:0.74em;color:${done ? '#86efac' : '#cbd5e1'};">${done ? '✓' : '•'} ${escapeHtml(formatEngagementActionLabel(action))}</span>`;
      }).join(' ');
      const detailText = task.body
        ? `<div style="font-size:0.8em;color:var(--text-secondary);margin-bottom:6px;">${escapeHtml(task.body)}</div>`
        : '';

      const actionControls = [
        !canAdminEngagement
          ? `<button class="btn-secondary btn-sm" ${isExpired ? 'disabled' : ''} onclick="completeEngagementTask(${Number(task.id)}, '')">Verify</button>`
          : '',
        task.source_post_url
          ? `<a class="btn-secondary btn-sm" href="${escapeHtml(task.source_post_url)}" target="_blank" rel="noopener noreferrer">Go to post</a>`
          : '',
        canAdminEngagement ? `<button class="btn-secondary btn-sm" onclick="openEngagementRepostModal(${Number(task.id)})">Repost</button>` : '',
        canAdminEngagement ? `<button class="btn-danger btn-sm" onclick="deleteEngagementTask(${Number(task.id)})">Delete</button>` : '',
      ].filter(Boolean).join('');

      return `<tr ${isExpired ? 'style="background:rgba(127,29,29,0.14);"' : ''}>
        <td style="padding:10px 12px;min-width:240px;">
          <div style="font-weight:600;">${taskName}</div>
          ${taskMeta}
        </td>
        <td style="padding:10px 12px;">${statusBadge}</td>
        <td style="padding:10px 12px;font-size:0.82em;color:var(--text-secondary);">${completedCount}/${requiredActions.length || 0}</td>
        <td style="padding:10px 12px;font-weight:600;color:#86efac;">${escapeHtml(totalReward)}</td>
        <td style="padding:10px 12px;">
          <div style="display:flex;gap:6px;flex-wrap:wrap;">${actionControls || '<span style="color:var(--text-muted);font-size:0.82em;">No actions</span>'}</div>
        </td>
        <td style="padding:10px 12px;min-width:320px;">
          ${detailText}
          <div style="display:flex;gap:6px;flex-wrap:wrap;">${actionTags || '<span style="color:var(--text-muted);font-size:0.82em;">No required actions</span>'}</div>
          ${isExpired ? '<div style="font-size:0.76em;color:#fca5a5;font-weight:700;margin-top:6px;">Task expired</div>' : ''}
        </td>
      </tr>`;
    }).join('');

    el.innerHTML = `<div class="data-table-wrap">
      <table class="data-table">
        <thead>
          <tr>
            <th>Task</th>
            <th>Status</th>
            <th>Progress</th>
            <th>Reward</th>
            <th>Actions</th>
            <th>Details</th>
          </tr>
        </thead>
        <tbody>${rows}</tbody>
      </table>
    </div>`;
  } catch (e) {
    el.innerHTML = '<p style="color:var(--error);">Failed to load tasks.</p>';
  }
}

async function completeEngagementTask(taskId, actionType) {
  try {
    const response = await fetch(`/api/user/engagement/tasks/${Number(taskId)}/complete`, {
      method: 'POST',
      credentials: 'include',
      headers: {
        'Content-Type': 'application/json',
        ...buildTenantRequestHeaders(),
      },
      body: JSON.stringify({ action_type: actionType }),
    });
    const data = await response.json();
    if (!data.success) {
      showError(data.message || 'Could not complete the task.');
      return;
    }
    const result = data.result || data.data || data;
    const verifiedCount = Number(result.verifiedCount || 0);
    const rewardPoints = Number(result.rewardPoints || 0);
    if (verifiedCount > 0) {
      showSuccess(`Verified ${verifiedCount} action(s) and awarded rewards.`);
    } else if (rewardPoints > 0) {
      showSuccess(`Task completed. Awarded ${formatEngagementAmount(rewardPoints)}.`);
    } else {
      showSuccess('Task completion recorded.');
    }
    loadEngagementTasks();
    if (typeof loadEngagementLeaderboard === 'function') loadEngagementLeaderboard();
    if (typeof loadEngagementHistory === 'function') loadEngagementHistory();
    if (typeof loadEngagementConfig === 'function') loadEngagementConfig();
    if (typeof loadEngagementRedemptions === 'function') loadEngagementRedemptions();
  } catch (error) {
    showError(`Task completion failed: ${error.message}`);
  }
}

async function submitEngagementTask(mode) {
  try {
    const body = {
      provider: document.getElementById('engTaskProvider').value,
      source_post_id: document.getElementById('engTaskSourcePostId').value.trim(),
      source_account_handle: document.getElementById('engTaskSourceHandle').value.trim(),
      source_post_url: document.getElementById('engTaskSourceUrl').value.trim() || null,
      title: document.getElementById('engTaskTitle').value.trim(),
      body: document.getElementById('engTaskBody').value.trim(),
      required_actions: parseEngagementTaskTypes(document.getElementById('engTaskActions').value),
      reward_config: parseEngagementJson(document.getElementById('engTaskRewards').value, {}),
      trigger_type: mode === 'ingest' ? 'account_post' : 'manual',
    };
    const endpoint = mode === 'ingest' ? '/api/admin/engagement/tasks/ingest' : '/api/admin/engagement/tasks';
    const res = await fetch(endpoint, {
      method: 'POST',
      credentials: 'include',
      headers: engagementHeaders(),
      body: JSON.stringify(body),
    });
    const data = await res.json();
    if (!data.success) {
      showError(data.message || 'Failed to save task.');
      return;
    }
    showSuccess(mode === 'ingest' ? 'Provider post ingested.' : 'Task created.');
    loadEngagementTasks();
  } catch (e) {
    showError('Reward JSON is invalid.');
  }
}

