function setEngagementPortalMode(canAdmin) {
  const engagementSection = document.getElementById('section-engagement');
  if (!engagementSection) return;
  const inEngagement = (selector) => engagementSection.querySelector(selector);
  const summaryView = inEngagement('#engagementMemberSummaryView');
  const linkedAccountsCard = inEngagement('#engagementLinkedAccountsCard');
  const historyCard = inEngagement('#engagementHistoryCard');
  const leaderboardCard = inEngagement('#engagementLeaderboardCard');
  const shopCard = inEngagement('#engagementShopCard');
  const achievementsCard = inEngagement('#engagementAchievementsCard');
  const redemptionsCard = inEngagement('#engagementRedemptionsCard');
  const configGrid = inEngagement('#engagementConfigGrid');
  const configSaveBtn = inEngagement('#engagementConfigSaveBtn');
  const shopAddBtn = inEngagement('#engagementShopAddBtn');
  const taskAdminForm = inEngagement('#engagementTaskAdminForm');
  const taskIngestBtn = inEngagement('#engagementTaskIngestBtn');
  const taskCreateBtn = inEngagement('#engagementTaskCreateBtn');
  const achievementAdminForm = inEngagement('#engagementAchievementAdminForm');
  const achievementSaveBtn = inEngagement('#engagementAchievementSaveBtn');
  const redemptionsRefreshBtn = inEngagement('#engagementRedemptionsRefreshBtn');
  const verifyAllBtn = inEngagement('#engagementVerifyAllBtn');
  const configTitle = inEngagement('#engagementConfigCard .card-title');
  const tasksCard = inEngagement('#engagementTasksView')?.closest('.card');
  const tasksTitle = tasksCard?.querySelector('.card-title');
  const providersCard = inEngagement('#engagementProvidersView')?.closest('.card');
  const taskAutomationCard = inEngagement('#engagementTaskAutomationCard');
  const adminOnlyCards = [
    inEngagement('#engagementMonitoredAccountsView')?.closest('.card'),
    inEngagement('#engagementHashtagView')?.closest('.card'),
  ].filter(Boolean);

  if (summaryView) summaryView.style.display = canAdmin ? 'none' : 'block';
  if (linkedAccountsCard) linkedAccountsCard.style.display = canAdmin ? 'none' : '';
  if (historyCard) historyCard.style.display = canAdmin ? 'none' : '';
  if (configGrid) configGrid.style.display = canAdmin ? 'grid' : 'none';
  if (configSaveBtn) configSaveBtn.style.display = canAdmin ? 'inline-flex' : 'none';
  if (shopAddBtn) shopAddBtn.style.display = canAdmin ? 'inline-flex' : 'none';
  if (taskAdminForm) taskAdminForm.style.display = canAdmin ? 'grid' : 'none';
  if (taskIngestBtn) taskIngestBtn.style.display = canAdmin ? 'inline-flex' : 'none';
  if (taskCreateBtn) taskCreateBtn.style.display = canAdmin ? 'inline-flex' : 'none';
  if (achievementAdminForm) achievementAdminForm.style.display = canAdmin ? 'grid' : 'none';
  if (achievementSaveBtn) achievementSaveBtn.style.display = canAdmin ? 'inline-flex' : 'none';
  if (redemptionsRefreshBtn) redemptionsRefreshBtn.style.display = 'inline-flex';
  if (verifyAllBtn) verifyAllBtn.style.display = canAdmin ? 'none' : 'inline-flex';
  if (configTitle) configTitle.textContent = canAdmin ? 'Settings' : 'My Engagement';
  if (tasksTitle) tasksTitle.textContent = canAdmin ? '🧩 Tasks' : '🧩 Active Tasks';
  if (providersCard) providersCard.style.display = canAdmin ? '' : 'none';
  if (taskAutomationCard) taskAutomationCard.style.display = canAdmin ? '' : 'none';
  engagementSection.classList.toggle('engagement-admin-mode', canAdmin);
  engagementSection.classList.toggle('engagement-user-mode', !canAdmin);

  [linkedAccountsCard, historyCard, leaderboardCard, shopCard, tasksCard, achievementsCard, redemptionsCard].forEach(card => {
    if (!card) return;
    card.classList.toggle('engagement-compact-card', !canAdmin);
  });

  adminOnlyCards.forEach(card => {
    card.style.display = canAdmin ? '' : 'none';
  });
}

function getEngagementRangeCutoff(rangeKey = '7d') {
  const now = Date.now();
  if (rangeKey === '24h' || rangeKey === 'today') return now - (24 * 60 * 60 * 1000);
  if (rangeKey === '30d') return now - (30 * 24 * 60 * 60 * 1000);
  return now - (7 * 24 * 60 * 60 * 1000);
}

function animateMetricValue(el, nextValue) {
  if (!el) return;
  const target = Number(nextValue || 0);
  const previous = Number(el.dataset.currentValue || 0);
  const duration = 320;
  const startedAt = performance.now();
  function tick(ts) {
    const progress = Math.min(1, (ts - startedAt) / duration);
    const value = Math.round(previous + ((target - previous) * progress));
    el.textContent = value.toLocaleString();
    if (progress < 1) requestAnimationFrame(tick);
    else el.dataset.currentValue = String(target);
  }
  requestAnimationFrame(tick);
}

function calculateUserEngagementRangeStats(rangeKey = '7d') {
  const cutoff = getEngagementRangeCutoff(rangeKey);
  const history = Array.isArray(window.__engagementSummaryHistoryRows) ? window.__engagementSummaryHistoryRows : [];
  const redemptions = Array.isArray(window.__engagementSummaryRedemptions) ? window.__engagementSummaryRedemptions : [];
  const achievements = Array.isArray(window.__engagementSummaryAchievements) ? window.__engagementSummaryAchievements : [];

  let earned = 0;
  history.forEach(entry => {
    const ts = entry?.created_at ? new Date(entry.created_at).getTime() : 0;
    if (!ts || ts < cutoff) return;
    const points = Number(entry?.points || 0);
    if (points > 0) earned += points;
  });

  const redemptionCount = redemptions.filter(entry => {
    const ts = entry?.created_at ? new Date(entry.created_at).getTime() : 0;
    return ts && ts >= cutoff;
  }).length;

  const unlocked = achievements.filter(entry => {
    const ts = entry?.awarded_at ? new Date(entry.awarded_at).getTime() : 0;
    return ts && ts >= cutoff;
  }).length;

  return { earned, redemptionCount, unlocked };
}

function applyEngagementSummaryRange(rangeKey = '7d') {
  window.__engagementUserRange = rangeKey;
  const wrap = document.getElementById('engagementUserRangeToggle');
  if (wrap) {
    wrap.querySelectorAll('button[data-range]').forEach(btn => {
      btn.classList.toggle('active', btn.dataset.range === rangeKey);
    });
  }
  const stats = calculateUserEngagementRangeStats(rangeKey);
  animateMetricValue(document.getElementById('engRangePointsValue'), stats.earned);
  animateMetricValue(document.getElementById('engRangeRedemptionsValue'), stats.redemptionCount);
  animateMetricValue(document.getElementById('engRangeAchievementsValue'), stats.unlocked);
}

function setEngagementSummaryRange(rangeKey = '7d') {
  applyEngagementSummaryRange(rangeKey);
}

